function get_class_grid(spinner=true) {

	return new Promise((resolve, reject) => {

	    let location_id = $('#location_id').val();
	    let date = $('#main_date').val();

	    //flush non-target grids
	    $('#spaces').html('');
	    $('#lessons').html('');
	    $('#rosters').html('');

	    if (isID(location_id) && isvalidDate(date)) {
	        if (spinner) {$('#loader-wrapper').show();}

	        if (USE_CLASS_SCHEDULE_MOCKS) {
	        	const mock = get_mock_class_grid_payload();
	        	$('#loader-wrapper').hide();
	        	if (mock.data.length && mock.data_schedule.length) {
	        		build_class_grid(mock.data, mock.data_schedule, true);
	        	}
	        	resolve();
	        	return;
	        }

	        let data = {location_id: location_id, date: date};

	        $.ajax({
	            type: 'GET',
	            url: '/api/getClassGridAdmin',
	            data: data,
	            dataType: 'JSON'
	        }).done(function( response ) {

	            if (response.success != undefined) {
	                $('#loader-wrapper').hide();
	                if (response.success.data.length) {
	                	build_class_grid(response.success.data, response.success.data_schedule, true);
	                }

	            } else if (response.redirect != undefined) {
	                mini_login_wizard(response.redirect); //session timeout case
	            } else {
	            	$('#loader-wrapper').hide();
	            	let unavail = (response.error.errors && response.error.errors[0].includes('No') && response.error.errors[0].includes('selected date')) ? true : false;
	                if (unavail) {
	                	$('#classes').html('<div class="unavail">'+(response.error.errors || response.error).join("<br>")+'</div>');
	                } else {
	                	set_side_error((response.error.errors || response.error).join("<br>"));
	                	$('#classes').html(''); //flush grid
	                }
	            }
	            resolve();

	        }).fail( function(xhr, textStatus, errorThrown) {
	            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
	            $('#loader-wrapper').hide();
	            reject();
	        });
	    }
	});		     
}

function get_roster_grid(spinner=true) {

	return new Promise((resolve, reject) => {

	    let location_id = $('#location_id').val();
	    let date = $('#main_date').val();

	    $('#spaces').html('');
	    $('#lessons').html('');
	    $('#classes').html('');

	    function rosterIntroWhenNoGridBuild() {
	    	deferHeavyWorkAfterNavPaint(function () {
	    		run_roster_grid_intro_animation();
	    	});
	    }

	    if (isID(location_id) && isvalidDate(date)) {
	        if (spinner) {$('#loader-wrapper').show();}

	        if (USE_ROSTER_MOCKS) {
	        	const mock = get_mock_roster_grid_payload();
	        	$('#loader-wrapper').hide();
	        	if (mock.data.length && mock.data_schedule.length) {
	        		build_class_grid(mock.data, mock.data_schedule, true, true);
	        	}
	        	resolve();
	        	return;
	        }

	        let data = {location_id: location_id, date: date};

		    if ($('.instructor-page').length) {
		        data.from = 'instructor';
		        if ($('.instructor_weekly_mode').length) {
		        	data.grid_view = 'weekly';
		        }
		    }

	        const reqId = ++rosterGridRequestId;
	        if (rosterGridXhr) {
	        	rosterGridXhr.abort();
	        }

	        rosterGridXhr = $.ajax({
	            type: 'GET',
	            url: '/api/getRosterGrid',
	            data: data,
	            dataType: 'JSON'
	        }).done(function( response ) {
	        	rosterGridXhr = null;
	        	if (reqId !== rosterGridRequestId) {
	        		resolve();
	        		return;
	        	}

	            if (response.success != undefined) {
	                $('#loader-wrapper').hide();
	                if (response.success.data.length) {
	                	build_class_grid(response.success.data, response.success.data_schedule, true, true);
	                } else {
	                	$('#rosters').html('<div class="unavail">No roster rows for this date.</div>');
	                	rosterIntroWhenNoGridBuild();
	                }

	            } else if (response.redirect != undefined) {
	                mini_login_wizard(response.redirect); //session timeout case
	            } else {
	            	$('#loader-wrapper').hide();
	            	let unavail = (response.error.errors && response.error.errors[0].includes('No') && response.error.errors[0].includes('selected date')) ? true : false;
	                if (unavail) {
	                	$('#rosters').html('<div class="unavail">'+(response.error.errors || response.error).join("<br>")+'</div>');
	                } else {
	                	set_side_error((response.error.errors || response.error).join("<br>"));
	                	$('#rosters').html(''); //flush grid
	                }
	            }
	            resolve();

	        }).fail( function(xhr, textStatus, errorThrown) {
	        	rosterGridXhr = null;
	        	if (textStatus === 'abort') {
	        		resolve();
	        		return;
	        	}
	            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
	            $('#loader-wrapper').hide();
	            rosterIntroWhenNoGridBuild();
	            reject();
	        });
	    } else {
	    	rosterIntroWhenNoGridBuild();
	    	resolve();
	    }
	});		     
}

function get_my_image() {
    $.ajax({
        type: 'GET',
        url: '/api/getImages',
        data: {user_id: $('#user_id').val()},
        dataType: 'JSON'
    }).done(function( response ) {

        if (response.success != undefined) {

            let res = response.success;

            if (res.data[0]) {
                $('.self_image').attr('src', 'data:image/png;base64,'+res.data[0].image_data);
            }

            $('.self_image').removeClass('noshow');

        } else if (response.redirect != undefined) {
            mini_login_wizard(response.redirect); //session timeout case
        } else {    
            set_side_error(response.error.join("<br>"));
        }

    }).fail( function(xhr, textStatus, errorThrown) {
        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
    });
}

function get_client_options(mode) {
    return new Promise((resolve, reject) => {

    	let modes = (Array.isArray(mode)) ? mode : [mode ? mode : 'cuser'];

    	//locations visible or location_id set from deeplink/admin_location_id
    	let location_id = (!$('#main_switch_location').closest('.locations').hasClass('noshow') || ($('#location_id').val() > 0)) ? $('#location_id').val() : '0';

        $.ajax({
            type: 'GET',
            url: '/api/getClientOptions',
            data: {from: 'user', modes: modes, location_id: location_id},
            dataType: 'JSON'
        }).done(function( response ) {

            if (response.success != undefined) {
                $('#loader-wrapper').hide();
            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();            
            }
            resolve(response.success);

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
            reject();
        }); 
    });    
}

async function set_client_options() {
	let options = {};
	options = await get_client_options();
	options.client = options.client || '';
	options.cash_sale = options.cash_sale || '';
	options.user = options.user || '';
	options.sms = options.sms || '';
	options.term = options.term || '';
	options.location = options.location || '';
	options.product = options.product || '';
	options.customer = options.customer || '';
	options.passtype = options.passtype || '';
	options.avail = options.avail || '';
	options.hold = options.hold || '';
	options.class = options.class || '';
	options.register = options.register || '';
	options.favs = options.favs || '';
	options.roster = options.roster || '';
	options.assess = options.assess || '';
	options.message = options.message || '';
	options.self = options.self || '';

    //admin
    if (options.is_admin) {
        $('#is_admin').val(options.is_admin);
    } else {
        $('.admin_only').remove();
        $('.admin_only_input').prop('disabled', true);
    }

    if (options.is_admin_users) {
    	$('#is_admin_users').val(options.is_admin_users);
    } else {
    	$('.users_only').remove();
    }

	if (!options.is_admin && !options.is_admin_users) {
		$('.admin_or_users_only').remove();
	}

	if (!options.is_admin && !options.is_instructor) {
		$('.admin_or_instructor_only').remove();
	}
    
    if (!options.is_admin_reports) {
    	$('.reports_only').remove();
    }

    if (!options.is_admin_intrac) {
    	$('.intrac_only').remove();
    }

    $('#user_id').val(options.user_id);
    $('#user_location_id').val(options.user_location_id);
    if (options.user_location_id > 0) {
    	$('.admin_0_only').remove();
    }

	//client
	$('#locale').val(options.client.locale);
	$('#ccy_code').val(options.client.currency);

	if (!options.client.show_classes) {
		$('.class_items').remove();
	}

	if (options.client.hide_classes) { //completely remove all class items; override show_classes
		$('.class_items').remove();
		$('.class_mgmt_items').remove();
	}

	if (!options.client.show_spaces) {
		$('.space_items').remove();
	}

	if (!options.client.show_single_booking) {
		$('.single_booking_items').remove();
	}

	if (!options.client.show_term_bookings) {
		$('.term_booking_items').remove();
	}

	if (!options.client.show_perm_bookings) {
		$('.perm_booking_items').remove();
	}

	if (!options.client.term_perm_hourly) {
		$('.term_perm_hourly').remove();
	} else {
		$('.not_term_perm_hourly').remove();
	}

	if (!options.client.show_lessons) {
		$('.lesson_items').remove();
	}

	if (options.client.show_promo_code) {
		$('.promo_form').show();
	} else {
		$('.promo_form').remove();
	}

	if (options.client.show_multi_regs_disc) {
		$('.multi_regs_items').show();
	} else {
		if (options.is_admin_intrac && options.class.level_types_0_1) {
			//re-purpose for recalc
			if ($('.tl_multir').length) {
				$('.tl_multir').prop('dataset').intrac_class_id = 0;
			};
			$('.tl_multir span').text('Recalculate '+(options.class.class_title || $('#class_title').val())+' costs');
            $('.multir_tab .tab-header h4').text('Recalculate '+(options.class.class_title || $('#class_title').val())+' costs');
		} else {
			$('.multi_regs_items').remove();
		}
	}

    if (!options.class.level_types_0_1) {
        $('.level_types_0_1_items').remove();
    }

    if (!options.class.level_types_4) {
        $('.level_types_4_items').remove();
    }

	if (!options.class.show_scoreboard_items) {
		$('.modal_o_scoreboards').remove(); //process_tiering
	}

	if (options.client.integrated_eftpos) {
		if (options.client.integrated_eftpos_stripe) {
			$('.eftpos_items').prop('dataset').intrac_stripe = true;
		}
	} else {
		$('.eftpos_items').remove();
	}

	if (!options.client.show_locks) {
		$('.locks_items').remove();
	}

	if (options.client.show_notes) {
		$('.notes_items').removeClass('noshow');
		$('.rtab_notes:first').click();
	} else {
		$('.notes_items').remove();
		$('.rtab_functions:first').click();
	}

	if (!options.client.show_comment_followup) {
		$('.comment_followup_items').remove();
	}

	if (!options.client.show_files) {
		$('.files_items').remove();
	} else {
		$('#max_file_size').val(options.client.show_files);
	}

	if (!(options.client.show_wait||'').includes('c')) {
		$('.wait_items').remove();
	}

	if (!options.client.show_shuffle) {
		$('.shuffle_items').remove();
	}

	if (!options.client.show_cancel_sms) {
		$('.cancel_sms_items').remove();
	}

	if (!options.client.show_update_class_schedule_puids) {
		$('.class_sched_puids_items').remove();
	}

    if (!options.client.show_gifts) {
        $('.gift_items').remove();
    }

    if (!options.client.show_gcards) {
        $('.gcard_items').remove();
    }

	if (!options.client.show_directs) {
		$('.directs_items').remove();
	}

	if (!options.client.show_cust_directs) {
		$('.cust_direct_items').remove();
	}

	if (!options.client.allow_amex) {
		$('#allow_amex').remove();
	}

	if (options.client.lesson_hide_capacity) {
		$('#lesson_modal .lesson_capacity_div').addClass('noshow');
	}

	if (options.client.widgets_list) {
		if ($('#add_widget').length) {
			$('#add_widget').prop('dataset').intrac = JSON.stringify(options.client.widgets_list);	
		}
	} else {
		$('.nav_dashboard').remove();
	}

	if (!options.client.show_print_grid) {
		$('.print_grid').remove(); //process_tiering
	}

	if ($('#stripe_pub_key').text()) {
		$('.non_stripe_items').remove();
		$('.cust_payment_options .directs_items').addClass('noshow'); //will be shown as part of stripe mount
	} else {
		$('.stripe_items').remove();
	}

	//store special rates for calculations later
	$('#special_rates').text(encryptData(JSON.stringify({rates: options.client.special_rates})));
	$('#special_rates_usage').text(encryptData(JSON.stringify({"back_end":{},"front_end":{}})));

	//ho
    if (options.client.ho_title) {
        $('.ho-title').text(function() {
            if ($(this).prop('dataset').intrac_fav_name) {
                $(this).prop('dataset').intrac_fav_name = $(this).prop('dataset').intrac_fav_name.replace('Head office',options.client.ho_title);
            }           
            return $(this).text().replace('Head office',options.client.ho_title);
        });     
        $('#ho_title').val(options.client.ho_title);
    }

	//class
	if (options.class.class_title) {
		$('.class-title').text(function() {
		    if ($(this).prop('dataset').intrac_fav_name) {
		    	$(this).prop('dataset').intrac_fav_name = $(this).prop('dataset').intrac_fav_name.replaceCaseFull('classes',options.class.class_title+'s').replaceCaseFull('class',options.class.class_title);
		    }			
		    return $(this).text().replaceCaseFull('classes',options.class.class_title+'s').replaceCaseFull('class',options.class.class_title);
		});		
		$('#class_title').val(options.class.class_title);
	}
	getClasssOptions(options.class, options);
    getRegistersOptions(options.register);

	//term
	if (options.term.term_title) {
		$('.term-title').text(function() {
		    if ($(this).prop('dataset').intrac_fav_name) {
		    	$(this).prop('dataset').intrac_fav_name = $(this).prop('dataset').intrac_fav_name.replaceCaseFull('term',options.term.term_title);
		    }
		    return $(this).text().replaceCaseFull('term',options.term.term_title);
		});		
		$('#term_title').val(options.term.term_title);
	}
	getTermsOptions(options.term);

	//location
	if (options.location.location_title) {
		$('.location-title').text(function() {
		    if ($(this).prop('dataset').intrac_fav_name) {
		    	$(this).prop('dataset').intrac_fav_name = $(this).prop('dataset').intrac_fav_name.replaceCaseFull('locations', (options.location.location_title == 'bus' ? 'buses' : options.location.location_title+'s')).replaceCaseFull('location',options.location.location_title);
		    }		    
		    return $(this).text().replaceCaseFull('locations', (options.location.location_title == 'bus' ? 'buses' : options.location.location_title+'s')).replaceCaseFull('location',options.location.location_title);
		});		
		$('#location_title').val(options.location.location_title);
	}
    if (options.location.space_title) {
		$('.space-title').each(function() {
		    if ($(this).prop('dataset').intrac_fav_name) {
		    	$(this).prop('dataset').intrac_fav_name = $(this).prop('dataset').intrac_fav_name.replaceCaseFull('space',options.location.space_title);
		    }
			if ($(this).prop('name')) {
				$(this).prop('name',$(this).prop('name').replaceCaseFull('space',options.location.space_title));
			}
			$(this).text($(this).text().replaceCaseFull('space',options.location.space_title));
		});	    	
    	$('#space_title').val(options.location.space_title);
    }
    getLocationsOptions(options.location);

    //passtype
    if (options.passtype.pass_title) {
		$('.pass-title').text(function() {
		    if ($(this).prop('dataset').intrac_fav_name) {
		    	$(this).prop('dataset').intrac_fav_name = $(this).prop('dataset').intrac_fav_name.replaceCaseFull('passes',options.passtype.pass_title+'s').replaceCaseFull('pass',options.passtype.pass_title);
		    }		    
		    return $(this).text().replaceCaseFull('passes',options.passtype.pass_title+'s').replaceCaseFull('pass',options.passtype.pass_title);
		});    	
    	$('#pass_title').val(options.passtype.pass_title);
    }
    if (options.passtype.pass_monthly_title) {
		$('.pass-monthly-title').text(function() {		    
		    return $(this).text().replaceCaseFull('month',options.passtype.pass_monthly_title);
		});    	
    	$('#pass_monthly_title').val(options.passtype.pass_monthly_title);
    }
    getPasstypesOptions(options.passtype);

    //customer
    getCustomersOptions(options.customer, options);

    //multitenant
    getMultiTenantOptions(options.client);

    //surcharge
	if (!options.client.show_surcharge) {
		$('.surcharge_items').remove();
	} else {
		$('.surcharge_rate').each(function() {
			let s_rate = options.client.show_surcharge;
			$(this).prop('dataset').intrac = s_rate;
			$(this).text(' ('+(s_rate.split('~')[0] > 0 ? s_rate.split('~')[0]+'%' : '')+(s_rate.split('~')[1] ? ('+'+numberformatccy(s_rate.split('~')[1])) : '')+')');
		});
		if (options.client.surcharge_title) {
			$('.surcharge-title').text(options.client.surcharge_title);
		}
	}    

    //users
    getUsersOptions(options.user, options);

    //products
    getProductsOptions(options.product, options);

    //roster
	if (options.roster.roster_title) {
		$('.roster-title').text(function() {
		    if ($(this).prop('dataset').intrac_fav_name) {
		    	$(this).prop('dataset').intrac_fav_name = $(this).prop('dataset').intrac_fav_name.replaceCaseFull('roster',options.roster.roster_title);
		    }
		    return $(this).text().replaceCaseFull('roster',options.roster.roster_title).replaceCaseFull('shift',options.roster.roster_title);
		});		
		$('#roster_title').val(options.roster.roster_title);
	}    
    getRostersOptions(options.roster);

    //assess
    getAssessOptions(options.assess);

    //sms
    getSMSsOptions(options.sms);

    //reports
    getReportsOptions(options.reports);

    //holds
    getHoldsOptions(options.hold);

    //weather
    getWeathersOptions(options.weather);

    //templates
    getTemplatesOptions(options.template);

    //messages
    getMessagesOptions(options.message, true);

    //fortnightly dates for prog_day_type
    let evenMondays = getFilteredDates(dayjs(),dayjs().add(28, 'day'),'Mon',[],6);
    let oddMondays = getFilteredDates(dayjs(),dayjs().add(28, 'day'),'Mon',[],7);
    $('.tb_prog_day_type option[value="6"], .pb_prog_day_type option[value="6"]').text('Fortnightly on even weeks of month only (e.g. week starting '+convert_date(evenMondays[0], 'ddd D MMM')+')');
    $('.tb_prog_day_type option[value="7"], .pb_prog_day_type option[value="7"]').text('Fortnightly on odd weeks of month only (e.g. week starting '+convert_date(oddMondays[0], 'ddd D MMM')+')');

    //processes link
    if (!$('#master_proc_view .tab-list li').length) {
    	$('.modal_o_procs').remove();
    }

    //instructor_view
    if ($('.instructor-page').length) {
    	$('.rtab-close').click();
    }

    //all settings done
    //show hide-on-load items
    $('.hol').removeClass('noshow');

    //location logic and trigger
    if (options.location.show_location) {
    	$('.locations').removeClass('noshow'); //Don't show location if there are no spaces in Yes/Read-Only
    } else {
    	$('.cur_location_name').remove();
    }

	let locs_str = '';
	for (let i = 0; i < options.location.locations.length; i++) {
		let l = options.location.locations[i];
		locs_str += '<li><a class="dropdown-item" href="#" data-intrac="'+l.location_id+'" data-intrac_combo="">'+l.location_name+'</a></li>';
	}	
	$('.switch_location').html(locs_str);

	let l_id = $('#location_id').val(); //from deeplink/admin_location_id

	if ((l_id) && ($('#main_switch_location a[data-intrac="'+l_id+'"]').length)) { //deeplink/admin_location_id
		$('#main_switch_location').closest('.dropdown').find('.dropdown-toggle span').text($('#main_switch_location a[data-intrac="'+l_id+'"]').text());
		$('.cur_location_name').text($('#main_switch_location a[data-intrac="'+l_id+'"]').text());
	} else { //set first location as default
		let f = $('#main_switch_location a:first');
		$('#location_id').val($(f).prop('dataset').intrac);
		$('#main_switch_location').closest('.dropdown').find('.dropdown-toggle span').text($(f).text());
		$('.cur_location_name').text($(f).text());

		if (l_id) {localStorage.removeItem('admin_location_id');} //stale location
	}

	//these must run at the end
    //availability - need location_id to be set
    getAvailsOptions(options.avail);

    //cash sale - need location_id to be set
    getCashSaleOptions(options.cash_sale, options);

    //cleanup and copy functions and reports list to mobile. mobile_favourites are part of getFavsOptions
	$('#functions_list li').filter(function() {
	    return $(this).text().trim() === '';
	}).remove();
	$('#reports_list li').filter(function() {
	    return $(this).text().trim() === '';
	}).remove();

    if ($('#functions_list li').length) {
    	$('#mobile_functions').html($('#functions_list').html().replace(/\bfav_\w+\b/g, match => match.replace('fav_', 'favm_'))); //rename all classes with word fav_ to favm_
    } else {
    	$('.functions_div, .mobile_functions_div').remove();
    }
    if ($('#reports_list li:not(.noshow)').length) {
    	$('#mobile_reports').html($('#reports_list').html().replace(/\bfav_\w+\b/g, match => match.replace('fav_', 'favm_'))); //rename all classes with word fav_ to favm_
    } else {
    	$('.reports_div, .mobile_reports_div').remove();
    }
    
    //move functions to top menu, use mobile_functions which are already clean without fav_
    if ($('.instructor-page').length) {
    	$('#mobile_functions .instructor_fn').each(function() {
    		let el = $(this).closest('li').clone();
    		$(el).addClass('nav-link-row instructor_nav');
    		$(el).find('a').removeClass('menu_item').addClass('nav-btn');

    		if ($(el).find('a').hasClass('modal_o_avails')) {
    			$(el).find('a').removeClass('modal_o_avails').addClass('nav-link-main nav_instr_availability');
    		}
    		if ($(el).find('a').hasClass('modal_o_rosters')) {
    			$(el).find('a').removeClass('modal_o_rosters').addClass('nav-link-main nav_instr_roster');
    		}

    		$('#nav_list').append($(el));
    	});

    	if (!$('#hamburger').is(":visible") && !$('#cross').is(":visible")) { //not mobile
    		$('#calendar_main_div').insertBefore('.functions_div');
    		$('#instructor_weekly_div').insertBefore('.functions_div');
    	}
    }


    //favs
    getFavsOptions(options.favs); //mobile_favourites and adjustFavs done as part of this

    //set default grid
    if (options.client.grid_default_admin) {
    	if ($('.instructor-page').length) {
    		$('.nav-link-main.nav_roster').click();
    	} else {
    		$('.nav-link-main.nav_'+options.client.grid_default_admin).click();	
    	}
    } else {
    	if ($('.instructor-page').length) {
    		$('.nav-link-main.nav_roster').click();
    	} else if ($('.class_items').length) {
	    	$('.nav-link-main.nav_class').click();
	    } else if ($('.lesson_items').length) {
	    	$('.nav-link-main.nav_lesson').click();
	    } else if ($('.space_items').length) {
	    	$('.nav-link-main.nav_space').click();
	    }
    }
	requestAnimationFrame(function () {
		requestAnimationFrame(updateNavPill);
	});
}

function getClasssOptions(options, options_all) {

    $('.class_status option').filter(function() {
        return !options.class_status.includes($(this).val());
    }).remove();

    $('.class_status_filter_items a[data-intrac != ""]').each(function() {
    	if (!options.class_status.includes($(this).prop('dataset').intrac)) {
    		$(this).closest('li').remove();
    	}
    });

    if (!options.show_class_images) {
        $('.class_image_tr').remove();
    } else {
        $('.class_image_tr').addClass('show_images');
        $('.class_img_buttons').addClass('noshow');
    }

    if (options.flat_cost_0) {
        $('.class_flat_cost').val("flat_cost_0");
    }

    if (options.flat_cost) {
        $('.class_flat_cost').val("flat_cost");
    }

    if (options.class_enrolment_titles) {
        $('#class_enrolment_titles').text(JSON.stringify(options.class_enrolment_titles));
        $('.enrolverb-title').text(function() {
            return $(this).text().replaceCaseFull('enrol',options.class_enrolment_titles.verb);
        });
        $('.enrolment-title').text(function() {
            return $(this).text().replaceCaseFull('enrolment',options.class_enrolment_titles.title);
        });                
    } else {
        $('#class_enrolment_titles').text('{}');
    }

    if (options.show_prog_public_hols) {
    	$('.prog_incl_hols_div').removeClass('noshow');
    }

    if (options.show_schedule_comment) {
        $('.sched_schedule_comment_div').removeClass('noshow');
    } else {
        $('.sched_schedule_comment_div').addClass('noshow');
    }

    if (options.show_attendees) {
        $('.sched_attendees_div').removeClass('noshow');
    } else {
        $('.sched_attendees_div').addClass('noshow');
    }

    if (options.show_full_option) {
        $('.sched_schedule_full_div').removeClass('noshow');
    } else {
        $('.sched_schedule_full_div').addClass('noshow');
    }

    if (options.fixtures_show_gala && options.fixtures_show_gala.includes($('#location_id').val())) {
        $('.fixt_cf_gala_div').removeClass('noshow');
        $('.fixt_gala').prop('checked', true);
    } else {
        $('.fixt_cf_gala_div').addClass('noshow');
        $('.fixt_gala').prop('checked', false);
    }

    if (options.fixtures_show_fullfield) {
        $('.fixt_cf_fullfield_div').removeClass('noshow');
    } else {
        $('.fixt_cf_fullfield_div').addClass('noshow');
    }

    if (options.show_fixtures_rules) {
        $('.fixt_cf_rules_div').removeClass('noshow');
    } else {
        $('.fixt_cf_rules_div').addClass('noshow');
    }

	if (!options.has_register_addons) {
		$('.class_feature_m').closest('.class_feature_div').remove();
	}

	if (!options.has_product_addons) {
		$('.class_feature_a').closest('.class_feature_div').remove();
	}

	if (!options.has_private_registers) {
		$('.class_feature_4').closest('.class_feature_div').remove();
	}

	if (!options.show_roll_washout) {
		$('.roll_washout_items').remove();
	}

    if (!options_all.client.show_classes_public) {
        $('.class_public_items').remove();
    }

    if (!options_all.client.show_makeups) {
        $('.makeup_items').remove();
    }

    if (options_all.client.classes_public_advance) {
        $('.class_feature_2').prop('dataset').intrac_classes_public_advance = 'y';
    }

    let level_id_options = '<option value="0"></option>';
    for (let i = 0; i < options.levels.length; i++) {
    	level_id_options += '<option value="'+options.levels[i].level_id+'" data-intrac="'+options.levels[i].level_type+'" data-intrac_open="'+options.levels[i].open+'">'+options.levels[i].level_name+'</option>';
    }
    $('.class_level_id').html(level_id_options);
    $('.restr_level_ids_class').html(level_id_options.replace('<option value="0"></option>', '<option value="0">No level</option>'));
    $('.lists_class_level_id').html(level_id_options.replace('<option value="0"></option>', '<option value=""></option>'));

    let term_id_options = '';
    let term_id_options_ = '';
    for (let i = 0; i < options.terms.length; i++) {
    	term_id_options += '<option value="'+options.terms[i].term_id+'">'+options.terms[i].term_name+'</option>';
    	if (dates_diff(options.terms[i].term_start, dayjs().format('YYYY-MM-DD')) > 0) {
    		term_id_options_ += '<option value="'+options.terms[i].term_id+'">'+options.terms[i].term_name+'</option>';	
    	}
    }
    $('.class_term_id').html(term_id_options);
    $('.multir_term_id').html(term_id_options_);
    $('.notices_term_id').html(term_id_options_);

    //users and spaces select options - start
    //spaces select options
    let space_id_options = '<option value="0"></option>';

    for (let i = 0; i < options.spaces.length; i++) {
        space_id_options += '<option value="'+options.spaces[i].space_id+'" data-intrac_location_id="'+options.spaces[i].location_id+'">'+options.spaces[i].space_name+'</option>';
    }

    $('.ps_space_id').html(space_id_options);
    if (options.spaces.length) {
    	$('.bspace_list').html(space_id_options);
    	$('.bspace_div').removeClass('noshow_imp');
    }
    $('.shuffle_space_id').html(space_id_options.replace('<option value="0"></option>',''));

    //users select options
    let user_id_options = '<option value="0"></option>';

    for (let i = 0; i < options.users.length; i++) {
        user_id_options += '<option value="'+options.users[i].user_id+'">'+options.users[i].username+'</option>';
    }

    $('.ps_user_id').html(user_id_options);
    if (options.users.length) {
    	$('.buser_list').html(user_id_options);
    	$('.buser_div').removeClass('noshow_imp');
    }

    $('.sched_swap_user_id').html(user_id_options.replace('<option value="0"></option>', '<option value="0">No User Assigned</option>'));
    $('.lists_pr_user_id').html(user_id_options.replace('<option value="0"></option>', '<option value=""></option>'));

    //multi options
    $('.ps_space_ids tbody').html('');
    let space_ids_html = '';
    for (let i = 0; i < Math.max(options.spaces.length, options.users.length); i++) {
        if (i<20) {
            space_ids_html += '<tr>\
                                    <td class="space_td">\
                                        <div class="form-label margin_btm_sm">\
                                            <label class="checkbox-container">\
                                                <input type="checkbox" class="checkbox-custom ps_su_sel">\
                                            </label>\
                                            <div class="form-select-group margin_left_md">\
                                                <select class="form-select ps_space_id_">'+space_id_options+'</select>\
                                            </div>\
                                        </div>\
                                    </td>\
                                    <td class="user_td noshow">\
                                        <div class="form-select-group margin_left_md margin_btm_sm">\
                                            <select class="form-select ps_user_id_">'+user_id_options+'</select>\
                                            '+(i == 0 ? '<img class="tooltip_img ps_user_id_ttip" src="images/icons/info.svg" alt="">':'')+'\
                                        </div>\
                                    </td>\
                                <tr>';
        } else {
            break; //break the loop
        }

    }    
    $('.ps_space_ids tbody').html(space_ids_html);

    //hide spaces selection if there are no spaces
    if (!options.spaces.length) {
        $('.ps_space_single_div, .ps_space_id_').addClass('noshow')
    } else {
        $('.ps_space_single_div, .ps_space_id_').removeClass('noshow')
    }

    //hide users selection if there are no users
    if (!options.users.length) {
        $('.ps_user_id_div, .ps_user_id_').addClass('noshow')
    } else {
        $('.ps_user_id_div, .ps_user_id_').removeClass('noshow')
    }
    //users and spaces select options - end

    $('.class_term_id option:last').prop('selected', true);

    $('.class_ho_name').text(options.ho_name);
    $('.client_class_features').val(options.class_features);

    if (!options.show_restrictions) {
        $('.class_restrictions').remove();
    } else {
        if (!options.show_gender_restriction) {
            $('.class_restrictions .restr_restriction_type option[value="1"]').remove();
        }
        if (!options.show_age_restriction) {
            $('.class_restrictions .restr_restriction_type option[value="2"]').remove();
            $('.class_restrictions .restr_restriction_type option[value="3"]').remove();
        }
        if (!options.show_level_restriction) {
            $('.class_restrictions .restr_restriction_type option[value="4"]').remove();
        }        
    }
}

function getRegistersOptions(options) {
    if (options.cancel_reason) {
        let cancel_reason_str = options.cancel_reason.length ? options.cancel_reason.join('~') : '';
        $('.reg_cancel_reason').text(cancel_reason_str);
        $('.cregister_cancel_reason').text(cancel_reason_str);
    }

    if (options.max_quantity) { //serves as show_register_quantity too
        $('.reg_alter_quantity').prop('max',options.max_quantity);
        $('.reg_alter_quantity_div').removeClass('noshow');

        $('.cregister_quantity').prop('max',options.max_quantity);
        $('.cregister_quantity_tr').removeClass('noshow');
    } else {
    	$('.cregister_quantity_tr').remove();
    }

    if (options.child_only) { 
        $('.cregister_cust_list').prop('dataset').intrac_child_only = "true";
    }

    if (options.register_addons && options.register_addons.length) {
        let addons_html = '';
        for (let i = 0; i < options.register_addons.length; i++) {
            let e = options.register_addons[i];
            let checked = e.optional ? '' : ' checked'+($('#is_admin').val() ? '' : ' disabled');
            addons_html += '<div class="register_addons_row form-label noshow"><label class="checkbox-container"> '+e.display+'<input type="checkbox" class="checkbox-custom register_addons" value="'+e.product_id+'" data-intrac_mode="'+(e.mode || '')+'" data-intrac_optional="'+(e.optional || '')+'" data-intrac_price="'+e.price+'" data-intrac_product_details="'+e.product_details+'" '+checked+'></label></div><br>';
        }
        $('.cregister_class_addons').html(addons_html);
        $('.cregister_class_addons_tr').removeClass('noshow');
    }
}

function getCustomersOptions(options, options_all) {

	if (options_all.client.integrated_eftpos) {
		$('.cust_payment input[name="mode"][value="eftpos"]').attr('checked', 'checked'); //using .attr instead of .prop because the latter won't work on hidden elements that are copied later as html()
	} else {
		$('.cust_payment input[name="mode"][value="cash"]').attr('checked', 'checked'); //using .attr instead of .prop because the latter won't work on hidden elements that are copied later as html()
	}
    
    if (!options.show_child) {
        $('.child_items').remove();
    }

    if (options.show_checkin) {
        $('.checkin_items').removeClass('noshow');
    } else {
    	$('.checkin_items').remove();
    }

    if (!options.show_customer_images) {
        $('.cust_image_tr').remove();
        $('.cust_image_child_tr').remove();
    } else {
        $('.cust_image_tr').addClass('show_images');
        $('.cust_image_child_tr').addClass('show_images');
        $('.cust_img_buttons').addClass('noshow');
    }

    //purchase settings
    if (options.show_refund_choice) {
        $('.refund_payments_tr').removeClass('noshow');
        $('.refund_payments_eftpos_tr').removeClass('noshow');
    } else {
        $('.refund_payments_tr').addClass('noshow');
        $('.refund_payments_eftpos_tr').addClass('noshow');
    }

    //lists related options
    if (!options.show_dob && !options.show_dob_ch) {
    	$('.lists_dob_from').closest('div').remove();
    	$('.lists_dob_to').closest('div').remove();
    }

    if (!options.show_gender && !options.show_gender_ch) {
    	$('.lists_gender').closest('div').remove();
    }

    if (!options.show_level && !options.show_level_ch) {
    	$('.lists_level_id').closest('div').remove();
    } else {
        let opts_str = '<option value=""></option>';
        for (let i = 0; i < options.levels.length; i++) {
            opts_str += '<option value="'+options.levels[i].level_id+'">'+options.levels[i].level_name+'</option>';
        }
        $('.lists_level_id').html(opts_str);
    }

    set_customer_form_fields(options);
}

function getTermsOptions(options) {
    if ((!options.client_booking) && (!options.location_booking)) {
    	$('.bookingdts_items').remove();
    }

    if (options.client_booking) {
        $('.term_clientbookingdt').attr('value', convert_date(options.client_booking)); //$(mc+' .term_clientbookingdt') isn't loaded yet, so setting it in the master
        //using .attr instead of .val because the latter won't work on hidden elements that are copied later as html()
        $('.term_client_booking_div').show();

        if (options.client_delay) {
        	if (isvalidDateTime(options.client_delay)) {
        		$('.term_clientdelaydt').attr('value', convert_date_time(options.client_delay, 'D MMM YYYY')); //$(mc+' .term_clientdelaydt') isn't loaded yet, so setting it in the master
        		$('.term_clientdelaytime').attr('value', convert_date_time(options.client_delay, 'HH:mm'));
        		//using .attr instead of .val because the latter won't work on hidden elements that are copied later as html()
        	} else {
        		$('.term_clientdelaydt').attr('value','');
        		$('.term_clientdelaytime').attr('value','');
        	}
        } else {
        	$('.term_clientdelay_div').remove();
        }
    }

    if (options.location_booking) {
    	$('.term_location_booking_div').show();
    }

    $('.public_holidays_all').html(JSON.stringify(options.holidays));
}

function getUsersOptions(options, options_all) {

	//user images always available
    $('.user_image_tr').addClass('show_images');
    $('.user_img_buttons').addClass('noshow');

	if (options_all.client.is_multitenant) {
		if (options_all.user_location_id > 0) {
			$('.add_customer').remove();
		}
	}

    if (options.strong_password) {
        $('.usr_password').addClass('strongpwd');
    }

    if (!options.show_user_comments) {
    	$('.user_comments_items').remove();
    }

    if (!options.show_comment) {
        $('.usr_comment_tr').hide();
    } else {
        if (options.comment) {
            $('.usr_comment_tr td:first').text(options.comment+':');
        }        
    }
    if (!options.show_business) {
        $('.usr_business_tr').hide();
    } else {
        if (options.business) {
            $('.usr_business_tr td:first').text(options.business+':');
        }
    }

    if (options.payrate) {
    	let rates_str = '';
    	for (let i = 0; i < options.payrate.length; i++) {
            for(const key in options.payrate[i]) {
            	if (!options.payrate[i][key].generic && !options.payrate[i][key].roster_only) {
	                let def = 0;
	                if (options.payrate[i][key].default) {
	                    def = options.payrate[i][key].default;
	                } else {
	                    def = options.payrate[i][key];
	                }
	                rates_str += '<div class="form-group">\
	                                <div class="label">'+((options.payrate[i][key].display)?(options.payrate[i][key].display):(toTitleCase(key)+ ' rate'))+'</div>\
	                                <div class="input-group">\
	                                    <input type="text" name="'+key+'" value="'+def+'" class="form-control usr_payrates">\
	                                </div>\
	                            </div>';
            	}
            }
        }
        $('.user_payrates_div').replaceWith(rates_str);
    }

    if (options.show_location) {
        let options_str_l = '<option value="0">All locations</option>';
        for (let i = 0; i < options.locations.length; i++) {
            options_str_l += '<option value="'+options.locations[i].location_id+'">'+options.locations[i].location_name+'</option>';
        }
        $('.usr_location_id').html(options_str_l);
    } else {
        $('.usr_location_th').addClass('noshow');
        $('.usr_location_tr').addClass('noshow');
    }

    //extras
    if (!options.show_apiuser) {
        $('.btn_usr_apiuser').remove();
    }
    if (!options.show_qualify) {
        $('.qual_items').remove();
    }
}

