function getReportsOptions(options) {
    if (!options.show_report_charts) {
        $('.report_chart_items').remove();
        $('.view_rep_data').remove();
    }    

    let html_str = '';

    //add lists manually
    let lists_rep = $('.modal_o_lists').text();
    let lists_rep_html = lists_rep && !$('.instructor-page').length ? '<li><a href="#" class="menu_item view_lists_report fav_lists" data-intrac_fav_name="'+lists_rep+'">'+lists_rep+'</a></li>' : '';
    let lists_rep_i = -1;
    if (lists_rep) {
	    for (let i = 0; i < options.reports.length; i++) {
	        if (lists_rep.localeCompare(options.reports[i].report_name, undefined, { sensitivity: 'base' }) < 0) {
	            lists_rep_i = i;
	            break;
	        }
	    }
	}

    //add pass report manually
    let pass_rep = $('.modal_o_passtypes').text();
    let pass_rep_html = pass_rep && !$('.instructor-page').length ? '<li><a href="#" class="menu_item view_pass_report">'+pass_rep+'</a></li>' : '';
    let pass_rep_i = -1;
    if (pass_rep) {
	    for (let i = 0; i < options.reports.length; i++) {
	        if (pass_rep.localeCompare(options.reports[i].report_name, undefined, { sensitivity: 'base' }) < 0) {
	            pass_rep_i = i;
	            break;
	        }
	    }
	}

    for (let i = 0; i < options.reports.length; i++) {

    	if (lists_rep_i == i) {html_str += lists_rep_html}
    	if (pass_rep_i == i) {html_str += pass_rep_html}

        let d = options.reports[i];
        let ttip = '';
        html_str += '<li'+(d.hidden_report ? ' class="noshow"' : '')+'><a href="#" class="menu_item view_report'+(d.hidden_report ? '' : ' fav_report_'+d.report_id)+(d.report_description ? ' rep_ttip' : '')+'" data-intrac="'+d.report+'" data-intrac_report_description="'+d.report_description+'" data-intrac_fav_name="'+d.report_name+'" data-intrac_default_dates="'+d.default_dates+'" data-intrac_max_days="'+d.max_days+'" data-intrac_navigation="'+d.navigation+'" data-intrac_sub_reports="'+(d.sub_reports.length > 1 ? JSON.stringify(d.sub_reports).replace(/"/g, '&quot;') : '[]')+'">'+d.report_name+ttip+'</a></li>';
    }

    $('#reports_list').html(html_str);

    init_day_flatpickr('#sh_reports .rep_start_date');
    init_day_flatpickr('#sh_reports .rep_finish_date');
    init_month_flatpickr('#sh_reports .rep_month');
}

function getFavsOptions(options) {
	
	//defaults
	let all_favs = [];

	$('a[class*="fav_"]').each(function () {
		let fav_ = [...$(this).prop('classList')].find(className => className.startsWith('fav_'));
		let name = $(this).prop('dataset').intrac_fav_name;
		all_favs.push({
			key: fav_.replace('fav_',''),
			name: fav_.includes('report') ? name+' Report' : name
		});
    });

	all_favs.sort((a, b) => a.name.localeCompare(b.name)); //sort alphabetically based on name

	let opts_str = '';
	let html_str = '';
	for (let i = 0; i < all_favs.length; i++) {
		opts_str += '<option value="'+all_favs[i].key+'">'+all_favs[i].name+'</option>';
		if (i < 10) { //max 10 favs can be set
			html_str += '<tr class="usr_favs_row">\
							<td class="no-form form-group-flex">\
								<div class="form-label">\
									<label class="checkbox-container">&nbsp;\
										<input type="checkbox" class="checkbox-custom usr_favs_chk" value="1">\
									</label>\
								</div>\
	                            <div class="form-select-group no_margin_btm">\
	                                <select class="form-select form-control inp_def_width usr_favs_key"></select>\
	                            </div>\
							</td>\
							<td>\
	                            <div class="no-form">\
	                                <input type="text" class="form-control inp_def_width usr_favs_name" value="">\
	                            </div>\
							</td>\
						</tr>';	
		}	
	}

	$('.favs_list tbody').html(html_str);
	$('.favs_list .usr_favs_key').html(opts_str);

	//selected favs
	let favs = options.favourites ? options.favourites : all_favs;

	let li_str = '';
	for (let i = 0; i < (options.favourites ? favs.length : Math.min(favs.length, 10)); i++) { //max 10 favs of the default
		if ($('.fav_'+favs[i].key+':first').length) {
			let classlist = [...$('.fav_'+favs[i].key+':first').prop('classList')].filter(cls => !cls.startsWith('fav_')).join(' ')+' menu_item'; //remove fav_ from class names for li
			let datalist =  Object.entries($('.fav_'+favs[i].key+':first')[0].dataset).map(([key, value]) => key == 'intrac_sub_reports' ? `data-${key}="${String(value).replace(/"/g, '&quot;')}"` : `data-${key}="${value}"`).join(' '); //all data-* items
			
			let fav_name = (favs[i].name || $('.fav_'+favs[i].key+':first').prop('dataset').intrac_fav_name);
			if (classlist.includes('view_report') && !fav_name.toLowerCase().includes('report') && !favs[i].name) {
				fav_name += ' Report';
			}

			li_str += '<li><a href="#" class="'+classlist+'" '+datalist+'>'+fav_name+'</a></li>';				
		}
	}
	li_str += '<li><a href="#" class="menu_item manage_favs">Manage Favourites</a></li>';
	$('#quick_actions').html(li_str);

	$('#quick_actions_opts').text(li_str);
	$('.user_options_favs').text(JSON.stringify(options.favourites ? favs : []));

	$('#mobile_favourites').html($('#quick_actions').html());
	$('#mobile_favourites .manage_favs').remove();
	adjustFavs();

	//re-order functions and reports
	if (!$('.instructor-page').length) {
		$('.star_fav').removeClass('star_fav');
		if (options.favourites) {
			for (let i = 0; i < options.favourites.length; i++) {
				let f = options.favourites[i].key;

				$('#functions_list .fav_'+f).addClass('star_fav');
				$('#mobile_functions .favm_'+f).addClass('star_fav');

				$('#reports_list .fav_'+f).addClass('star_fav');
				$('#mobile_reports .favm_'+f).addClass('star_fav');
			}
		}
	}

	//dashboard
	if ($('.reports_only').length) {
		if (options.dashboard_layout) {
			$('#dashboard_layout').text(JSON.stringify(options.dashboard_layout));
		} else {
			$('#dashboard_layout').text('');
		}
	}

	//grid_default
	if (options.grid_default) {
		$('#grid_default').closest('li').addClass('noshow');
		$('#grid_default_reset').closest('li').removeClass('noshow');
	} else {
		$('#grid_default').closest('li').removeClass('noshow');
		$('#grid_default_reset').closest('li').addClass('noshow');
	}

	//mini_grid
	if (options.mini_grid) {
		if (options.mini_grid.includes('s')) {
			$('#spaces').addClass('mini_grid');	
		}
		if (options.mini_grid.includes('l')) {
			$('#lessons').addClass('mini_grid');	
		}
		if (options.mini_grid.includes('c')) {
			$('#classes').addClass('mini_grid');	
		}
		if (options.mini_grid.includes('r')) {
			$('#rosters').addClass('mini_grid');	
		}		
	}
}

