function getMessagesOptions(options, open_messages=false) {
    if (!options.show_messages) {
        $('.message_items').remove();
    } else {
	    let user_id_options =  $('#is_admin').val() ? '<option value="0">Everyone</option>' : '';

	    for (let i = 0; i < options.users.length; i++) {
	        user_id_options += '<option value="'+options.users[i].user_id+'">'+options.users[i].username+'</option>';
	    }

	    $('.msg_user_ids').html(user_id_options);
    }

    if (options.open_messages && open_messages) {
    	$('#master_message_view .tl_msg_comments').prop('dataset').intrac_silent = true;
    	$('.modal_o_messages:first').click();
    }

    if (options.comment_general) {
        let sel_str = '';
        let div_str = '';
        for (let k = 0; k < options.comment_general.length; k++) {
            let s = options.comment_general[k];

            sel_str += '<option value="'+s.name+'">'+s.name+'</option>';


            for (let w = 0; w < s.items.length; w++) {
                let e = s.items[w];

                if (e.type == 'text') {
                    div_str += '<div class="form-group msg_gen_item'+(k == 0 ? '' : ' noshow')+'" data-intrac="'+s.name+'" data-intrac_comment="'+e.comment_text+'">\
                                    <div class="label">'+e.display+'</div>\
                                    <input type="text" class="form-control msg_gen_value" value="" placeholder="">\
                                </div>';
                }

                if (e.type == 'select') {
                    let opts_str = '<option value=""></option>';
                    for (let i = 0; i < e.values.length; i++) {
                        opts_str += '<option value="'+e.values[i]+'">'+e.values[i]+'</option>';
                    }                

                    div_str += '<div class="form-group msg_gen_item'+(k == 0 ? '' : ' noshow')+'" data-intrac="'+s.name+'" data-intrac_comment="'+e.comment_text+'">\
                                    <div class="label">'+e.display+'</div>\
                                    <select class="form-control msg_gen_value">'+opts_str+'</select>\
                                </div>';
                }
            }

        }
        $('#master_message_view .msg_gen_type').html(sel_str);
        $('#master_message_view .msg_gen_items').replaceWith(div_str);
    } else {
    	$('.message_general_items').remove();
    }
}

