async function location_changed() {
	$('.cur_location_name').text($('#main_switch_location a[data-intrac="'+$('#location_id').val()+'"]').text());
	//start/end times for avail; others have options dependant on location
    let options = await get_client_options(['loc_change']);
    getAvailsOptions(options.avail || '');
    getCashSaleOptions(options.cash_sale || '', options);
    getUsersOptions(options.user || '', options);
    getClasssOptions(options.class || '', options);
    getPasstypesOptions(options.passtype || '');
    getHoldsOptions(options.hold || '');
    getRostersOptions(options.roster || '');
    getMessagesOptions(options.message || '');
    getMultiTenantOptions(options.client);
}

function getClasssResults(res) {

    let data = res.data;

    let class_enrolment_titles = JSON.parse($('#class_enrolment_titles').text());

    let html_str = '';

    for (let i = 0; i < data.length; i++) {
        
    	data[i].term_name = data[i].term_name || ''; //legacy classes without any term_id e.g. sports

        let comp = (data[i].level_type == 4) ? true : false;
        let enr = ([0,1,2,4].includes(data[i].level_type)) ? true : false;
        let rlvr = ([0,1,6].includes(data[i].level_type)) && (data[i].status > 0) && data[i].term_id && (data[i].category != 'Deprecated') ? true : false; //legacy classes without any term_id or deprecated level e.g. sports are excluded

        let is_admin = $('#is_admin').val() ? true : false;

        let status_map = {
            0: '<span class="event-status bg-gray-100 text-gray"><span class="size-1.5 bg-gray rounded-[20px]"></span> Archive</span>',
            1: '<span class="event-status bg-yellow-100 text-black"><span class="size-1.5 bg-yellow rounded-[20px]"></span> Renewals</span>',
            2: '<span class="event-status text-purple-dark bg-purple-pretty"><span class="size-1.5 bg-purple-dark rounded-[20px]"></span> Returning Customers</span>',
            3: '<span class="event-status bg-blue-100 text-blue"><span class="size-1.5 bg-blue rounded-[20px]"></span> Changes</span>',
            4: '<span class="event-status bg-green-100 text-green"><span class="size-1.5 bg-green rounded-[20px]"></span> Open</span>',
            5: '<span class="event-status bg-coral-100 text-coral"><span class="size-1.5 bg-coral rounded-[20px]"></span> Closed</span>'
        }

        //header
        if ((i == 0) || (data[i].level_name != data[i-1].level_name) || ((data[i].level_type == 4) && (data[i].term_name != data[i-1].term_name))) {
            let header = (data[i].level_type == 4) ? data[i].term_name : data[i].level_name;
            html_str += '<h4 class="section_title text-xl leading-[18px]">'+header+'</h4><div class="table-wrapper plain-table classes-table">';

            html_str += '<table class="table">\
                            <thead>\
                                <tr>\
                                    <th class="th-lg">Title</th>\
                                    <th class="th-lg">'+toTitleCase($('#term_title').val())+'</th>\
                                    <th class="th-sm"><img src="images/icons/instructors.svg" data-intrac_tooltip="Capacity" class="cl_status_ttip inline-block cursor size-6"></th>\
                                    '+(comp ? '<th class="th-sm"><img src="images/icons/file.svg" data-intrac_tooltip="Teams" class="cl_status_ttip inline-block cursor size-6"></th>' : '')+'\
                                    '+(enr ? '<th class="th-sm"><img src="images/icons/users.svg" data-intrac_tooltip="'+toTitleCase(class_enrolment_titles.title || 'enrolment')+'s" class="cl_status_ttip inline-block cursor size-6"></th></th>' : '')+'\
                                    <th>Status</th>\
                                    <th>Actions</th>\
                                </tr>\
                            </thead>\
                            <tbody>'

        }

        //table body
        html_str += '<tr class="class_row">\
                        <td><a href="#" class="primary modal_o_class edit_class class_name">'+data[i].class_name+'</a></td>\
                        <td>'+(rlvr ? '<a href="#" class="primary modal_o_rollover get_class_rollover">'+data[i].term_name+'</a>' : data[i].term_name)+'</td>\
                        <td class="noshow class_id">'+data[i].class_id+'</td>\
                        <td class="noshow class_level_type">'+data[i].level_type+'</td>\
                        <td class="td-sm">'+(data[i].capacity > 0 ? data[i].capacity : '')+'</td>\
                        '+(comp ? '<td class="td-sm">'+data[i].teams+'</td>' : '')+'\
                        '+(enr ? '<td class="td-sm">'+data[i].enrolments+'</td>' : '')+'\
                        <td class="class_status">'+status_map[data[i].status]+'</td>\
                        <td>\
                            <ul class="table-actions">\
                                <li><a href="#" class="btn-edit modal_o_class edit_class">Manage</a></li>\
                                '+(rlvr && is_admin ? '<li><a href="#" class="btn-edit modal_o_rollover get_class_rollover">Rollover</a></li>' : '')+'\
                            </ul>\
                            <div class="show_tabs noshow">\
                                tl_class_enrolments,\
                                tl_programs,\
                                tl_schedules,\
                                '+(comp ? 'tl_teams' : '')+',\
                                '+(comp ? 'tl_fixtures' : '')+',\
                                '+(comp ? 'tl_ladder' : '')+',\
                                tl_attendance,\
                                '+(!comp ? 'tl_waitlist' : '')+'\
                            </div>\
                        </td>\
                    </tr>';

        //close table
        if ((i == data.length-1) || (data[i].level_name != data[i+1].level_name) || ((data[i].level_type == 4) && (data[i].term_name != data[i+1].term_name))) {
            html_str += '</tbody></table></div>';
        }

        if (rlvr) {
        	$('#location_rollover').closest('li').removeClass('noshow');
        }

    }

    $('#classes_list').html(html_str);

    filter_classes();
}

function toggle_class_inputs() {

    let level_type = $(mc+' .class_level_id option[value="' + $(mc+' .class_level_id').val() + '"]').prop('dataset').intrac;
    let status = $(mc+' .class_status').val();

    let new_class = $(mc+' .class_class_id').val() ? false : true;

    //status
    if ((level_type != '0') && (level_type != '1')) {
    	$(mc+' .class_status option[value="2"]').hide(); //Returning Customers
    	$(mc+' .class_status option[value="3"]').hide(); //Changes
    } else {
		$(mc+' .class_status option[value="2"]').show(); //Returning Customers
    	$(mc+' .class_status option[value="3"]').show(); //Changes    	
    }

    //status tooltip
    if (level_type == '4') {
    	$(mc+' .clstatuscompttip').removeClass('noshow');
    } else {
    	$(mc+' .clstatuscompttip').addClass('noshow');
    }

    //features
    //features set per client
    let features = $(mc+' .client_class_features').val().split('');

    //resets
    $(mc+' .class_feature_div').hide();
    $(mc+' .class_feature_div_group [class*="class_feature_"]').prop('disabled', false);

    for (let i = 0; i < features.length; i++) {
        let passed = false;

        if (features[i] == 't') {
            if (level_type == '4') {
                passed = true;
            }
        } else if (['p','c','l'].includes(features[i])) {
            if (level_type == '4') {
                passed = true;
            }
        } else if (features[i] == 'g') {
            if (level_type == '4') {
                passed = true;
		        if ((status != '4') && (status != '5')) {
		            $(mc+' .class_feature_g').prop('disabled', true);    
		        }                
            }
        } else if (features[i] == '0') {
            if ((level_type == '0') || (level_type == '1') || (level_type == '6')) {
                passed = true;
            }          
        } else {
            passed = true; //h
        }

        if (passed) {
            $(mc+' .class_feature_'+features[i]).closest('.class_feature_div').show();
        }
    }
    //features - common
    //s
    if (level_type == '4') {
        $(mc+' .class_feature_s').closest('.class_feature_div').show();
        if (status != '1') {
            $(mc+' .class_feature_s').prop('disabled', true);    
        }
    }

    //n
    if (level_type == '4') {
        $(mc+' .class_feature_n').closest('.class_feature_div').show();
        if ((status != '4') && (status != '5')) {
            $(mc+' .class_feature_n').prop('disabled', true);    
        }
    }

    //r
	if ((level_type == '0') || (level_type == '1') || (level_type == '6') || (level_type == '4')) {
		$(mc+' .class_feature_r').closest('.class_feature_div').show(); //div already removed if no emailconfirmregister - register_email_div
		$(mc+' .class_feature_w').closest('.class_feature_div').show(); //div already removed if no emailonlineregister - regworkflow_email_div
	}

    //m
	if ((level_type == '0') || (level_type == '1') || (level_type == '6')) {
		$(mc+' .class_feature_m').closest('.class_feature_div').show(); //div already removed if no register_addons
	}

    //a
	if ((level_type == '0') || (level_type == '1') || (level_type == '6')) {
		$(mc+' .class_feature_a').closest('.class_feature_div').show(); //div already removed if no product_addons
	}

    //0,1,6 - class_public_items, won't show unless public_view is set for classes
	if ((level_type == '0') || (level_type == '1') || (level_type == '6')) {
		$(mc+' .class_feature_0').closest('.class_feature_div').show();
		if (features.includes('0') && new_class) {
			$(mc+' .class_feature_0').prop('checked', true);
		}
	}
	if (level_type == '1') {
		if ($(mc+' .class_feature_2').prop('dataset')?.intrac_classes_public_advance) {
			$(mc+' .class_feature_1').closest('.class_feature_div').show();
			$(mc+' .class_feature_2').closest('.class_feature_div').show();			
		}
	}
	if (level_type == '0') {
		$(mc+' .class_feature_2').closest('.class_feature_div').show();
	}

	//3 - makeup_items, won't show unless makeup module is set
	if (level_type == '1') {
		$(mc+' .class_feature_3').closest('.class_feature_div').show();
	}

	//4 - private registers, won't show unless option in class is set
	if ((level_type == '0') || (level_type == '1') || (level_type == '6')) {
		$(mc+' .class_feature_4').closest('.class_feature_div').show();
	}

    //5 - roll code, won't show unless emailrollcode is set
	if ((level_type == '0') || (level_type == '1') || (level_type == '6') || (level_type == '4')) {
		$(mc+' .class_feature_5').closest('.class_feature_div').show();
	}

    //cost per
    let per = 'per ';
    if (level_type == '0') {
        per += $('#term_title').val(); 
    } else if (level_type == '1' || level_type == '2' || level_type == '6' || level_type == '7' || level_type == '9') {
        per += 'booking'; 
    } else if (level_type == '4') {
        if (features.includes('t')) {
            per = '';
        } else {
            per += 'player'; 
        }
        
    }
    if (($(mc+' .class_flat_cost').val() == 'flat_cost') || (($(mc+' .class_flat_cost').val() == 'flat_cost_0') && (level_type == '0'))) {
        per = '';
    }
    $(mc+' .cost_per').text(per);
}

function filter_classes() {
	let title = $('#class_search').val().trim().toLowerCase();
	let status = $('#class_status_filter span').text().toLowerCase();

	$('#classes_main .section_title.noshow').removeClass('noshow');
	$('#classes_main .classes-table.noshow').removeClass('noshow');
	$('#classes_main .class_row.noshow').removeClass('noshow');

	$('#classes_main .class_row').each(function() {
		let valid = true;

		if (title && !$(this).find('.class_name').text().toLowerCase().includes(title)) {
			valid = false;
		}

		if (status && (status != 'all') && !($(this).find('.class_status').text().trim().toLowerCase() == status)) {
			valid = false;
		}

		if (!valid) {
			$(this).addClass('noshow');
		}
	});

	$('#classes_main .section_title').each(function() {
		if (!$(this).next('.classes-table').find('.class_row:not(.noshow)').length) {
			$(this).addClass('noshow');
			$(this).next('.classes-table').addClass('noshow');
		}	
	});
}

function editClass(class_id, spinner=true) {

	return new Promise((resolve, reject) => {

	    //resets
	    //need to do resets because we are using term_id/name, level_id/name from the api below
	    $(mc+' select.class_level_id option[value!="0"]').remove();
	    $(mc+' select.class_term_id option[value!="0"]').remove();

	    //data
	    $(mc+' .class_class_id').val(class_id); //set it first incase any parallel modal actions are dependant on it

	    /* fetch from api directly because of html in class_comment*/
	    if (spinner) {$('#loader-wrapper').show()};

	    let querydata = {class_id: class_id, show_archive: true};

        if ($('.instructor-page').length) {
            querydata.from = 'instructor';
        }

	    $.ajax({
	        type: 'GET',
	        url: '/api/getClasss',
	        data: querydata,
	        dataType: 'JSON'
	    }).done(function( response ) {

	        if (response.success != undefined) {

	            if (spinner) {$('#loader-wrapper').hide()};

	            if (response.success.data.length) {
	                let itemobj = response.success.data[0]; //override itemobj

	                if (itemobj.level_id != 0) {
	                    $(mc+' .class_level_id').append($('<option>', {
	                        value: itemobj.level_id,
	                        text: itemobj.level_name,
	                        'data-intrac': itemobj.level_type,
	                        'data-intrac_open': itemobj.open
	                    }));                    
	                }
	                $(mc+' .class_level_id').val(itemobj.level_id).prop('disabled', true);

	                if (itemobj.term_id != 0) {
	                    $(mc+' .class_term_id').append($('<option>', {
	                        value: itemobj.term_id,
	                        text: itemobj.term_name
	                    }));
	                }
	                $(mc+' .class_term_id').val(itemobj.term_id).prop('disabled', true);

					if ((itemobj.level_type == 4) && (dates_diff(itemobj.term_finish, itemobj.term_start) < 4)) {
	                    $(mc+' .class_term_id').prop('dataset').intrac_gala_term = 'y';
	                }	                

	                $(mc+' .class_status').val(itemobj.status);
	                $(mc+' .class_name').val(itemobj.class_name);
	                $('.modal_title_mc1').text(itemobj.class_name);
	                $(mc+' .class_capacity').val(itemobj.capacity);
	                $(mc+' .class_cost').val(itemobj.cost);
	                $(mc+' .class_special_cost').val(itemobj.special_cost);

	                let quill = Quill.find($(mc+' .class_class_comment')[0]);
	                quill.clipboard.dangerouslyPasteHTML(itemobj.class_comment);
	                quill.blur();
	                
	                $(mc+' .class_info').val(itemobj.info);

	                $(mc+' .class_class_features').val(itemobj.features);

	                let features = itemobj.features.split('');

	                for (let i = 0; i < features.length; i++) {
	                    if (features[i] == 't') {
	                        $(mc+' .class_feature_t').val('t');
	                    } else {
	                        $(mc+' .class_feature_'+features[i]).prop('checked', true);    
	                    }
	                }

	                $(mc+' .class_feature_t').prop('disabled', true);

	                toggle_class_inputs();

	                //comments
	                let comments_str = '';
	                for (let i = 0; i < itemobj.comments.length; i++) {
	                    let c = itemobj.comments[i];

	                    comments_str += '<tr class="class_comment_row">\
	                                        <td class="w-75p">\
	                                            <span class="comment_id noshow">'+c.comment_id+'</span>\
	                                            Created by '+(c.opener || 'Online')+' '+convert_date(c.open)+'<br>'+c.comment_data.replace(/\r?\n|\r/g,"<br>");
	                    if (isvalidDate(c.close)) {
	                            comments_str += '<br>'+'Archived '+convert_date(c.close)+(c.username ? ' by '+c.username : '');
	                    }

	                        comments_str += '</td>';

	                        comments_str += '<td>\
	                                            <ul>\
	                                                '+(itemobj.status > 0 ? '<li><a href="#" class="btn-edit class_comment_edit">Edit</a></li>' : '')+'\
	                                                '+($('#is_admin').val() && (itemobj.status > 0) ? '<li><a href="#" class="btn-edit class_comment_delete">Delete</a></li>' : '')+'\
	                                            </ul>\
	                                        </td>';

	                    comments_str += '</tr>';                                    
	                }
	                $(mc+' .class_comments_list tbody').html(comments_str);

	                //restrictions
	                let restr_str = '';
	                if (itemobj.restrictions) {
	                    let restrictions = itemobj.restrictions;                
	                    for (let i = 0; i < restrictions.length; i++) {
	                        let restriction_name = '';

	                        if (restrictions[i].restriction_type == 1) {
	                            restriction_name = 'Gender';
	                        } else if (restrictions[i].restriction_type == 2) {
	                            restriction_name = 'Min Age';
	                        } else if (restrictions[i].restriction_type == 3) {
	                            restriction_name = 'Max Age';
	                        } else if (restrictions[i].restriction_type == 4) {
	                            restriction_name = 'Level';
	                        }

	                        let r = restrictions[i];

	                        restr_str += '<tr class="class_restr_item">\
	                                            <td>\
	                                                <span class="restriction_id noshow">'+r.restriction_id+'</span>\
	                                                <span class="restriction_type noshow">'+r.restriction_type+'</span>\
	                                                <span class="restriction_value noshow">'+r.value+'</span>\
	                                                '+restriction_name;
	                                restr_str += '</td>';

	                                restr_str += '<td>'+(restrictions[i].restriction_type == 4 ? r.level_names : r.value)+'</td>';

	                                restr_str += '<td>\
	                                                <ul>\
	                                                    '+($('#is_admin').val() && (itemobj.status > 0) ? '<li><a href="#" class="btn-edit class_restr_update">Edit</a></li>' : '')+'\
	                                                    '+($('#is_admin').val() && (itemobj.status > 0) ? '<li><a href="#" class="btn-edit class_restr_delete">Delete</a></li>' : '')+'\
	                                                </ul>\
	                                            </td>';

	                        restr_str += '</tr>';
	                    }                                    
	                }
	                $(mc+' .class_restrictions tbody').html(restr_str);

	                //deeplink
	                if (itemobj.level_type == 4) {
	                	$(mc+' .class_deeplink').text(window.location.origin+'/dashboard?page=team&tab=create_team&term_id='+itemobj.term_id+'&class_id='+class_id+(response.success.options?.is_multilocation ? '&location_id='+itemobj.location_id : ''));
	                } else {
	                	$(mc+' .class_deeplink').text(window.location.origin+'/dashboard?enrol='+class_id+(response.success.options?.is_multilocation ? '&location_id='+itemobj.location_id : ''));
	                }

	                //archived class
	                if (itemobj.status == 0) {
	                	$(mc+' .btn-default').remove();
	                	$(mc+' .btn-edit').remove();
	                }

                    //get image if exists
                    if ($(mc+' .class_image_tr').hasClass('show_images')) {

                        $(mc+' .class_image_tr').show();
                        
                        $(mc+' .class_image_tr .display_img').hide();

                        get_class_image(itemobj.class_id);
                    }

	            }

	        } else if (response.redirect != undefined) {
	            mini_login_wizard(response.redirect); //session timeout case
	        } else {    
	            set_side_error(response.error.join("<br>"));
	            $('#loader-wrapper').hide();           
	        }
	        resolve();

	    }).fail( function(xhr, textStatus, errorThrown) {
	        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
	        $('#loader-wrapper').hide();
	        resolve();
	    });
	}); 
}

function saveClass() {

    $('#loader-wrapper').show();

    //prepare the data

    let features = '';
    $(mc+' .class_feature_div input[type="checkbox"]:visible').each(function () {
        if (this.checked) {
            features += $(this).val();
        }
    });

    if ($(mc+' .class_feature_t:visible').val()) { //Payment type
        features += $(mc+' .class_feature_t:visible').val();
    }

    let data ={
        class_id: $(mc+' .class_class_id').val(),
        location_id: $('#location_id').val(),
        level_id: $(mc+' .class_level_id').val(),
        term_id: $(mc+' .class_term_id').val() || '',
        status: $(mc+' .class_status').val(),
        class_name: $(mc+' .class_name').val(),
        capacity: $(mc+' .class_capacity').val(),
        cost: $(mc+' .class_cost').val(),
        special_cost: $(mc+' .class_special_cost').val(),
        class_comment: sanitiseQuillHTML($(mc+' .class_class_comment .ql-editor').html()),
        info: $(mc+' .class_info').val(),
        features: features
    };  

    let errors = [];
    //validations
    if (!validator.isInt(data.level_id,{min: 1})) {
        errors.push('Invalid level'); 
    }

    if (!validator.isInt(data.term_id,{min: 0})) {
        errors.push('Invalid '+$('#term_title').val()); 
    }

    if (!validator.isInt(data.status,{min: 0})) {
        errors.push('Invalid status'); 
    }

    if (isEmpty(data.class_name) || data.class_name.length < 3) {
        errors.push('Invalid title');
    }

    if (!validator.isInt(data.capacity,{min: 0})) {
        errors.push('Invalid capacity'); 
    }

    if (!validator.isFloat(data.cost,{min: 0})) {
        errors.push('Invalid cost');
    }

    if ((!isEmpty(data.special_cost)) && (!validator.isFloat(data.special_cost,{min: 0}))) {
        errors.push('Invalid daily cost');
    }

    if (data.class_comment.includes('base64')) {
        errors.push('You can only upload images via Image URL button, please contact intrac team for further information');
    }

    if (errors.length == 0) {
        $.ajax({
            type: 'POST',
            url: '/api/saveClass',
            data: data,
            dataType: 'JSON'
        }).done(function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

                set_side_error(toTitleCase($('#class_title').val())+' saved succesfully', 'green');
                if ((!data.class_id) || (data.status == 0)) { //new class or archive
                    close_modal();
                } else {
                	editClass(data.class_id); //refresh data
                }

                //refresh classes
                if ($('#classes_main').is(":visible")) {
                	get_api('getClasss');
                }

                //refresh grid
                if ($('#classes').is(":visible")) {
                	get_class_grid(false);
                }

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });  
    }  else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();       
    }            
}

function get_class_image(class_id) {  

    let querydata = {class_id: class_id};

    //resets related to class images
    $(mc+' .class_image_id').text('');
    $(mc+' .class_img_buttons').addClass('noshow');
    $(mc+' .image_upload_div .display_img').attr('src','/images/avatar.png').hide();
    $(mc+' .class_img_upload_options').removeClass('noshow');

    $.ajax({
        type: 'GET',
        url: '/api/getImages',
        data: querydata,
        dataType: 'JSON'
    }).done(function( response ) {

        if (response.success != undefined) {

            $('#loader-wrapper').hide();

            let res = response.success;

            if (res.data[0]) {
                $(mc+' .image_upload_div .display_img').attr('src', 'data:image/png;base64,'+res.data[0].image_data).show();

                $(mc+' .class_image_id').text(res.data[0].image_id);
                $(mc+' .class_img_buttons').removeClass('noshow');
                $(mc+' .class_img_upload_options').addClass('noshow');;
            }

        } else if (response.redirect != undefined) {
            mini_login_wizard(response.redirect); //session timeout case
        } else {    
            set_side_error(response.error.join("<br>"));
            $('#loader-wrapper').hide();
        }

    }).fail( function(xhr, textStatus, errorThrown) {
        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
        $('#loader-wrapper').hide();
    });    
}

function delete_class_image(image_id) {
    $('#loader-wrapper').show();

    let class_id = $(mc+' .class_class_id').val();
    
    let errors = [];
    //validations

    if (errors.length == 0) {
        $.ajax({
            type: 'POST',
            url: '/api/saveImage',
            data: {image_id: image_id, class_id: class_id, action: 'delete'},
            dataType: 'JSON'
        }).done(async function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

                get_class_image(class_id);

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });  
    }  else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();
    }    
}

function get_all_classes() {

    //resets
    $('#loader-wrapper').show();

	if (USE_EVENTS_MOCKS) {
		$('#loader-wrapper').hide();
		getClasssResults({ data: get_mock_events_classes_data() });
		requestAnimationFrame(run_events_intro_animation);
		return;
	}

	let data = {location_id: $('#location_id').val(), show_archive: true};

    $.ajax({
        type: 'GET',
        url: '/api/getClasss',
        data: data,
        dataType: 'JSON'
    }).done(function( response ) {

        if (response.success != undefined) {
            
            $('#loader-wrapper').hide();
            getClasssResults(response.success);
            requestAnimationFrame(run_events_intro_animation);

        } else if (response.redirect != undefined) {
            mini_login_wizard(response.redirect); //session timeout case
        } else {    
            set_side_error(response.error.join("<br>"));
            $('#loader-wrapper').hide();           
        }

    }).fail( function(xhr, textStatus, errorThrown) {
        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
        $('#loader-wrapper').hide();
    }); 
}

