async function get_class_registers({ class_id='', level_type='', term_id='', schedule_id='', term_changed=false, no_reset=false } = {}) {

    $('#loader-wrapper').show();

    //grab inputs before reset
    if ($(mc).hasClass('modal-open') && ($(mc+' .reg_class_id').val() > 0)) {
        class_id = $(mc+' .reg_class_id').val();
        level_type = $(mc+' .reg_level_type').val();
        term_id = $(mc+' .reg_term_id').val();
        if (!term_changed) { //this check is to ensure new term_id is not sent with old schedule_id
            schedule_id = $(mc+' .reg_schedule_id_li:not(.noshow) .reg_schedule_id').val();
        }
    }

    if (!no_reset) {
    	$(mc+' .class_enrolments_tab').html($('#master_class_view .class_enrolments_tab').html()); //reset	
    } else {
    	$(mc+' .sched_items').remove(); //schedule specific items e.g. comments
    }
    
    let class_enrolment_titles = JSON.parse($('#class_enrolment_titles').text());

    let register_mode = '';
    if (level_type == 0) {
        register_mode = 'class';
    } else if (level_type == 1) {
        register_mode = 'program';
    } else if (level_type == 6) {
        register_mode = 'schedule';
    } else if (level_type == 4) {
        register_mode = 'competition';
    }

    if (class_id) {
        $.ajax({
            type: 'GET',
            url: '/api/getRegisters',
            data: {class_id: class_id, term_id: term_id, schedule_id: schedule_id, register_mode: register_mode},
            dataType: 'JSON'
        }).done(function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

                let res = response.success;

                //class info
                $(mc+' .reg_class_id').val(res.class.class_id);
                $(mc+' .reg_level_type').val(res.class.level_type);
                $(mc+' .reg_capacity').val(res.class.capacity);

                //term info
                let options_str_t = '';
                for (let i = 0; i < res.terms.length; i++) {
                    options_str_t += '<option value="'+res.terms[i].term_id+'">'+res.terms[i].term_name+'</option>'; //from_schedule not required
                }
                $(mc+' .reg_term_id').html(options_str_t);

                if (term_id) {
                    $(mc+' .reg_term_id').val(term_id);
                } else {
                    $(mc+' .reg_term_id').val(res.class.term_id);
                }

                if (register_mode == 'competition') {
                    $(mc+' .reg_term_id').prop('disabled', true);
                }

                //adjust chevrons
                if (true) {
                    let show_next = false;
                    let show_prev = false;
                    let currentIndex = $(mc+' .reg_term_id').prop('selectedIndex');

                    $(mc+' .reg_term_id option').each(function(index) {
                        let from_schedule = $(this).prop('dataset').intrac_from_schedule;

                        if (index > currentIndex) {
                            show_next = true;
                        }
                        
                        if (index < currentIndex) {
                            show_prev = true;
                        }
                    });
                    if (show_next) {
                        $(mc+' .reg_term_next').show();
                    } else {
                        $(mc+' .reg_term_next').hide();
                    }

                    if (show_prev) {
                        $(mc+' .reg_term_prev').show();
                    } else {
                        $(mc+' .reg_term_prev').hide();
                    }
                }

                //schedule info
                if (register_mode == 'schedule') {
                    $(mc+' .reg_schedule_id_li').removeClass('noshow');

                    let options_str_s = '';
                    for (let i = 0; i < res.schedules.length; i++) {
                        let s = res.schedules[i];
                        let schedule_name = convert_date(s.schedule_start, 'ddd D MMM YYYY')+' '+dayjs(s.schedule_start).format('h:mma')+'-'+dayjs(s.schedule_finish).format('h:mma');
                        if (s.usernames.split(',')[0]) {
                            schedule_name += ' ('+s.usernames.split(',')[0]+')';
                        }

                        options_str_s += '<option value="'+s.schedule_id+'">'+schedule_name+'</option>';
                    }
                    $(mc+' .reg_schedule_id').html(options_str_s);

                    $(mc+' .reg_schedule_id').val(res.schedules.filter(item => item.selected_schedule)[0].schedule_id);

                    //adjust chevrons
                    let show_next = false;
                    let show_prev = false;
                    let currentIndex = $(mc+' .reg_schedule_id').prop('selectedIndex');

                    $(mc+' .reg_schedule_id option').each(function(index) {
                        let from_schedule = $(this).prop('dataset').intrac_from_schedule;

                        if (index > currentIndex) {
                            show_next = true;
                        }
                        
                        if (index < currentIndex) {
                            show_prev = true;
                        }
                    });
                    if (show_next) {
                        $(mc+' .reg_schedule_next').show();
                    } else {
                        $(mc+' .reg_schedule_next').hide();
                    }

                    if (show_prev) {
                        $(mc+' .reg_schedule_prev').show();
                    } else {
                        $(mc+' .reg_schedule_prev').hide();
                    }
                }

                //data
                let data = res.data;

                let html_str = '';

                //prepare data_map
                let data_map = [];

                if (register_mode == 'class') {
                    data_map.push({
                        header: res.class.class_name,
                        ids: class_id+'~0~0~0~0',
                        data: data
                    });
                }

                if (register_mode == 'program') {
                    for (let i = 0; i < res.programs.length; i++) {
                        let p = res.programs[i];
                        let program_name = p.day.substring(1)+' '+convert_time(p.program_start,'h:mma')+'-'+convert_time(p.program_finish,'h:mma');
                        if (p.usernames.split(',')[0]) {
                            program_name += ' ('+p.usernames.split(',')[0]+')';
                        }                       
                        data_map.push({
                            header: program_name,
                            sub_header: p.space_names.split(',')[0] || '',
                            ids: p.class_id+'~'+p.program_id+'~0~0~0',
                            data: data.filter(item => item.program_id == p.program_id),
                            cur_term: (p.term_id == res.class.term_id) ? true : false
                        });
                    }
                }

                if (register_mode == 'schedule') {
                    let s = res.schedules.filter(item => item.selected_schedule)[0];

                    if (s) {
                        if (s.schedule_comment) {
                            $(mc+' .reg_hdr_ul').append('<li class="sched_items"><span>Comment:</span>'+s.schedule_comment+'</li>');
                        }

                        let schedule_name = $(mc+' .reg_schedule_id option[value="'+s.schedule_id+'"]').text(); //should be same as $(mc+' .reg_schedule_id option:selected').text();
                        data_map.push({
                            header: schedule_name,
                            ids: s.class_id+'~'+s.program_id+'~'+s.schedule_id+'~0~0',
                            data: data,
                            addons: res.addons
                        });                                                  
                    }
                }

                if (register_mode == 'competition') {
                    for (let i = 0; i < res.teams.length; i++) {
                        let t = res.teams[i];
                        let team_name = (t.pool ? t.pool+' ' : '')+t.team_name;
                        data_map.push({
                            header: team_name,
                            ids: t.class_id+'~0~0~'+t.team_id+'~0',
                            data: data.filter(item => item.team_id == t.team_id),
                            pool: t.pool,
                            captain_id: t.captain_id
                        });                           
                    }
                }

                let empty_div = '<div class="empty_div noshow"></div>'; //pointer for alter_reg and prog_switch div blocks

                //convert data_map to html
                for (let j = 0; j < data_map.length; j++) {

                    //header
                    let header_str = data_map[j].header ? (data_map[j].header+(data_map[j].sub_header ? '<br>'+data_map[j].sub_header : '')) : '';

                    html_str += '<div class="table-wrapper toggle_div"><table class="table table_th_top table_td_top se_div class_reg_hdr">\
                                    <thead'+(!header_str ? ' class="noshow"' : '')+'>\
                                        <tr>\
                                            <th class="w-50p">'+header_str+empty_div+'</th>\
                                            <th class="w-25p"><div class="ids noshow">'+data_map[j].ids+'</div></th>\
                                            <th class="relative align-right">menu_btn_str_'+j+'</th>\
                                        </tr>\
                                    </thead>\
                                    <tbody>'

                    //data
                    for (let i = 0; i < data_map[j].data.length; i++) {
                        let d = data_map[j].data[i];
                        
                        let age = (getAge(d.dob)) ? ' ('+getAge(d.dob)+')' : '';
                        if (d.details && d.details.schoolyear) {
                            age = ' ('+d.details.schoolyear+')';
                        }

                        let medical = (d.medical && !d.medical_reused) ? ' *' : '';

                        let comment = (d.customer_comments) ? ' ?' : '';

                        let captain = ((register_mode == 'competition') && (d.customer_id == data_map[j].captain_id)) ? ' (C)' : '';

                        let qty = (d.quantity > 0) ? ' - Qty: '+d.quantity : '';

                        let absent = (d.absent) ? ' <b>Absent</b>' : '';

                        html_str += '<tr class="class_reg_item">\
                                        <td class="w-50p"><span class="register_id noshow">'+d.register_id+'</span><span class="customer_id noshow">'+d.customer_id+'</span><span class="parent_id noshow">'+d.parent_id+'</span><span class="receipt_id noshow">'+d.receipt_id+'</span>'+(i+1)+'. '+'<a href="#" class="view_customer">'+d.first_name+' '+d.last_name+age+captain+medical+comment+'</a>'+qty+empty_div+'</td>\
                                        <td class="'+(d.receipt_type == 1 ? 'flex_gap' : '')+'">'+(d.receipt_type == 2 ? '<span class="paid">Paid</span>' : (d.receipt_type == 1 ? '<a href="#" class="btn-edit view_account">View Account</a>' : ''))+absent+'</td>\
                                        <td><ul>\
                                                '+(d.show_actions['alter'] && ($(mc+' .class_status').val() > 0) ? '<li><a href="#" class="btn-edit class_reg_alter">Alter</a></li>' : '')+'\
                                                '+(d.show_actions['delete'] && ($(mc+' .class_status').val() > 0) ? '<li><a href="#" class="btn-edit class_reg_delete">Delete</a></li>' : '')+'\
                                            </ul>\
                                            <span class="se_det noshow">'+(d.parent_id > 0 ? d.parent_id : d.customer_id)+'~'+d.first_name+' '+d.last_name+'~'+d.phone+'~'+d.email+'~'+d.altemail+'</span>\
                                        </td>\
                                    </tr>';
                    }

                    

                    //count
                    let qtys = data_map[j].data.reduce((sum, item) => sum + item.quantity, 0); //sum of all quantity
                    let regs = qtys > 0 ? qtys : data_map[j].data.length;
                    let absents = data_map[j].data.filter(item => item.absent).length;

                    let acts_str = '';
                    
                    let switch_prog_str = ((register_mode == 'program') && data_map[j].cur_term && $('#is_admin').val() && ($(mc+' .class_status').val() > 0)) ? '<li><a href="#" class="menu_item class_reg_ps">Switch Program</a></li>' : '';
                    acts_str += switch_prog_str;

                    if (($(mc+' .reg_capacity').val() > 0) && ((regs-absents) >= $(mc+' .reg_capacity').val()) && (['class','program','schedule'].includes(register_mode))) {
                        html_str += '<tr class="white_tr">\
                                        <td colspan="3"><b>Capacity Reached</b></td>\
                                    </tr>';
                    	
                    	acts_str += '<li><a href="#" class="menu_item sms_lnk">SMS</a></li>'; 
                    	acts_str += '<li><a href="#" class="menu_item email_lnk">Email</a></li>'; 

                    } else if ($(mc+' .class_status').val() > 0) {

                        //register deeplink
                        if ((register_mode == 'competition') && (data_map[j].header.replace(data_map[j].pool,'').trim() == 'Bye')) {
                            //don't show register link
                        } else {
                        	let reg_str_ = (register_mode == 'competition') ? 'Add player' : toTitleCase(class_enrolment_titles.verb || 'enrol')+' a new customer';
                            acts_str += '<li><a href="#" data-intrac="'+data_map[j].ids+'" class="menu_item reg_register_customer">'+reg_str_+'</a></li>';
                        }

                        //reserve deeplink
                        if ((register_mode == 'program') || (register_mode == 'schedule'))  {
                            acts_str += '<li><a href="#" data-intrac="'+data_map[j].ids+'" class="menu_item reg_reserve">Reserve a place</a></li>'; 
                        }

                        //sms & email
                        if (data_map[j].data.length) {
                        	acts_str += '<li><a href="#" class="menu_item sms_lnk">SMS</a></li>'; 
                        	acts_str += '<li><a href="#" class="menu_item email_lnk">Email</a></li>'; 
                        }
                    }

                    if (acts_str) {
                        acts_str = '<button type="button" class="size-11 p-1 bg-natural-white rounded-full block_toggle" data-toggle_target="enrol_actions_menu">\
                                        <div class="flex justify-center items-center rounded-full bg-white size-full">\
                                            <img class="size-[18px]" src="images/icons/more-horizontal.svg" alt="">\
                                        </div>\
                                    </button>\
	                                <div class="actions_menu enrol_actions_menu dropdown-menu w-[188px] p-1 z-10 hidden abs_inset">\
                                        <ul class="text-sm text-main">'+acts_str+'</ul>\
                                    </div>';
                    }
                    html_str = html_str.replace('menu_btn_str_'+j, acts_str);

                    //close table
                    html_str += '</tbody></table></div>';

                    //addons - shows in schedule_mode only (for programs - today's view will be schedule_mode), add as a separate table
                    if (data_map[j].addons && data_map[j].addons.length) {
                        html_str += '<div class="table-wrapper"><table class="table">\
                                        <thead>\
                                            <tr>\
                                                <th colspan="3">Addons Purchased</th>\
                                            </tr>\
                                        </thead>\
                                        <tbody>'                         
                        
                        for (let i = 0; i < data_map[j].addons.length; i++) {
                            let d = data_map[j].addons[i];
                            /*note: d.customer_id here is purchase.customer_id*/
                            html_str += '<tr class="class_addon_item">\
                                            <td><span class="purchase_id noshow">'+d.purchase_id+'</span><span class="customer_id noshow">'+d.customer_id+'</span><span class="receipt_id noshow">'+d.receipt_id+'</span>'+(i+1)+'. '+d.first_name+' '+d.last_name+'</td>\
                                            <td>'+(d.quantity > 1 ? d.quantity+' x ' : '')+d.category+' '+d.product_name+'</td>\
                                            <td>'+(d.receipt_type == 2 ? '<span class="paid">Paid</span>' : (d.receipt_type == 1 ? '<a href="#" class="btn-edit view_account">View Account</a>' : ''))+'</td>\
                                        </tr>'; 
                        }

                        //close table
                        html_str += '</tbody></table></div>';
                    }
                    
                }

                //sms & email at top level
                if ((html_str.includes('se_det')) && ((register_mode == 'program')  || (register_mode == 'competition'))) {
                	$(mc+' .sms_lnk').removeClass('noshow');
                	$(mc+' .email_lnk').removeClass('noshow');
                } else {
                	$(mc+' .sms_lnk').remove();
                	$(mc+' .email_lnk').remove();                	
                }

                $(mc+' .reg_list').html(html_str);

                if (register_mode == 'competition') {
                    $(mc+' .reg_view_class_payments').removeClass('noshow');
                } else {
                	$(mc+' .reg_view_class_payments').remove();
                }

                if (((register_mode == 'class') || (register_mode == 'program')) && (dates_diff(res.class.term_finish, dayjs().format('YYYY-MM-DD')) >= 0)) {
                	$(mc+' .recalc_class_amounts').removeClass('noshow');
                } else {
                	$(mc+' .recalc_class_amounts').remove();
                }

                //archived class
                if ($(mc+' .class_status').val() === '0') {
                	$(mc+' .btn-default').remove();
	                $(mc+' .btn-edit').remove();
                }

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });
    } else {
        $('#loader-wrapper').hide();
    }
}

function set_prog_switch_register(el) {
    $('#loader-wrapper').show();

    $(mc+' .ps_div').remove();
    $(mc+' .alter_div').remove();
    $(mc2+' .alter_div').remove();

    let class_id = $(el).find('.ids').text().split('~')[0];
    let program_id = $(el).find('.ids').text().split('~')[1];

    let errors = [];
    //validations

    if (errors.length == 0) {
        $.ajax({
            type: 'GET',
            url: '/api/getClassPrograms',
            data: {class_id: class_id, program_id: program_id},
            dataType: 'JSON'
        }).done(async function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();
                
                let d = response.success.data[0];
                if (d) {
                    $(el).find('th:first div').after('<div class="ps_div margin_top_md margin_btm_sm">'+$(mc+' .reg_ps_view').html()+'</div>');

                    if (d.alters.length) {
                        $(el).find('.reg_ps_class_id_div').show();

                        let ps_options_str = '';
                        for (let i = 0; i < d.alters.length; i++) {
                            let a = d.alters[i];
                            ps_options_str += '<option value="'+a.class_id+'">'+(response.success.class.location_id != a.location_id ? a.location_name+' ' : '')+a.class_name+'</option>';
                        }
                        $(el).find('.reg_ps_class_id').html(ps_options_str);

                    } else {
                        $(el).find('.reg_ps_noids').show();
                        $(el).find('.regbtn_prog_switch').hide();
                    }

                } else {
                    set_side_error('Unable to retrieve details'); //this should never show
                }

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });  
    }  else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();
    }    
}

function program_switch_register(class_id, cur_program_id) {
    $('#loader-wrapper').show();

    let location_id = $('#location_id').val();

    let errors = [];
    //validations
    if (!class_id) {
        errors.push('You must choose an option to proceed further');
    }

    if (errors.length == 0) {
        $.ajax({
            type: 'POST',
            url: '/api/updateRegister',
            data: {class_id: class_id, cur_program_id: cur_program_id, location_id: location_id, action: 'program_switch'},
            dataType: 'JSON'
        }).done(async function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();
                get_class_registers();

                if (response.info.length) {
                    set_side_error(response.info.join("<br>"), 'amber');
                }

                //refresh classes
                if ($('#classes_main').is(":visible")) {
                	get_api('getClasss');
                }

                //refresh grid
                if ($('#classes').is(":visible")) {
                	get_class_grid(false);
                }

                //refresh grid
                if ($('#rosters').is(":visible")) {
                	get_roster_grid(false);
                }

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });  
    }  else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();
    }    
}


async function set_alter_register(el, creg=false) {
    $('#loader-wrapper').show();

    $(mc+' .alter_div').remove();
    $(mc2+' .alter_div').remove();
    $(mc+' .ps_div').remove();  

    let class_id = null;
    let register_mode = '';

    //populate class_id and register_mode
    if (creg) {
        let ids = $(el).find('.register_details').text().split('~');
        class_id = ids[0];
        let program_id = ids[1];
        let schedule_id = ids[2];

        if (schedule_id > 0) {
            register_mode = 'schedule';
        } else if (program_id > 0) {
            register_mode = 'program';
        } else {
            register_mode = 'class';
        }
    } else {
        class_id = $(mc+' .reg_class_id').val();
        let level_type = $(mc+' .reg_level_type').val();

        if (level_type == 0) {
            register_mode = 'class';
        } else if (level_type == 1) {
            register_mode = 'program';
        } else if (level_type == 6) {
            register_mode = 'schedule';
        }
    }

    let register_id = $(el).find('.register_id').text();

    let errors = [];
    //validations

    if (errors.length == 0) {
        $.ajax({
            type: 'GET',
            url: '/api/getRegisters',
            data: {class_id: class_id, register_mode: register_mode, register_id: register_id},
            dataType: 'JSON'
        }).done(async function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();
                
                let d = response.success.data[0];
                if (d) {

                	let alt_html = $('#master_class_view .reg_alter_view').html(); //using master_class_view i/o mc here as creg will be in mc2 in customer modal
                	if (creg) {
                		alt_html = alt_html.replace('regbtn_alter', 'custregisterbtn_alter');
                		alt_html = alt_html.replace('static_form margin_top_md', ''); //customer alter will act as a default form/grid model
                	}

                    $(el).find('.empty_div:first').after('<div class="alter_div flex_new_row">'+alt_html+'</div>'); 

                    if (($(el).find('.reg_alter_quantity').is(":visible")) && (d.quantity > 0)) {
                        $(el).find('.reg_alter_quantity').val(d.quantity);
                        if ($('#is_admin').val()) {
                            $(el).find('.reg_alter_quantity').prop('disabled', false); //allowed only for admins/admin privileges
                        }
                    } else {
                        $(el).find('.reg_alter_quantity_div').hide();
                    }
                    
                    if (d.amount !== null) {
                        $(el).find('.reg_alter_amount_div').show();
                        $(el).find('.reg_alter_amount').val(d.amount);
                        if (d.receipt_type == 0 || d.receipt_type == 1) {
                            if ($('#is_admin').val()) {
                                $(el).find('.reg_alter_amount').prop('disabled', false); //allowed only for admins/admin privileges
                            }
                        } else if (d.receipt_type == 2) {
                            $(el).find('.reg_alter_amount_status').text('Status: Paid');
                        }
                    }

                    if (d.alters.length) {
                        $(el).find('.reg_alter_id_div').show();

                        let alter_options_str = '<option value="">No Change</option>';
                        for (let i = 0; i < d.alters.length; i++) {
                            let a = d.alters[i];
                            if (register_mode == 'class') {
                                alter_options_str += '<option value="'+a.class_id+'">'+(response.success.class.location_id != a.location_id ? a.location_name+' ' : '')+a.class_name+'</option>';
                            } else if (register_mode == 'program') {
                                let user_str = a.username;
                                let space_str = a.space_name;
                                let prog_str = a.day.substring(1)+' '+convert_time(a.program_start,'h:mma')+'-'+convert_time(a.program_finish,'h:mma')+(user_str ? ' '+user_str : '')+(space_str ? ' '+space_str : '');

                                alter_options_str += '<option value="'+a.class_id+'~'+a.program_id+'">'+(response.success.class.location_id != a.location_id ? a.location_name+' ' : '')+(response.success.class.class_name != a.class_name ? a.class_name+' ' : '')+prog_str+'</option>';;    
                            }
                        }
                        $(el).find('.reg_alter_id').html(alter_options_str);

                    } else {
                        $(el).find('.reg_alter_noids').show();
                        $(el).find('.regbtn_alter').hide();
                    }

                } else {
                    set_side_error('Unable to retrieve details'); //this should never show
                }

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });  
    }  else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();
    }    
}

function alter_register(el, creg=false) {
    $('#loader-wrapper').show();

    let register_id = $(el).find('.register_id').text();
    let customer_id = (creg) ? $(el).closest('.cregister_cust_row').find('.cregister_customer_id').val() : $(el).find('.customer_id').text();

    let location_id = $('#location_id').val();

    let data = {register_id: register_id, customer_id: customer_id, location_id: location_id, action: 'alter'};

    //populate alter data
    let alt_el = $(el).find('.alter_div');

    if ($(alt_el).find('.reg_alter_quantity').is(':visible'))  {
        data.quantity = $(alt_el).find('.reg_alter_quantity').val();
    } else {
        data.quantity = 0;
    }

    if ($(alt_el).find('.reg_alter_amount').is(':visible')) {
        data.cost = $(alt_el).find('.reg_alter_amount').val();
    } else {
        data.cost = 0;
    }

    if ($(alt_el).find('.reg_alter_id').is(':visible')) {
        let ids = $(alt_el).find('.reg_alter_id').val().split('~');
        data.class_id = ids[0];
        data.program_id = (ids.length > 1) ? ids[1] : '';
    } else {
        data.class_id = '';
        data.program_id = '';
    }

    let errors = [];
    //validations

    if (!validator.isFloat(data.cost,{min: 0})) {
    	errors.push('Invalid amount')
    }

    if (errors.length == 0) {
        $.ajax({
            type: 'POST',
            url: '/api/updateRegister',
            data: data,
            dataType: 'JSON'
        }).done(async function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();
                if (creg) {
                	set_side_error(toTitleCase(JSON.parse($('#class_enrolment_titles').text()).title || 'enrolment')+' updated successfully', 'green');

                    viewCustomer($(mc2+' .cust_edit_tab .cust_customer_id').val(), 'cust_registers');

	                //refresh class enrolments
	                if (($(mc).hasClass('modal-open')) && $(mc+' .tl_class_enrolments').hasClass('active')) {
	                	get_class_registers({no_reset: true}); //no_reset of html to retain scroll position
	                }

	                //refresh class attendance
	                if (($(mc).hasClass('modal-open')) && $(mc+' .tl_attendance').hasClass('active')) {
	                	get_class_attendance();
	                }

                } else {
                    get_class_registers();

	                //refresh classes
	                if ($('#classes_main').is(":visible")) {
	                	get_api('getClasss');
	                }

	                //refresh grid
	                if ($('#classes').is(":visible")) {
	                	get_class_grid(false);
	                }
                }

                if (response.info.length) {
                    set_side_error(response.info.join("<br>"), 'amber');
                }

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });  
    }  else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();
    }    
}

