function get_class_schedules(class_id,term_id='') {

	return new Promise((resolve, reject) => {

	    if (!class_id) {
	        class_id = $(mc+' .class_class_id').val();
	    }

	    $('#loader-wrapper').show();

	    $(mc+' .schedules_tab').html($('#master_class_view .schedules_tab').html()); //reset
	    $(mc+' .programs_tab').html(''); //reset to avoid ps_user_id ps_space_id interference

	    //archived class
	    if ($(mc+' .class_status').val() === '0') {
			$(mc+' .btn-default').remove();
		    $(mc+' .btn-edit').remove();
	    }

	    //have to do these here than in master
	    //set each ps_space_id_ sel with a value per index, so that selects don't look all blanks
	    set_ps_space_id_defaults();	

	    if (class_id) {
	        $.ajax({
	            type: 'GET',
	            url: '/api/getClassSchedules',
	            data: {class_id: class_id, term_id: term_id},
	            dataType: 'JSON'
	        }).done(function( response ) {

	            if (response.success != undefined) {

	                $('#loader-wrapper').hide();

	                let res = response.success;

	                //data
	                let data = res.data;

	                let html_str = '';

	                //term info
	                let options_str_t = '';
	                for (let i = 0; i < res.terms.length; i++) {
	                    options_str_t += '<option value="'+res.terms[i].term_id+'" data-intrac_from_schedule="'+res.terms[i].from_schedule+'">'+res.terms[i].term_name+'</option>';
	                }
	                $(mc+' .sched_term_id').append(options_str_t);

	                if (res.class.level_type != 4) {
	                	$(mc+' .sched_term_id_ul').removeClass('noshow');
	                }

	                //class info
	                $(mc+' .sched_class_id').val(res.class.class_id);
	                
	                if (term_id) {
	                    $(mc+' .sched_term_id').val(term_id);
	                } else {
	                    $(mc+' .sched_term_id').val(res.class.term_id);
	                }

	                $(mc+' .sched_term_start').val(res.terms.filter(item => item.term_id == $(mc+' .sched_term_id').val())[0]?.term_start);
	                $(mc+' .sched_term_finish').val(res.terms.filter(item => item.term_id == $(mc+' .sched_term_id').val())[0]?.term_finish);

	                //adjust chevrons
	                let show_next = false;
	                let show_prev = false;
	                let currentIndex = $(mc+' .sched_term_id').prop('selectedIndex');

	                $(mc+' .sched_term_id option').each(function(index) {
	                    let from_schedule = $(this).prop('dataset').intrac_from_schedule;

	                    if (index > currentIndex && from_schedule == 1) {
	                        show_next = true;
	                    }
	                    
	                    if (index < currentIndex && from_schedule == 1) {
	                        show_prev = true;
	                    }
	                });
	                if (show_next) {
	                    $(mc+' .sched_term_next').show();
	                } else {
	                    $(mc+' .sched_term_next').hide();
	                }

	                if (show_prev) {
	                    $(mc+' .sched_term_prev').show();
	                } else {
	                    $(mc+' .sched_term_prev').hide();
	                }

	                //program info
	                $(mc+' .sched_program_id option').not("[value='0']").remove();
	                let options_str_p = '';
	                for (let i = 0; i < res.programs.length; i++) {
	                    let p = res.programs[i];
	                    let program_name = p.day.substring(1)+' '+convert_time(p.program_start,'h:mma')+'-'+convert_time(p.program_finish,'h:mma');
	                    if (p.usernames.split(',')[0]) {
	                        program_name += ' ('+p.usernames.split(',')[0]+')';
	                    }
	                    options_str_p += '<option value="'+p.program_id+'">'+program_name+'</option>';
	                }
	                $(mc+' .sched_program_id').append(options_str_p)

	                //header
	                html_str += '<div class="table-wrapper"><table class="table">\
	                                <thead>\
	                                    <tr>\
	                                        <th>Date</th>\
	                                        <th>Program</th>\
	                                        <th>Instructor</th>\
	                                        '+($(mc+' .ps_space_id option').length > 1 ? '<th>'+toTitleCase($('#space_title').val())+'</th>' : '')+'\
	                                        '+(res.class.level_type != 4 ? '<th>Size</th>' : '')+'\
	                                        <th>Actions</th>\
	                                    </tr>\
	                                </thead>\
	                                <tbody>';

	                //data            
	                for (let i = 0; i < data.length; i++) {

	                    let usernames = data[i].usernames.split(',');
	                    let user_str = (usernames.length>1) ? (usernames[0] ? usernames[0]+'*<br>' : '')+usernames.slice(1).join('<br>') : (usernames[0] || '');

	                    let space_names = data[i].space_names.split(',');
	                    let space_str = (space_names.length>1) ? space_names.join('<br>') : (space_names[0] || '');

	                    html_str += '<tr class="class_sched_item">\
	                                    <td><span class="class_id noshow">'+data[i].class_id+'</span><span class="schedule_id noshow">'+data[i].schedule_id+'</span>'+convert_date(data[i].schedule_start, 'ddd D MMM YYYY')+' '+dayjs(data[i].schedule_start).format('h:mma')+'-'+dayjs(data[i].schedule_finish).format('h:mma')+'</td>\
	                                    <td>'+(data[i].program_id ? 'Yes' : 'No')+'</td>\
	                                    <td>'+user_str+'</td>\
	                                    '+($(mc+' .ps_space_id option').length > 1 ? '<td>'+space_str+'</td>' : '')+'\
	                                    '+(res.class.level_type != 4 ? '<td>'+(data[i].enrolments-data[i].absents)+'</td>':'')+'\
	                                    <td><ul>\
	                                            '+($('#is_admin').val() && ($(mc+' .class_status').val() > 0) ? '<li><a href="#" class="btn-edit edit_form class_sched_update" data-intrac="'+data[i].schedule_id+'">Edit</a></li>' : '')+'\
	                                            '+($('#is_admin').val() && ($(mc+' .class_status').val() > 0) && !data[i].enrolments_sched && !data[i].presents ? '<li><a href="#" class="btn-edit class_sched_delete">Delete</a></li>' : '')+'\
	                                        </ul></td>\
	                                </tr>';

	                                //removed && !data[i].enrolments from class_sched_delete
	                }

					//close table
	                html_str += '</tbody></table></div>';

	                $(mc+' .sched_list').html(html_str);

	            } else if (response.redirect != undefined) {
	                mini_login_wizard(response.redirect); //session timeout case
	            } else {    
	                set_side_error(response.error.join("<br>"));
	                $('#loader-wrapper').hide();
	            }
	            resolve();

	        }).fail( function(xhr, textStatus, errorThrown) {
	            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
	            $('#loader-wrapper').hide();
	            resolve();
	        });
	    } else {
	        $('#loader-wrapper').hide();
	        resolve();
	    }
    });
}

function update_class_schedule(class_id, schedule_id) {
    let term_id = $(mc+' .sched_term_id').val();

    /* fetch from api directly*/
    $('#loader-wrapper').show();

    $.ajax({
        type: 'GET',
        url: '/api/getClassSchedules',
        data: {class_id: class_id, term_id: term_id, schedule_id: schedule_id},
        dataType: 'JSON'
    }).done(function( response ) {

        if (response.success != undefined) {

            if (response.success.data.length) {
                let res = response.success;
                let itemobj = res.data[0]; //override itemobj

                $(mc+' .sched_class_id').val(itemobj.class_id);
                $(mc+' .sched_schedule_id').val(itemobj.schedule_id);
                $(mc+' .sched_program_id').val(itemobj.program_id).prop('disabled', true);
                $(mc+' .sched_date').val(convert_date(dayjs(itemobj.schedule_start).format('YYYY-MM-DD')));
                $(mc+' .sched_schedule_start').val(dayjs(itemobj.schedule_start).format('HH:mm'));
                $(mc+' .sched_schedule_finish').val(dayjs(itemobj.schedule_finish).format('HH:mm'));
                
                if (itemobj.schedule_comment == 'Full') {
                    if ($(mc+' .sched_schedule_full').is(":visible")) {
                        $(mc+' .sched_schedule_full').prop('checked', true);    
                    }
                } else {
                    $(mc+' .sched_schedule_comment').val(itemobj.schedule_comment);    
                }

                $(mc+' .sched_attendees').val(itemobj.attendees);

                let user_ids = itemobj.user_ids.split(',');
                let user_ids_unique = [...new Set(user_ids)];
                let space_ids = itemobj.space_ids.split(',');

                //spaces
                if (space_ids.length == 1) {
                    $(mc+' .ps_space_id').val(space_ids[0]);
                } else {
                    $(mc+' .ps_show_spaces_multiple').click();

                    for (let i = 0; i < space_ids.length; i++) {
                        let el = $(mc+' .ps_space_id_').eq(i);
                        $(el).val(space_ids[i]);
                        $(el).closest('tr').find('.ps_su_sel').prop('checked', true);
                    }
                }

                //users
                if (user_ids_unique.length == 1) {
                    $(mc+' .ps_user_id').val(user_ids_unique[0]);
                } else {
                    $(mc+' .ps_show_users_multiple').click();

                    for (let i = 0; i < user_ids.length; i++) { //user_ids.length will be the same as space_ids.length
                        let el = $(mc+' .ps_user_id_').eq(i);
                        $(el).val(user_ids[i]);
                        $(el).closest('tr').find('.ps_su_sel').prop('checked', true);
                    }
                }

                //avails
                let html_str_a = '';
                if (res.avails && res.avails.length) {
                    html_str_a += '<div class="margin_top_md margin_bottom_sm"><b>Staff Availability on '+convert_date_time(res.avails[0].avail_start, 'D MMM YYYY')+'</b><br><br>';
                    for (let i = 0; i < res.avails.length; i++) {
                        html_str_a += res.avails[i].username+' '+convert_date_time(res.avails[i].avail_start,'h:mma')+'-'+convert_date_time(res.avails[i].avail_finish,'h:mma')+'<br>';
                    }
                    html_str_a += '</div>';
                }
                $(mc+' .sched_avails_list').html(html_str_a);
            }
            
            $('#loader-wrapper').hide();

        } else if (response.redirect != undefined) {
            mini_login_wizard(response.redirect); //session timeout case
        } else {    
            set_side_error(response.error.join("<br>"));
            $('#loader-wrapper').hide();          
        }

    }).fail( function(xhr, textStatus, errorThrown) {
        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
        $('#loader-wrapper').hide();
    }); 
}

function saveClassSchedule() {

    let schedule_comment = $(mc+' .sched_schedule_comment').val();

    if ($(mc+' .sched_schedule_full').is(":checked")) {
        schedule_comment = 'Full'; //overwrite
    }

    //prepare the data
    let data ={
        class_id: $(mc+' .sched_class_id').val(),
        schedule_id: $(mc+' .sched_schedule_id').val(),
        location_id: $('#location_id').val(),
        term_id: $(mc+' .sched_term_id').val(),
        program_id: $(mc+' .sched_program_id').val(),
        date: parse_date($(mc+' .sched_date').val()),
        schedule_start: parse_time($(mc+' .sched_schedule_start').val()),
        schedule_finish: parse_time($(mc+' .sched_schedule_finish').val()),
        schedule_bookings: [],
        schedule_comment: schedule_comment,
        attendees: $(mc+' .sched_attendees:visible').val() || 0,
        split_schedules: ''
    };

    //spaces and users
    //multiple spaces visible
    if ($(mc+' .ps_space_multiple_div').is(":visible")) {

        $(mc+' .ps_su_sel').each(function () {
            if (this.checked) {
                let s_id = 0;
                let u_id = 0;
                
                s_id = $(this).closest('tr').find('.ps_space_id_').val();

                //multiple users visible
                let u_el = $(this).closest('tr').find('.ps_user_id_');
                if ($(u_el).is(":visible")) {
                    u_id = $(u_el).val();
                } else { //single user, assign only to first schedule_bookings element
                    u_id = data.schedule_bookings.length ? '0' : $(mc+' .ps_user_id').val();
                }

                if (s_id || u_id) {
                    data.schedule_bookings.push({
                        space_id: s_id || '0',
                        user_id: u_id || '0'
                    });                
                }
            }
        });

        if (!data.schedule_bookings.length) {
            data.schedule_bookings.push({
                space_id: '0',
                user_id: '0'
            });        	
        }        

    } else { //single space
        data.schedule_bookings.push({
            space_id: $(mc+' .ps_space_id').val() || '0',
            user_id: $(mc+' .ps_user_id').val() || '0'
        })
    }

    if (dayjs(data.date).isBefore(dayjs($(mc+' .sched_term_start').val())) ||
        dayjs(data.date).isAfter(dayjs($(mc+' .sched_term_finish').val()))) {
            let result = confirm('Date is outside of '+$('#term_title').val()+' start and finish dates. Do you want to proceed further?');
            if (!result) {
                return false;
            }
    }

    //split bookings
    if ($(mc+' .sched_split_div').is(":visible")) {
		if ($(mc+' .sched_split_time').is(":checked") || $(mc+' .sched_split_space').is(":checked")) {
			data.split_schedules = {};

			if ($(mc+' .sched_split_time').is(":checked")) {
				data.split_schedules.time = $(mc+' .sched_split_duration').val();
			}
	    	if ($(mc+' .sched_split_space').is(":checked")) {
	    		data.split_schedules.spaces = '1';
	    	}
	    }
    }

    $('#loader-wrapper').show();

    let errors = [];
    //validations

    if (!isvalidDate(data.date)) {
        errors.push('Invalid date');
    }

    if (!isvalidTime(data.schedule_start)) {
        errors.push('Invalid start time');
    }

    if (!isvalidTime(data.schedule_finish)) {
        errors.push('Invalid finish time');
    }

    if (errors.length == 0) { //times are valid
        
        if (dayjs(data.schedule_start,'HH:mm:ss').isAfter(dayjs(data.schedule_finish,'HH:mm:ss'))) {
            errors.push("Finish time cannot be after start time");
        }
    }

    if (!validator.isInt(data.attendees.toString(),{min: 0})) {
        errors.push('Invalid attendees');
    }

    if (data.split_schedules) {
    	if (data.schedule_id > 0) {
    		errors.push('Splitting is allowed only for new bookings'); //this should never show
    	}

    	if (data.program_id > 0) {
    		errors.push('Splitting is not allowed for bookings of a program, please deselect the program and re-try');
    	}

    	if (data.split_schedules.time != undefined) {
    		if (!validator.isInt(data.split_schedules.time,{min: 5})) {
    			errors.push('Please select a valid split duration in minutes');	
    		} else if (data.split_schedules.time > times_diff(data.schedule_finish, data.schedule_start)) {
                errors.push('Split duration cannot be greater than the booking duration');
            }
    	}

        if (data.split_schedules.spaces > 0) {
            if (data.schedule_bookings.filter(item => item.user_id>0).length) {
                errors.push('Instructors cannot be selected when splitting by '+$('#space_title').val());
            }
            if (!data.schedule_bookings.filter(item => item.space_id>0).length) {
                errors.push('Please select one or more '+$('#space_title').val()+'s to split by '+$('#space_title').val());
            }                        
        }
    }


    if (errors.length == 0) {
        $.ajax({
            type: 'POST',
            url: '/api/saveClassSchedule',
            data: data,
            dataType: 'JSON'
        }).done(function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();
                get_class_schedules(data.class_id, $(mc+' .sched_term_id').val());

                //refresh grid
                if ($('#classes').is(":visible")) {
                    get_class_grid(false);
                }

                //refresh grid
                if ($('#rosters').is(":visible")) {
                    get_roster_grid(false);
                }

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });  
    }  else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();        
    }            
}

