function save_team_extras(team_id) {
    let class_id = $(mc+' .team_class_id').val();

    $('#loader-wrapper').show();

    //prepare the data
    let data ={
        team_id: team_id,
        location_id: $('#location_id').val(),
        points: $(mc+' .team_extra_points:visible').val(),
        goals: $(mc+' .team_extra_goals:visible').val(),
        extra_comment: $(mc+' .team_extra_comment:visible').val()
    };  

    let errors = [];
    //validations

    if ((!isEmpty(data.points)) && (!validator.isInt(data.points))) {
        error_string.push("Invalid points");
    }

    if ((!isEmpty(data.goals)) && (!validator.isInt(data.goals))) {
        error_string.push("Invalid goals");
    }

    if (isEmpty(data.extra_comment)) {
        errors.push('Please enter a comment and re-try');
    }

    if ((data.points == 0) && (data.goals == 0)) {
        error_string.push("You must enter the number of extra competition points and extra goals");
    }

    if (errors.length == 0) {
        $.ajax({
            type: 'POST',
            url: '/api/saveExtra',
            data: data,
            dataType: 'JSON'
        }).done(function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();
                get_class_teams();

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });  
    }  else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();       
    }            
}

