function get_class_fixtures(class_id, rawcsv='') {

    if (!class_id) {
        class_id = $(mc+' .class_class_id').val();
    }

    $('#loader-wrapper').show();

    $(mc+' .fixtures_tab').html($('#master_class_view .fixtures_tab').html()); //reset

    if (class_id) {
        $.ajax({
            type: 'GET',
            url: '/api/getClassFixtures',
            data: {class_id: class_id},
            dataType: 'JSON'
        }).done(function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

                let res = response.success;

                //data
                let data = res.data;

                let html_str = '';
                let cf_html_str = '';

                //class info
                $(mc+' .fixt_class_id').val(res.class.class_id);

                let gala_term = false;

                if (dates_diff(res.class.term_finish, res.class.term_start) < 4) {
                    gala_term = true;
                    $(mc+' .fixt_gala').prop('checked', true);
                    $(mc+' .fixt_cf_gala_div').removeClass('noshow');
                } //don't set it to false as fixtures_show_gala also controls this

                //fullfield can't be used with gala
                if ($(mc+' .fixt_cf_gala').is(":visible")) {
                    $(mc+' .fixt_cf_fullfield_div').addClass('noshow');
                }

                //header
                html_str += '<div class="table-wrapper"><table class="table table_td_top">\
                                <thead>\
                                    <tr>\
                                        <th>Date & Time</th>\
                                        <th>Space</th>\
                                        <th>User</th>\
                                        <th>Details</th>\
                                        <th>Result</th>\
                                        <th>Actions</th>\
                                    </tr>\
                                </thead>\
                                <tbody>';


                //first create rounds
                let rounds = [];
                let round_date = '';

                let round_format = gala_term ? 'YYYY-MM-DD HH:mm' : 'YYYY-MM-DD';

                for (let i = 0; i < data.length; i++) {
                    //round
                    if (convert_date_time(data[i].schedule_start,round_format) != round_date) {
                        round_date = convert_date_time(data[i].schedule_start,round_format);
                    }

                    //round about to change?
                    if ((!data[i+1]) || (convert_date_time(data[i+1].schedule_start,round_format) != round_date)) {
                        rounds.push({
                            round_date: gala_term ? round_date+':00' : round_date, //:00 for seconds in gala format
                            round_data: data.filter(item => convert_date_time(item.schedule_start,round_format) == round_date)
                        });
                    }
                }

                let empty_div = '<div class="empty_div noshow"></div>'; //pointer for fxtalter_div blocks

                for (let n = 0; n < rounds.length; n++) {

                	let which_tr = (n%2 == 0 ? ' white_tr' : ' purple_tr');

                    //data
                    for (let i = 0; i < rounds[n].round_data.length; i++) {

                        let d = rounds[n].round_data[i];

                        let result = '';
                        if ((d.result1 !== null) && (d.result2 !== null)) {
                            result = d.result1+' - '+d.result2;
                        } else if (d.result1 !== null) {
                            result = d.team2_name+' forfeit';
                        } else if (d.result2 !== null) {
                            result = d.team1_name+' forfeit';
                        }

                        let fixture = '';
                        if (d.fixture_id > 0) {
                            if (d.pool) {
                                fixture += d.pool+': ';
                            }
                            if (d.tag) {
                                fixture += d.tag+': ';
                            }                        
                            fixture += (d.team1_name || '') +' v '+ (d.team2_name || '');
                        }

                        html_str += '<tr class="class_fixt_item'+which_tr+'">\
                                        <td class="noshow"><span class="class_id noshow">'+class_id+'</span><span class="schedule_id noshow">'+d.schedule_id+'</span><span class="fixture_id noshow">'+d.fixture_id+'</span><span class="team1_name noshow">'+d.team1_name+'</span><span class="team2_name noshow">'+d.team2_name+'</span></td>\
                                        <td class="schedule_start">'+convert_date_time(d.schedule_start)+'</td>\
                                        <td class="space_name">'+d.space_names.split(',').filter(item => item).join(', ')+'</td>\
                                        <td>'+d.usernames.split(',').filter(item => item).join(', ')+'</td>\
                                        <td class="fixt_match w-[30%]">'+fixture+empty_div+'</td>\
                                        <td>'+result+'</td>\
                                        <td><ul class="flex-wrap">\
                                                '+($('#is_admin').val() && ($(mc+' .class_status').val() > 0) && (!d.fixture_id) ? '<a href="#" class="btn-edit class_fixt_add">Add</a>' :'')+'\
                                                '+($('#is_admin').val() && ($(mc+' .class_status').val() > 0) && (d.fixture_id && !result) ? '<a href="#" class="btn-edit class_fixt_delete">Delete</a>' :'')+'\
                                                '+(($(mc+' .class_status').val() > 0) && (d.fixture_id && !result && (d.team1_name != 'Bye') && (d.team2_name != 'Bye') && d.team1_name && d.team2_name) ? '<a href="#" class="btn-edit fixt_show_result" '+(dayjs().isAfter(dayjs(d.schedule_finish)) ? '' : 'data-intrac_forfeit_only="y"')+'>Record Result</a>' :'')+'\
                                                '+($('#is_admin').val() && ($(mc+' .class_status').val() > 0) && (result) ? '<a href="#" class="btn-edit fixt_remove_result">Remove Result</a>' :'')+'\
                                                '+($('#is_admin').val() && ($(mc+' .class_status').val() > 0) && (d.fixture_id && (dates_diff(convert_date_time(d.schedule_start,'YYYY-MM-DD'), dayjs().format('YYYY-MM-DD')) >= 0) && (d.space_ids.split(',').filter(item => item > 0).length)) ? '<a href="#" class="btn-edit fixt_swap_fixture">Swap</a>' :'')+'\
                                            </ul></td>\
                                    </tr>';

                    }

                    //separator
                    if ((dates_diff(rounds[n].round_date, dayjs().format(round_format)) >= 0) && (!gala_term)) {
                        html_str += '<tr class="row_sep class_fixt_item'+which_tr+'">\
                                        <td class="noshow round_date">'+rounds[n].round_date+'</td>\
                                        <td colspan="6"><a href="#" class="btn-edit fixt_swap_round">Swap this round of fixtures</a>'+empty_div+'</td>\
                                    </tr>'; 
                    } else {
                        //add a blank separator
                        html_str += '<tr class="row_sep class_fixt_item'+which_tr+'">\
                        				<td colspan="6"></td>\
                                    </tr>';                             
                    }

                    //create fixtures option
                    let checkbox = '<input type="checkbox" class="checkbox-custom cf_round" value="'+rounds[n].round_date+'" checked>';
                    if (rounds[n].round_data.filter(item => item.fixture_id > 0).length) {
                        checkbox = '&nbsp; &nbsp; &nbsp;';
                    }

                    cf_html_str += '<div class="form-label">\
                                        <label class="checkbox-container">'+(gala_term ? convert_date_time(rounds[n].round_date) : convert_date(rounds[n].round_date))+' ('+rounds[n].round_data.length+' bookings)'+'\
                                            '+checkbox+'\
                                        </label>\
                                    </div> '
                }

                //close table
                html_str += '</tbody></table></div>';

                $(mc+' .fixt_list').html(html_str);

                //teams
                let tm_options_str = '';
                for (let i = 0; i < res.teams.length; i++) {
                    tm_options_str += '<option value="'+res.teams[i].team_id+'">'+res.teams[i].team_name+'</option>';
                }
                $(mc+' .fixt_team1_id').html(tm_options_str);
                $(mc+' .fixt_team2_id').html(tm_options_str);
                $(mc+' .fixt_cf_r_team_id').html('<option value=""></option>'+tm_options_str);

                //create fixtures 
                $(mc+' .fixt_cf_rounds').html(cf_html_str);
                $(mc+' .fixt_cf_team_count').text(res.teams.length+(res.teams.filter(item => item.team_name == 'Bye').length ? ' (includes a bye)' : ''));
                let future_bookings = data.filter(item => dates_diff(dayjs(item.schedule_start).format('YYYY-MM-DD'), dayjs().format('YYYY-MM-DD')) > 0);
                let future_bookings_fixtures = future_bookings.filter(item => item.fixture_id > 0);

                if (future_bookings.length > future_bookings_fixtures.length) {
                    $(mc+' .fixt_cf_div').show();
                    $(mc+' .master_tr .fa-plus-square-o').click();
                    $(mc+' .fixt_cf_alt_close').hide();
                }

                //manual fixture
                $(mc+' .fixt_edit_items').hide();

                if (rawcsv) {
                    if (data.length) {
                        let dataArry = [];
                        for (let i = 0; i < data.length; i++) {
                            if (data[i].fixture_id) {
                                dataArry.push({
                                    round: data[i].tag,
                                    date: convert_date_time(data[i].schedule_start, 'YYYY-MM-DD'),
                                    start: convert_date_time(data[i].schedule_start, 'HH:mm'),
                                    team1: data[i].team1_name,
                                    team2: data[i].team2_name,
                                    space: data[i].space_name
                                });                                
                            }
                        }
                        downloadCSV(dataArry);
                    }
                }
                

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });
    } else {
        $('#loader-wrapper').hide();
    }
}

