function set_swap_fixture(el) {
    $('#loader-wrapper').show();

    let class_id = $(mc+' .fixt_class_id').val();
    let fixture_id = $(el).find('.fixture_id').text();

    let errors = [];
    //validations

    if (errors.length == 0) {
        $.ajax({
            type: 'GET',
            url: '/api/getClassFixtures',
            data: {class_id: class_id, fixture_id: fixture_id},
            dataType: 'JSON'
        }).done(async function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();
                
                let d = response.success.data[0];
                if (d) {
                    $(el).find('.empty_div:first').after('<div class="fxtalter_div flex_new_row margin_top_sm margin_bottom_sm">'+$(mc+' .fixt_swap_fixt_view').html()+'</div>');

                    if (d.swaps.length) {
                        $(el).find('.fixt_new_fixture_id_div').show();

                        let options_str = '';
                        for (let i = 0; i < d.swaps.length; i++) {
                            let a = d.swaps[i];
                            options_str += '<option value="'+a.fixture_id+'">'+convert_date_time(a.schedule_start, 'h:mma')+' '+(a.space_names ? a.space_names.split(',').filter(item => item).join(', ')+' ' : '')+(a.tag ? a.tag+': ' : '')+a.team1_name+' v '+a.team2_name+'</option>';
                        }
                        $(el).find('.fixt_new_fixture_id').html(options_str);

                    } else {
                        $(el).find('.fixt_swap_noids').show();
                        $(el).find('.fixtbtn_swap_fixture').hide();
                    }

                } else {
                    set_side_error('Unable to retrieve details'); //this should never show
                }

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });  
    }  else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();
    }    
}

