function create_fixtures() {
    $('#loader-wrapper').show();

    let location_id = $('#location_id').val();
    let class_id = $(mc+' .fixt_class_id').val();
    let round_dates = [];
    
    $(mc+' .cf_round').each(function() {
        if (this.checked) {
            round_dates.push($(this).val());
        }
    });    

    let data = {
        location_id: location_id, 
        class_id: class_id, 
        round_dates: round_dates, 
        gala: $(mc+' .fixt_cf_gala:visible').is(":checked") ? 1 : 0,
        fullfield: $(mc+' .fixt_cf_fullfield:visible').is(":checked") ? 1 : 0,
        cf_rules: [],
        action: 'create_fixtures'
    }


    let errors = [];

    $(mc+' .dynamic_tr').each(function () {
        let r = {
            mandatory: $(this).find('.fixt_cf_r_mandatory').val(),
            team_id: $(this).find('.fixt_cf_r_team_id').val(),
            type: $(this).find('.fixt_cf_r_type').val(),
            date: $(this).find('.fixt_cf_r_date').val() ? parse_date($(this).find('.fixt_cf_r_date').val()) : '',
            start_time: $(this).find('.fixt_cf_r_start_time').val() ? parse_time($(this).find('.fixt_cf_r_start_time').val()) : '00:01:00',
            finish_time: $(this).find('.fixt_cf_r_finish_time').val() ? parse_time($(this).find('.fixt_cf_r_finish_time').val()) : '23:59:00',
        } 

        if (r.team_id) {
            data.cf_rules.push(r);

            let r_team_name = $(this).find('.fixt_cf_r_team_id option:selected').text();

            if (r.type == 'Date') {
                if (!isvalidDate(r.date || '')) {
                    errors.push(r_team_name+" rule - invalid date");
                }
            }

            if (!isvalidTime(r.start_time)) {
                errors.push(r_team_name+" rule - invalid start time, leave blank for full day");
            }

            if (!isvalidTime(r.finish_time)) {
                errors.push(r_team_name+" rule - inavlid finish time, leave blank for full day");
            }

            if (!r.date && r.start_time == '00:01:00') {
                errors.push(r_team_name+" rule - invalid start time, cannot be blank with out a date");
            }

        }
    });

    //validations
    if (!round_dates.length) {
        errors.push('You must choose at least one option to proceed further');
    }

    if (errors.length == 0) {
        $.ajax({
            type: 'POST',
            url: '/api/updateClassFixture',
            data: data,
        }).done(async function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();
                get_class_fixtures();

                if (response.info.length) {
                    set_side_error(response.info.join("<br>"), 'amber');
                }

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else { 
                $('#loader-wrapper').hide();
                //preference is to refresh. If cf_rules are involved, there won't be dummy schedules & we need to retain the cf_rules
                if (data.cf_rules.length) {
                    set_side_error(response.error.join("<br>"));
                } else {
                    get_class_fixtures(); //must refresh to reflect any dummy schedules created
                    set_side_error(response.error.join("<br>"));                    
                }
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });  
    }  else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();       
    }    
}

function get_class_ladder(class_id) {

    if (!class_id) {
        class_id = $(mc+' .class_class_id').val();
    }

    $('#loader-wrapper').show();

    $(mc+' .ladder_tab').html($('#master_class_view .ladder_tab').html()); //reset

    if (class_id) {
        $.ajax({
            type: 'GET',
            url: '/api/getClassLadder',
            data: {class_id: class_id},
            dataType: 'JSON'
        }).done(function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

                let res = response.success;

                //data
                let data = res.data;

                let html_str = '';
                let html_str_h = '';

                //class info
                $(mc+' .fixt_class_id').val(res.class.class_id);

                //header
                if (res.options.score_model) {
	                html_str_h += '<div class="table-wrapper"><table class="table">\
	                                <thead>\
	                                    <tr>\
	                                        <th class="align-left">Team</th>\
	                                        <th>Play</th>\
	                                        <th>Pnts</th>\
	                                        '+(res.options.extras ? '<th>Extr</th>' : '')+'\
	                                    </tr>\
	                                </thead>\
	                                <tbody>';
                } else {
	                html_str_h += '<div class="table-wrapper"><table class="table">\
	                                <thead>\
	                                    <tr>\
	                                        <th class="align-left">Team</th>\
	                                        <th>Play</th>\
	                                        <th>Wins</th>\
	                                        <th>Draw</th>\
	                                        <th>Loss</th>\
	                                        '+(res.options.byes ? '<th>Byes</th>' : '')+'\
	                                        '+(res.options.extras ? '<th>Extr</th>' : '')+'\
	                                        '+(res.options.win_perc ? '<th>Perc</th>' : '<th>Pnts</th>')+'\
	                                        <th>Diff</th>\
	                                    </tr>\
	                                </thead>\
	                                <tbody>';
                }

                for (let n = 0; n < data.length; n++) {

                    //pool name
                    if (data[n].pool) {
                    	html_str += '<h4 class="text-xl leading-[130%]"'+(n>0 ? ' margin_top_lg' : '')+'>'+data[n].pool+'</h4>';
                    }

                    //open table incl table header
                    html_str += html_str_h; 

                	let comp = data[n].comp; //comp is JSON team_id: team_data

                	let comp_arr = Object.entries(comp).sort(([, a], [, b]) => b.sort - a.sort).map(([key]) => key); //sort comp based on sort field in team_data. returns team_ids (key) in an array             	

                    //data
                    for (let i = 0; i < comp_arr.length; i++) {

                    	let t = comp_arr[i];

                    	let play = comp[t].wins+comp[t].draw+comp[t].loss;

		                if (res.options.score_model) {
			                html_str += '<tr>\
		                                        <td class="align-left">'+comp[t].team_name+'</td>\
		                                        <td>'+play+'</td>\
		                                        <td>'+comp[t].pnts+'</td>\
		                                        '+(res.options.extras ? '<td>'+(comp[t].extras == 0 ? '' : comp[t].extras)+'</td>' : '')+'\
		                                    </tr>';
		                } else {
			                html_str += '<tr>\
		                                        <td class="align-left">'+comp[t].team_name+'</td>\
		                                        <td>'+play+'</td>\
		                                        <td>'+comp[t].wins+'</td>\
		                                        <td>'+comp[t].draw+'</td>\
		                                        <td>'+comp[t].loss+'</td>\
		                                        '+(res.options.byes ? '<td>'+comp[t].byes+'</td>' : '')+'\
		                                        '+(res.options.extras ? '<td>'+(comp[t].extras != 0 ? comp[t].extras : '')+'</td>' : '')+'\
		                                        '+(res.options.win_perc ? ('<td>'+(play > 0 ? numberformat(comp[t].wins/play*100, 0)+'%' : '')+'</td>') : '<td>'+comp[t].pnts+'</td>')+'\
		                                        <td>'+(comp[t].gfor-comp[t].gagn)+'</td>\
			                                </tr>';
		                }
                    }

	                //close table
	                html_str += '</tbody></table></div>';
                }

                $(mc+' .ladd_list').html(html_str);
                

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });
    } else {
        $('#loader-wrapper').hide();
    }
}

async function get_class_attendance({ class_id='', term_id='', schedule_id='', term_changed=false } = {}) {

	return new Promise((resolve, reject) => {

	    $('#loader-wrapper').show();

	    //grab inputs before reset
	    if ($(mc).hasClass('modal-open') && ($(mc+' .att_class_id').val() > 0)) {
	        class_id = $(mc+' .att_class_id').val();
	        term_id = $(mc+' .att_term_id').val();
	        if (!term_changed) { //this check is to ensure new term_id is not sent with old schedule_id
	            schedule_id = $(mc+' .att_schedule_id').val();
	        }
	    }

	    $(mc+' .attendance_tab').html($('#master_class_view .attendance_tab').html()); //reset	    
	    
	    let class_enrolment_titles = JSON.parse($('#class_enrolment_titles').text());

	    let register_mode = 'schedule';

        let level_type = $(mc+' .class_level_id option[value="' + $(mc+' .class_level_id').val() + '"]').prop('dataset').intrac;
        if (level_type == 4) {
            register_mode = 'fixture';
        }

	    if (class_id) {
	    	let querydata = {class_id: class_id, term_id: term_id, schedule_id: schedule_id, register_mode: 'schedule', roll_mode: true} //register_mode here is always schedule
	        
		    if ($('.instructor-page').length) {
		        querydata.from = 'instructor';
		    }	    	

	        $.ajax({
	            type: 'GET',
	            url: '/api/getRegisters',
	            data: querydata,
	            dataType: 'JSON'
	        }).done(function( response ) {

	            if (response.success != undefined) {

	                $('#loader-wrapper').hide();

	                let res = response.success;

	                //class info
	                $(mc+' .att_class_id').val(res.class.class_id);
	                $(mc+' .att_capacity').val(res.class.capacity);

	                //term info
	                let options_str_t = '';
	                for (let i = 0; i < res.terms.length; i++) {
	                    options_str_t += '<option value="'+res.terms[i].term_id+'">'+res.terms[i].term_name+'</option>'; //from_schedule not required
	                }
	                $(mc+' .att_term_id').html(options_str_t);

	                if (term_id) {
	                    $(mc+' .att_term_id').val(term_id);
	                } else {
	                    $(mc+' .att_term_id').val(res.class.term_id);
	                }

	                //adjust chevrons
	                if (true) {
	                    let show_next = false;
	                    let show_prev = false;
	                    let currentIndex = $(mc+' .att_term_id').prop('selectedIndex');

	                    $(mc+' .att_term_id option').each(function(index) {
	                        let from_schedule = $(this).prop('dataset').intrac_from_schedule;

	                        if (index > currentIndex) {
	                            show_next = true;
	                        }
	                        
	                        if (index < currentIndex) {
	                            show_prev = true;
	                        }
	                    });
	                    if (show_next) {
	                        $(mc+' .att_term_next').show();
	                    } else {
	                        $(mc+' .att_term_next').hide();
	                    }

	                    if (show_prev) {
	                        $(mc+' .att_term_prev').show();
	                    } else {
	                        $(mc+' .att_term_prev').hide();
	                    }
	                }

	                //schedule info
                    $(mc+' .att_schedule_id_li').removeClass('noshow');

                    let options_str_s = '';
                    for (let i = 0; i < res.schedules.length; i++) {
                        let s = res.schedules[i];
                        let user_str = s.usernames.split(',')[0];

                        let schedule_name = convert_date(s.schedule_start, 'ddd D MMM YYYY')+' '+dayjs(s.schedule_start).format('h:mma')+'-'+dayjs(s.schedule_finish).format('h:mma');
                        if (user_str && (register_mode == 'schedule')) {
                            schedule_name += ' ('+user_str+')';
                        }

                        options_str_s += '<option value="'+s.schedule_id+'">'+schedule_name+'</option>';
                    }
                    $(mc+' .att_schedule_id').html(options_str_s);

                    $(mc+' .att_schedule_id').val(res.schedules.filter(item => item.selected_schedule)[0].schedule_id);
                    $(mc+' .att_schedule_date').val(convert_date(res.schedules.filter(item => item.selected_schedule)[0].schedule_start, 'YYYY-MM-DD'));

                    //adjust chevrons
                    let show_next = false;
                    let show_prev = false;
                    let currentIndex = $(mc+' .att_schedule_id').prop('selectedIndex');

                    $(mc+' .att_schedule_id option').each(function(index) {
                        let from_schedule = $(this).prop('dataset').intrac_from_schedule;

                        if (index > currentIndex) {
                            show_next = true;
                        }
                        
                        if (index < currentIndex) {
                            show_prev = true;
                        }
                    });
                    if (show_next) {
                        $(mc+' .att_schedule_next').show();
                    } else {
                        $(mc+' .att_schedule_next').hide();
                    }

                    if (show_prev) {
                        $(mc+' .att_schedule_prev').show();
                    } else {
                        $(mc+' .att_schedule_prev').hide();
                    }

	                //data
	                let data = res.data;

	                let html_str = '';
	                let html_str_a = '';

	                //prepare data_map
	                let data_map = [];

                    let s = res.schedules.filter(item => item.selected_schedule)[0];

                    if (s) {
                        if (s.schedule_comment) {
                            $(mc+' .att_hdr_ul').append('<li class="sched_items"><span>Comment:</span>'+s.schedule_comment+'</li>');
                        }
                        $(mc+' .att_schedule_comment').val(s.schedule_comment);

                        let schedule_name = $(mc+' .att_schedule_id option[value="'+s.schedule_id+'"]').text(); //should be same as $(mc+' .att_schedule_id option:selected').text();

                        if (register_mode == 'fixture') {
	                        
                        	let fixts = (res.fixtures||[]).filter(item => item.schedule_id == s.schedule_id);

                        	for (let i = 0; i < fixts.length; i++) {

		                        let space_str = fixts[i].space_names.split(',')[0];
		                        let user_str = fixts[i].usernames.split(',')[0];

		                        //team 1
		                        data_map.push({
		                            header: schedule_name+' '+fixts[i].team1_name,
		                            sub_header: space_str+' '+user_str,
		                            ids: s.class_id+'~0~'+s.schedule_id+'~0~0',
		                            data: data.filter(item => item.team_id == fixts[i].team1_id),
		                            captain_id: fixts[i].team1_captain_id,
		                            team_name: fixts[i].team1_name,
		                            fixture_id: fixts[i].fixture_id,
		                            fixture_team: 1
		                        });

		                        //team 2
		                        data_map.push({
		                            header: schedule_name+' '+fixts[i].team2_name,
		                            sub_header: space_str+' '+user_str,
		                            ids: s.class_id+'~0~'+s.schedule_id+'~0~0',
		                            data: data.filter(item => item.team_id == fixts[i].team2_id),
		                            captain_id: fixts[i].team2_captain_id,
		                            team_name: fixts[i].team2_name,
		                            fixture_id: fixts[i].fixture_id,
		                            fixture_team: 2
		                        });
		                    }
                        } else {

                        	let space_str = s.space_names.split(',')[0];

	                        data_map.push({
	                            header: schedule_name,
	                            sub_header: space_str,
	                            ids: s.class_id+'~'+s.program_id+'~'+s.schedule_id+'~0~0',
	                            data: data,
	                            addons: res.addons
	                        }); 
                        }                                                 
                    }

	                //convert data_map to html
	                for (let j = 0; j < data_map.length; j++) {

	                    //header
	                    let header_str = data_map[j].header ? (data_map[j].header+(data_map[j].sub_header ? '<br>'+data_map[j].sub_header : '')) : '';

	                    if ($('.instructor-page').length) {
	                    	if (data_map[j].data[0]?.team_name) {
		                        html_str += '<li class="w-full">\
		                                        <div class="w-full p-2 rounded-3xl bg-purple-light text-base text-purple text-center margin_btm_sm">'+data_map[j].data[0]?.team_name+'</div>\
		                                    </li>';
	                    	}
	                    	html_str += '<ul class="mb-5 flex flex-wrap gap-4 class_att_hdr">';
	                    } else {
		                    html_str += '<div class="table-wrapper"><table class="table se_div class_att_hdr">\
		                                    <thead'+(!header_str ? ' class="noshow"' : '')+'>\
		                                        <tr>\
		                                            <th class="w-50p">'+header_str+'<div class="ids noshow">'+data_map[j].ids+'</div></th>\
		                                            <th>Status</th>\
		                                            <th>Present</th>\
		                                            <th>Absent</th>\
		                                            '+($('.makeup_items').length ? '<th>No show</th>' : '')+'\
		                                            '+(res.options.roll.includes('4')? '<th>Cancelled</th>' : '')+'\
		                                            '+(res.options.roll.includes('5')? '<th>Left</th>' : '')+'\
		                                        </tr>\
		                                    </thead>\
		                                    <tbody>'
	                    }

	                    //data
	                    if (res.options.roll.includes('f')) { //sort by first_name
	                    	data_map[j].data = data_map[j].data.sort((a, b) => a.first_name.localeCompare(b.first_name));
	                    	if (data_map[j].addons) {
	                    		data_map[j].addons = data_map[j].addons.sort((a, b) => a.first_name.localeCompare(b.first_name));	
	                    	}
	                    }

	                    for (let i = 0; i < data_map[j].data.length; i++) {
	                        let d = data_map[j].data[i];
	                        
	                        let captain = '';
	                        if (register_mode == 'fixture') {
		                        if (data_map[j].captain_id == d.customer_id) {
		                        	captain += ' (C)'
		                        }	                        	
	                        }

	                        let age = (getAge(d.dob)) ? ' ('+getAge(d.dob)+')' : '';
	                        if (d.details && d.details.schoolyear) {
	                            age = ' ('+d.details.schoolyear+')';
	                        }
	                        if (register_mode == 'fixture') {
	                        	age = '';
	                        }

	                        let medical = (d.medical && !d.medical_reused) ? ' *' : '';

	                        if ($('.instructor-page').length && medical && (d.medical != '-')) {
	                        	medical = '<img class="cursor margin_left_xs margin_right_xs tooltip_img att_medical_ttip" src="images/icons/medical-note.svg" alt="Medical" data-intrac_tooltip="'+d.medical+'">';
	                        }

	                        let comment = (d.customer_comments) ? ' ?' : '';

	                        let qty = (d.quantity > 0) ? ' - Qty: '+d.quantity : '';

	                        let free_makeup = d.makeup ? ' (makeup)' : (d.free_trial ? ' (free trial)' : '');

	                        let dropin = (d.fixture_id > 0) ? ' (drop-in)' : '';

	                        let roll_data = '';
	                        if (d.roll_data && !isEmptyJSON(d.roll_data)) {
	                        	roll_data += ' - ';
		                        for(const key in d.roll_data) {
		                        	roll_data += d.roll_data[key]+' ';
		                        }
	                        }

	                        let rollcode = d.rollcode ? '<span class="margin_left_sm">'+d.rollcode+'</span>' : '';

	                        let img = d.image_data && !$('.instructor-page').length ? '<img src="data:image/png;base64,'+d.image_data+'" class="margin_top_sm img-w-h">' : '';
	                        let img_ = d.image_data && $('.instructor-page').length ? '<img src="data:image/png;base64,'+d.image_data+'" class="rounded-t-[20px] att_img">' : '';

	                        let bday = '';
							if ($('.instructor-page').length) {
								if (isvalidDate(d.bday||'')) {
									let dt = dayjs().format('YYYY')+'-'+dayjs(d.bday).format('MM-DD');
									let diff = dates_diff(dt,dayjs().format('YYYY-MM-DD'));
									if (diff >=0 && diff < 7) {
										bday = ' <b class="half-bold inline-flex gap-1 items-center valign-middle"><img src="images/icons/cake.svg" alt=""> '+convert_date(dt, 'D MMM')+'</b>';
									}
								}
							}

							let unpaid_lnk = '<a href="#" class="btn-edit view_account">View Account</a>';

							let comments_lnk = d.comments_na ? '' : '<a href="#" class="btn-edit !w-full align-center view_customer_info" data-intrac_goto_tab="cust_comments" data-intrac_customer_id="'+d.customer_id+'" data-intrac_parent_id="'+d.parent_id+'">Comments</a>';
							let assess_lnk = $('.assess_items').length && (level_type == 0 || level_type == 1) && d.customer_level_id > 0 ? '<a href="#" class="btn-edit !w-full align-center view_assess_customer">Assess'+(!d.assess_completed || d.assess_overdue ? ' #' : '')+'</a>' : '';

							let suspended = d.suspended ? ' Currently suspended' : '';

							let no_roll = d.customer_id == 2 || suspended ? ' noshow' : '';

							let cust_str = '<span class="register_id noshow">'+d.register_id+'</span><span class="customer_id noshow">'+d.customer_id+'</span><span class="parent_id noshow">'+d.parent_id+'</span><span class="customer_name noshow">'+d.first_name+' '+d.last_name+'</span><span class="receipt_id noshow">'+d.receipt_id+'</span><span class="assess_id noshow">'+(d.assess?.assess_id || 'new')+'</span><div>'+(i+1)+'. '+'<a href="#" class="view_customer" '+(d.parent_id > 0 ? 'data-intrac_goto_tab="childs"': '')+'>'+d.first_name+' '+d.last_name+age+captain+medical+comment+'</a>'+qty+free_makeup+dropin+suspended+roll_data+bday+'</div>'+img+'<span class="se_det noshow">'+(d.parent_id > 0 ? d.parent_id : d.customer_id)+'~'+d.first_name+' '+d.last_name+'~'+d.phone+'~'+d.email+'~'+d.altemail+'</span>'; 

							if ($('.instructor-page').length) {
								html_str += '<li class="w-full class_att_item assess_cust_item">\
												<div class="margin_btm_sm flex justify-center">'+img_+'</div>\
												<div class="p-2 pt-0">\
			                                        <div class="margin_btm_sm leading-5">'+cust_str+'</div>\
			                                        '+(d.receipt_type == 1 ? '<div class="margin_btm_sm"><span class="unpaid">Unpaid</span></div>' : '')+'\
			                                        <div class="flex justify-between gap-4 margin_btm_sm">'+assess_lnk+comments_lnk+'</div>\
			                                        <div class="flex flex-wrap justify-between items-center text-xs text-gray">\
				                                        <label class="pretty-radio'+no_roll+'">Present '+rollcode+'<input type="radio" name="att_roll_type_'+d.register_id+'" value="1" '+(d.roll_type == 1 ? 'checked' : '')+'><span class="radio-custom"></span></label>\
				                                        '+(!$('.makeup_items').length ? '<label class="pretty-radio'+no_roll+'">Absent <input type="radio" name="att_roll_type_'+d.register_id+'" value="2" '+(d.roll_type == 2 ? 'checked' : '')+'><span class="radio-custom"></span></label>' : '')+'\
			                                            '+($('.makeup_items').length ? '<label class="pretty-radio'+no_roll+'">No show <input type="radio" name="att_roll_type_'+d.register_id+'" value="3" '+(d.roll_type == 3 ? 'checked' : '')+'><span class="radio-custom"></span></label>' : '')+'\
			                                            '+(res.options.roll.includes('5') ? '<label class="pretty-radio'+no_roll+'">Left <input type="radio" name="att_roll_type_'+d.register_id+'" value="5" '+(d.roll_type == 5 ? 'checked' : '')+'><span class="radio-custom"></span></label>' : '')+'\
			                                        </div>\
			                                    </div>\
											</li>';
							} else {
		                        html_str += '<tr class="class_att_item assess_cust_item">\
		                                        <td class="w-50p">'+cust_str+'</td>\
		                                        <td>'+(d.receipt_type == 2 ? '<span class="paid">Paid</span>' : (d.receipt_type == 1 ? unpaid_lnk : ''))+'</td>\
		                                        <td><label class="pretty-radio'+no_roll+'"><input type="radio" name="att_roll_type_'+d.register_id+'" value="1" '+(d.roll_type == 1 ? 'checked' : '')+'><span class="radio-custom"></span>'+rollcode+'</label></td>\
		                                        <td><label class="pretty-radio'+no_roll+'"><input type="radio" name="att_roll_type_'+d.register_id+'" value="2" '+(d.roll_type == 2 ? 'checked' : '')+'><span class="radio-custom"></span></label></td>\
	                                            '+($('.makeup_items').length ? '<td><label class="pretty-radio'+no_roll+'"><input type="radio" name="att_roll_type_'+d.register_id+'" value="3" '+(d.roll_type == 3 ? 'checked' : '')+'><span class="radio-custom"></span></label></td>' : '')+'\
	                                            '+(res.options.roll.includes('4') ? '<td><label class="pretty-radio'+no_roll+'"><input type="radio" name="att_roll_type_'+d.register_id+'" value="4" '+(d.roll_type == 4 ? 'checked' : '')+'><span class="radio-custom"></span></label></td>' : '')+'\
	                                            '+(res.options.roll.includes('5') ? '<td><label class="pretty-radio'+no_roll+'"><input type="radio" name="att_roll_type_'+d.register_id+'" value="5" '+(d.roll_type == 5 ? 'checked' : '')+'><span class="radio-custom"></span></label></td>' : '')+'\
		                                    </tr>';
							}
	                    }

	                    //count
	                    let qtys = data_map[j].data.reduce((sum, item) => sum + item.quantity, 0); //sum of all quantity
	                    let regs = qtys > 0 ? qtys : data_map[j].data.length;
	                    let absents = data_map[j].data.filter(item => item.absent).length;

	                    if (($(mc+' .att_capacity').val() > 0) && ((regs-absents) >= $(mc+' .att_capacity').val()) && (register_mode == 'schedule')) {
	                        if ($('.instructor-page').length) {
		                        html_str += '<li class="w-full cap_reached" data-intrac_capacity="'+$(mc+' .att_capacity').val()+'">\
		                                        <div class="w-full p-2 rounded-3xl bg-purple-light text-base text-purple text-center">Capacity Reached</div>\
		                                    </li>';
		                    } else {
		                        html_str += '<tr class="cap_reached" data-intrac_capacity="'+$(mc+' .att_capacity').val()+'">\
		                                        <td colspan="7"><b>Capacity Reached</b></td>\
		                                    </tr>';		                    	
		                    }                                 
	                    }

	                    if ($('.instructor-page').length) {
	                    	html_str += '</ul>';
	                    } else {

	                        //sms & email
	                        if (data_map[j].data.length) {
		                        html_str += '<tr class="white_tr">\
		                                        <td colspan="3">\
		                                        	<ul>\
		                                        		<li><a href="#" class="btn-edit sms_lnk">SMS</a></li>\
		                                        		<li><a href="#" class="btn-edit email_lnk">Email</a></li>\
		                                        		'+($('.gcard_items').length && (register_mode == 'fixture') && $('#is_admin').val() && (dayjs().isAfter(dayjs(s.schedule_finish))) ? '<li><a href="#" class="btn-edit admin_add_game_card" data-intrac_fixture_id="'+data_map[j].fixture_id+'" data-intrac_orders="'+data_map[j].fixture_team+'">Record Player Booking</a></li>' : '')+'\
		                                        	</ul>\
		                                        </td>\
		                                    </tr>';                          	
	                        }

		                    //close table
		                    html_str += '</tbody></table></div>'
		                }

	                    //addons - shows in schedule_mode only (for programs - today's view will be schedule_mode), add as a separate table
	                    if (data_map[j].addons && data_map[j].addons.length) {
	                        html_str_a += '<div class="table-wrapper"><table class="table">\
	                                        <thead>\
	                                            <tr>\
	                                                <th colspan="3">Addons Purchased</th>\
	                                            </tr>\
	                                        </thead>\
	                                        <tbody>'                         
	                        
	                        for (let i = 0; i < data_map[j].addons.length; i++) {
	                            let d = data_map[j].addons[i];
	                            /*note: d.customer_id here is purchase.customer_id*/
	                            html_str_a += '<tr class="class_addon_item">\
	                                            <td><span class="purchase_id noshow">'+d.purchase_id+'</span><span class="customer_id noshow">'+d.customer_id+'</span><span class="receipt_id noshow">'+d.receipt_id+'</span>'+(i+1)+'. '+d.first_name+' '+d.last_name+'</td>\
	                                            <td>'+(d.quantity > 1 ? d.quantity+' x ' : '')+d.category+' '+d.product_name+'</td>\
	                                            <td>'+(d.receipt_type == 2 ? ($('.instructor-page').length ? '' : '<span class="paid">Paid</span>') : (d.receipt_type == 1 ? ($('.instructor-page').length ? '<span class="unpaid">Unpaid</span>' : '<a href="#" class="btn-edit view_account">View Account</a>') : ''))+'</td>\
	                                        </tr>'; 
	                        }

	                        //close table
	                        html_str_a += '</tbody></table></div>';
	                    }
	                }

	                $(mc+' .att_list').html(html_str);
	                $(mc+' .att_addons_list').html(html_str_a);

	                //adjust buttons
	                if (data.length > data.filter(item => item.roll_type).length) {
	                	$(mc+' .att_rest_btn').removeClass('noshow');
	                } else {
	                	$(mc+' .att_rest_btn').remove();
	                }

	                if (s && dayjs(s.schedule_start).isAfter(dayjs()) && data.filter(item => item.roll_type==1).length) {
	                	$(mc+' .att_remove_present').removeClass('noshow');
	                } else {
	                	$(mc+' .att_remove_present').remove();
	                }

	                if (data.length) {
	                	$(mc+' .att_mark_all_washout').removeClass('noshow');
	                	$(mc+' .btn_saveClassRoll').removeClass('noshow');
	                } else {
	                	$(mc+' .att_mark_all_washout').remove();
	                	$(mc+' .btn_saveClassRoll').remove();
	                }

	                if (register_mode != 'fixture') {
	                	$(mc+' .att_report').removeClass('noshow');
	                } else {
	                	$(mc+' .att_report').remove();
	                }

	                //instructor
	                if ($('.instructor-page').length) {
	                	if (dayjs().format('YYYY-MM-DD') != $(mc+' .att_schedule_date').val()) { //not today
	                		$(mc+' .btn_saveClassRoll').remove();
	                		$(mc+' .att_mark_btn').remove();
	                	}

	                	$(mc+' .att_report').remove();
	                	$(mc+' .att_mark_rest_absent').remove();
	                	$(mc+' .att_mark_all_washout').remove();
	                }

	                //archived class
	                if ($(mc+' .class_status').val() === '0') {
	                    $(mc+' .btn-default').remove();
	                	$(mc+' .btn-edit').remove();
	                }

	            } else if (response.redirect != undefined) {
	                mini_login_wizard(response.redirect); //session timeout case
	            } else {    
	                set_side_error(response.error.join("<br>"));
	                $('#loader-wrapper').hide();
	            }
	            resolve();

	        }).fail( function(xhr, textStatus, errorThrown) {
	            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
	            $('#loader-wrapper').hide();
	            resolve();
	        });
	    } else {
	        $('#loader-wrapper').hide();
	        resolve();
	    }
	});    
}

function saveClassRoll() {

    $('#loader-wrapper').show();

    //prepare the data

    let rolls = [];
    $(mc+' .class_att_item').each(function () {
    	let register_id = $(this).find('.register_id').text()
        let roll_type = $(this).find('input:radio[name="att_roll_type_'+register_id+'"]:visible:checked').length ? $(this).find('input:radio[name="att_roll_type_'+register_id+'"]:visible:checked').val() : '';
        if (roll_type) {
            rolls.push({
                customer_id: $(this).find('.customer_id').text(),
                roll_type: roll_type
            });
        }
    });

    let data ={
    	class_id: $(mc+' .att_class_id').val(),
        schedule_id: $(mc+' .att_schedule_id').val(),
        location_id: $('#location_id').val(),
        rolls: rolls
    };  

    let qry_from = '';
    if ($('.instructor-page').length) {
        qry_from = '?from=instructor';
    }

    let errors = [];
    //validations
    if (!rolls.length) {
        errors.push('Please mark the attendance and try again'); 
    }

    if (errors.length == 0) {
        $.ajax({
            type: 'POST',
            url: '/api/saveClassRoll'+qry_from,
            data: data,
            dataType: 'JSON'
        }).done(function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

                set_side_error('Attendance saved succesfully', 'green');
                
                if ($('.instructor-page').length) {
                	close_modal();
                } else {
                	get_class_attendance();	

	                //refresh grid
	                if ($('#classes').is(":visible")) {
	                    get_class_grid(false);
	                }                	
                }

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });  
    }  else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();       
    }            
}

function update_att_schedule_comment() {
    $('#loader-wrapper').show();

    let location_id = $('#location_id').val();
    let schedule_id = $(mc+' .att_schedule_id').val();
    let schedule_comment = $(mc+' .att_schedule_comment').val();

    let errors = [];
    //validations

    if (errors.length == 0) {
        $.ajax({
            type: 'POST',
            url: '/api/updateClassSchedule',
            data: {schedule_comment:schedule_comment, schedule_id: schedule_id, location_id: location_id, action: 'update_comment'},
            dataType: 'JSON'
        }).done(async function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

                set_side_error('Comment saved succesfully', 'green');

                get_class_attendance();

                //refresh grid
                if ($('#classes').is(":visible") && $('#classes .is_detailed').length) {
                    get_class_grid(false);
                }

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });  
    }  else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();
    }    
}

