function get_class_waitlist(class_id) {
    $('#loader-wrapper').show();

    let class_enrolment_titles = JSON.parse($('#class_enrolment_titles').text());

    if (class_id) {
        $.ajax({
            type: 'GET',
            url: '/api/getClassWait',
            data: {class_id: class_id},
            dataType: 'JSON'
        }).done(function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

                let res = response.success;

                //data
                let data = res.data;

                let html_str = '';

                //header
                html_str += '<div class="table-wrapper"><table class="table class_att_hdr">\
                                <thead>\
                                    <tr>\
                                        <th>Customer</th>\
                                        '+(res.class.level_type == 1 ? '<th>Program</th>' : '')+'\
                                        <th>Booking</th>\
                                        <th>Comment</th>\
                                        <th>Created by</th>\
                                        <th>Actions</th>\
                                    </tr>\
                                </thead>\
                                <tbody>'                

                for (let i = 0; i < data.length; i++) {
                    let d = data[i];
                    let prog_str = '';
                    let sched_str = '';

                    let user_str = d.usernames.split(',')[0];
                    let space_str = d.space_names.split(',')[0];


                    if (d.schedule_id > 0) {
                        sched_str = convert_date(d.schedule_start)+' '+convert_time(dayjs(d.schedule_start).format('HH:mm:ss'),'h:mma')+'-'+convert_time(dayjs(d.schedule_finish).format('HH:mm:ss'),'h:mma')+(user_str ? ' '+user_str : '')+(space_str ? ' '+space_str : '');
                    } else if (d.program_id > 0) {
                        prog_str = d.day.substring(1)+' '+convert_time(d.program_start,'h:mma')+'-'+convert_time(d.program_finish,'h:mma')+(user_str ? ' '+user_str : '')+(space_str ? ' '+space_str : '');
                    }

                    html_str += '<tr class="class_wait_item">\
                                    <td><span class="wait_id noshow">'+d.wait_id+'</span><span class="customer_id noshow">'+d.customer_id+'</span><span class="parent_id noshow">'+d.parent_id+'</span><a href="#" class="view_customer">'+d.first_name+' '+d.last_name+'</a></td>\
                                    '+(res.class.level_type == 1 ? '<td>'+prog_str+'</td>' : '')+'\
                                    <td>'+sched_str+'</td>\
                                    <td>'+d.wait_comment+'</td>\
                                    <td>'+(d.opener || '')+'</td>\
                                    <td><ul>\
                                            <li><a href="#" class="btn-edit reg_register_customer class_wait_enrol" data-intrac="'+d.class_id+'~'+d.program_id+'~'+d.schedule_id+'~0~0'+'">'+toTitleCase(class_enrolment_titles.verb || 'enrol')+'</a></li>\
                                            <li><a href="#" class="btn-edit class_wait_delete">Delete</a></li>\
                                        </ul>\
                                        <span class="se_det noshow">'+(d.parent_id > 0 ? d.parent_id : d.customer_id)+'~'+d.first_name+' '+d.last_name+'~'+d.phone+'~'+d.email+'~'+d.altemail+'</span>\
                                    </td>\
                                </tr>';
                }

                //close table
                html_str += '</tbody></table></div>'

                $(mc+' .wait_list').html(html_str);

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });
    } else {
        $('#loader-wrapper').hide();
    }
}

