function createReceiptInvoice(inv_msg='') {
    $('#loader-wrapper').show();

    inv_msg = inv_msg.trim();

    let customer_id = $(mc2+' .cust_edit_tab .cust_customer_id').val()

    let receipt_ids = [];

    let credits_receipts = 0;
    let total_aud_calc = 0;

    $(mc2+' .cust_rec_receipt').each(function () {
       if (this.checked) {
            receipt_ids.push($(this).val());
            let amount = parseFloat($(this).prop('dataset').intrac_amount);
            if (amount < 0) {
                credits_receipts++;
            }
            total_aud_calc += amount;
       }
    });

    let errors = [];
    //validations

    if (credits_receipts > 1) {
        errors.push('Please select only one credit item, or combine credits by first processing a payment against just the credits');
    }

    if (total_aud_calc <= 0) {
        errors.push("The total amount of selected receipts is not greater than zero. Please process these as a payment to generate invoice");
    }

    if (inv_msg.length > 25) {
    	errors.push("Maximum length of optional text is 25 characters");
    }

    //prepare the data
    let data ={
        customer_id: customer_id,
        location_id: $('#location_id').val(),
        receipt_ids: receipt_ids,
        inv_msg: inv_msg
    };  

    //console.log(data);

    if (errors.length == 0) {
        $('#loader-wrapper').hide();

        $('#cust_generate_invoice').text(customer_id+'~'+$(mc2+' .rcpts_list .receipt_id:first').text()); //store

        let href = '/api/createReceiptInvoice?customer_id='+data.customer_id+'&location_id='+data.location_id+(data.inv_msg ? '&inv_msg='+data.inv_msg : '')+'&receipt_ids='+data.receipt_ids.join(',');
        window.open(href, '_blank');
        close_modal2(); 
    } else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();       
    }  
}

