function update_cust_comment(el) {
	$(mc2+' .cust_comment_form').removeClass('noshow_imp');
	$(mc2+' .cust_comment_id').val($(el).find('.comment_id').text());
	$(mc2+' .cust_comment_child_id').val($(el).find('.child_id').text());
	$(mc2+' .cust_comment_cur').html($(el).find('.comment_cur').html());
    $(mc2+' .new-modal-content').animate({
        scrollTop: $(mc2+' .cust_comment_form').position().top + $(mc2+' .new-modal-content').scrollTop() - $(mc2 + ' .modal-header').outerHeight()
    }, 500);
    if ($(mc2+' .btn_saveCustComment').prop('dataset').intrac_overwrite) {
    	let quill = Quill.find($(mc2+' .cust_comment_data')[0]);
    	quill.clipboard.dangerouslyPasteHTML($(el).find('.comment_data').html().replace(/\r?\n|\r/g,"<br>"));
    	quill.blur();
    }
    $(mc2+' .cust_followup').val($(el).find('.followup').text());	
}

function save_cust_comment() {

    $('#loader-wrapper').show();

    //prepare the data

    let data ={
        comment_id: $(mc2+' .cust_comment_id').val(),
        customer_id: $(mc2+' .cust_edit_tab .cust_customer_id').val(),
        child_id: $(mc2+' .cust_comment_child_id').val(),
        comment_data: sanitiseQuillHTML($(mc2+' .cust_comment_data .ql-editor').html()),
        location_id: $('#location_id').val()
    };

    if (data.comment_data == '<p><br></p>') {
    	data.comment_data = '';
    }

    if (data.comment_id && $(mc2+' .btn_saveCustComment').prop('dataset').intrac_overwrite) {
    	data.action = 'overwrite';
    }

    let followup = parse_date($(mc2+' .cust_followup').val() || '');
    if (isvalidDate(followup)) {
    	data.followup = followup;
    }

    let qry_from = '';
    if ($('.instructor-page').length) {
        qry_from = '?from=instructor';
    }

    let errors = [];
    //validations

    if (isEmpty(data.comment_data)) {
        errors.push('Please enter a comment and re-try');
    }

    if (!isEmpty($(mc2+' .cust_followup').val() || '') && !data.followup) {
    	errors.push('Please enter a valid follow up date');
    }

    if (errors.length == 0) {
        $.ajax({
            type: 'POST',
            url: '/api/saveComment'+qry_from,
            data: data,
            dataType: 'JSON'
        }).done(function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

                viewCustomer(data.customer_id, 'cust_comments');

                //refresh class attendance
                if (($(mc).hasClass('modal-open')) && $(mc+' .tl_attendance').hasClass('active')) {
                	get_class_attendance();
                }

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });  
    }  else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();        
    }            
}

