function getTermsResults(res, allterms=false) {

    let data = res.data;

    $(mc+' .term_form').html($('#master_term_view .term_form').html()); //reset
    $(mc+' .term_form').hide();

    let html_str = '';                       
    for (let i = 0; i < data.length; i++) {
        let d = data[i];

        let monthly_perm = $('.perm_booking_items').length && (dayjs(d.term_start).endOf('month').format('YYYY-MM-DD') == d.term_finish);

        html_str += '<tr class="term_row">\
        					<td>'+d.term_name+'<div class="noshow"><span class="term_id">'+d.term_id+'</span><span class="term_term_name">'+d.term_name+'</span><span class="term_term_start">'+d.term_start+'</span><span class="term_term_finish">'+d.term_finish+'</span></div></td>\
        					<td>'+convert_date(d.term_start)+'</td>\
        					<td>'+convert_date(d.term_finish)+'</td>\
        					<td><ul>\
                                    '+($('#is_admin').val() && !monthly_perm ? '<li><a href="#" class="btn-edit edit_form edit_term">Edit</a></li>' : '')+'\
                                </ul></td>\
        				</tr>';
    }

    $(mc+' .terms_list tbody').html(html_str);

    if (allterms) {
    	$(mc+' .cur_terms_items').hide();
    	$(mc+' .terms_showcur').show();
    }
}

function show_term_holidays() {
    let term_start = parse_date($(mc+' .term_start').val());
    let term_finish = parse_date($(mc+' .term_finish').val());

    if ((isvalidDate(term_start)) && (isvalidDate(term_finish))) {

        $(mc+' .term_public_holidays').html('');

        let holidays_all = JSON.parse($(mc+' .public_holidays_all').html());

        let td_html = '';

        for(const key in holidays_all) {
            let title = key.substring(0, key.indexOf("hol")).toUpperCase()+ ' holidays:'; 
            if (td_html) {
            	td_html += '<br/><br/>';
            }
            td_html += '<b>'+title+'</b><br/>'

            let dates = holidays_all[key];

            let filteredDates = dates.filter(date => {
                const dayjsDate = dayjs(date);
                return dayjsDate.isAfter(dayjs(term_start).subtract(1, 'day')) && dayjsDate.isBefore(dayjs(term_finish).add(1, 'day'));
            });

            td_html += filteredDates.map(date => convert_date(date)).join('<br/>'); //present in readable format
        }

        $(mc+' .term_public_holidays').html(td_html);

    } else {
        $(mc+' .term_public_holidays').html('');
    }
}

