function saveTerm() {

    $('#loader-wrapper').show();

    //prepare the data
    let data ={
        term_id: $(mc+' .term_term_id').val(),
        term_name: $(mc+' .term_name').val(),
        term_start: parse_date($(mc+' .term_start').val()),
        term_finish: parse_date($(mc+' .term_finish').val()),
        location_id: $('#location_id').val(),
    };  

    let errors = [];
    //validations
    if (isEmpty(data.term_name)) {
        errors.push("Invalid "+$('#term_title').val()+" name");
    }

    if (!isvalidDate(data.term_start)) {
        errors.push("Invalid start date");
    }

    if (!isvalidDate(data.term_finish)) {
        errors.push("Invalid finish date");
    }

	if (!validator.isInt(data.location_id,{min: 1})) {
    	errors.push('Invalid location');
    } else if (data.location_id == 0) {
    	errors.push($('#ho_title').val()+' is not a valid location for the '+$('#term_title').val());
    }

    if (errors.length == 0) {
        $.ajax({
            type: 'POST',
            url: '/api/saveTerm',
            data: data,
            dataType: 'JSON'
        }).done(async function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

                get_api('getTerms');

                //refresh terms in classes
                let options = await get_client_options('class');
                getClasssOptions(options.class || '', options);

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });  
    }  else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();       
    }            
}

