function viewUser(user_id,goto_tab='') {

	reset_user_data();

    if (goto_tab) {
        $(mc+ ' .tl_'+goto_tab).click();
    } else {
    	if ($(mc+ ' .tl_user_edit').length) {
    		$(mc+ ' .tl_user_edit').click();
    	} else {
    		$(mc+ ' .tl_user_comments').click();
    	}
    }	

    $('#loader-wrapper').show();

    if (user_id) {
	    $.ajax({
	        type: 'GET',
	        url: '/api/getUsers',
	        data: {user_id: user_id},
	        dataType: 'JSON'
	    }).done(function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

                let res = response.success;

                if (res.data && res.data.length) {
                    let itemobj = res.data[0];

                    $('.modal_title_mc1').text(itemobj.username);

                    $(mc+' .usr_user_id').val(itemobj.user_id);
                    $(mc+' .usr_username').val(itemobj.username);
                    $(mc+' .usr_password').val('');
                    
                    if (itemobj.access.includes('p')) {$(mc+' .usr_pwdreset').prop("checked", true);}
                    if (itemobj.access.includes('c')) {$(mc+' .usr_instructor').prop("checked", true);}
                    if (itemobj.access.includes('l')) {$(mc+' .usr_login').prop("checked", true);}
                    if (itemobj.access.includes('a')) {$(mc+' .usr_admin').prop("checked", true);}
                    if (itemobj.access.includes('r')) {$(mc+' .usr_reports').prop("checked", true);}
                    if (itemobj.access.includes('u')) {$(mc+' .usr_users').prop("checked", true);}

                    $(mc+' .usr_phone').val(itemobj.phone);
                    $(mc+' .usr_email').val(itemobj.email);
                    $(mc+' .usr_location_id').val(itemobj.location_id);
                    $(mc+' .usr_comment').val(itemobj.user_comment);
                    $(mc+' .usr_business').val(itemobj.business);
                    
                    if (itemobj.payrate) {
                        for(const key in itemobj.payrate) {
                            $(mc+' .usr_payrates[name="'+key+'"]').val(itemobj.payrate[key])
                        }
                    }
                    
                    if (itemobj.username == 'apiuser') {
                        $(mc+' .usr_key_tr').show();
                        $(mc+' .usr_pwd_tr').hide();
                        $(mc+' .btn_saveUser').hide();
                        $(mc+' .usr_key_tr .usr_apikey').text(itemobj.password);
                    } else {
                        $(mc+' .usr_key_tr').hide();
                        $(mc+' .usr_pwd_tr').show();
                        $(mc+' .btn_saveUser').show();
                        $(mc+' .usr_key_tr .usr_apikey').text('');
                    }

	                if (validator.isEmail(itemobj.email)) {
	                	$(mc+' .usr_email_email').show();
	                	$(mc+' .usr_email_email').attr('href', 'mailto:'+itemobj.email);
	                }

	                if (isMobile(itemobj.phone.replace(' ',''),$('#locale').val())) {
	                	$(mc+' .usr_phone_sms, '+mc+' .usr_sms_hist').show();
	                	$(mc+' .se_det').text(itemobj.user_id+'~'+itemobj.username+'~'+itemobj.phone);
	                }

                    //comments - start
                    let c_html_str = '';
                    for (let i = 0; i < res.comments.length; i++) {
                        let d = res.comments[i];
                        
                        let archived = d.username && isvalidDate(d.close);

                        c_html_str += '<tr'+(d.close == '0000-00-00' ? '' : ' class="user_comment_archived noshow"')+'>\
                                            <td>'+convert_date(d.open)+'<span class="noshow comment_id">'+d.comment_id+'</span></td>\
                                            '+($('.comment_followup_items').length ? ('<td class="followup">'+(d.followup != '0000-00-00' ? convert_date(d.followup) : '')+'</td>') : '')+'\
                                            <td class="comment_cur">'+(d.opener ? 'Created by: '+d.opener+'<br>' : '')+d.comment_data.replace(/\r?\n|\r/g,"<br>")+(archived ? '<br>Archived by: '+d.username+' '+convert_date(d.close) : '')+'<div class="comment_data noshow">'+d.comment_data+'</div></td>\
                                            <td><ul>\
                                                '+($('#is_admin_users').val() && d.close == '0000-00-00' ? '<li><a href="#" class="btn-edit update_user_comment">Update</a></li>' : '')+'\
                                                '+($('#is_admin_users').val() && d.close == '0000-00-00' ? '<li><a href="#" class="btn-edit archive_user_comment">Archive</a></li>' : '')+'\
                                                '+($('#is_admin_users').val() && d.close == '0000-00-00' ? '<li><a href="#" class="btn-edit overwrite_user_comment overwrite_comment noshow">Overwrite</a></li>' : '')+'\
                                                '+($('#is_admin_users').val() && archived ? '<li><a href="#" class="btn-edit delete_user_comment">Delete</a></li>' : '')+'\
                                            </ul></td>\
                                        </tr>';
                    }
                    $(mc+' .user_comments_list tbody').html(c_html_str);
                    //comments - end

                    //files - start
                    let f_html_str = '';
                    for (let i = 0; i < res.files.length; i++) {
                        let d = res.files[i];
                        
                        f_html_str += '<tr>\
                                  <td>'+convert_date(d.date)+'</td>\
                                  <td><a class="a_file primary" href="#" data-intrac="api/getFile?filename='+d.s3_filename+'&location_id='+$('#location_id').val()+'&user_id='+itemobj.user_id+'" target="_blank">'+d.filename+'</a><span class="file_id noshow">'+d.file_id+'</span></td>\
                                  <td>'+(d.opener || '')+'</td>\
                                  <td><ul>\
                                            '+($('#is_admin_users').val() ? '<a href="#" class="btn-edit rename_user_file">Rename</a>' : '')+'\
                                            '+($('#is_admin_users').val() ? '<a href="#" class="btn-edit delete_user_file">Delete</a>' : '')+'\
                                        </ul></td>\
                                </tr>';
                    }
                    $(mc+' .user_files_list tbody').html(f_html_str);
                    //files - end

                    //get image if exists
                    if ($(mc+' .user_image_tr').hasClass('show_images')) {

                        $(mc+' .user_image_tr').show();
                        
                        $(mc+' .user_image_tr .display_img').hide();

                        get_user_image(itemobj.user_id);
                    }
                }
                
            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });
    } else {
        $('#loader-wrapper').hide();
    }
}

function get_user_image(user_id) {  

    let querydata = {user_id: user_id};

    //resets related to user images
    $(mc+' .user_image_id').text('');
    $(mc+' .user_img_buttons').addClass('noshow');
    $(mc+' .image_upload_div .display_img').attr('src','/images/avatar.png').hide();
    $(mc+' .user_img_upload_options').removeClass('noshow');

    $.ajax({
        type: 'GET',
        url: '/api/getImages',
        data: querydata,
        dataType: 'JSON'
    }).done(function( response ) {

        if (response.success != undefined) {

            $('#loader-wrapper').hide();

            let res = response.success;

            if (res.data[0]) {
                $(mc+' .image_upload_div .display_img').attr('src', 'data:image/png;base64,'+res.data[0].image_data).show();

                $(mc+' .user_image_id').text(res.data[0].image_id);
                $(mc+' .user_img_buttons').removeClass('noshow');
                $(mc+' .user_img_upload_options').addClass('noshow');;
            }

        } else if (response.redirect != undefined) {
            mini_login_wizard(response.redirect); //session timeout case
        } else {    
            set_side_error(response.error.join("<br>"));
            $('#loader-wrapper').hide();
        }

    }).fail( function(xhr, textStatus, errorThrown) {
        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
        $('#loader-wrapper').hide();
    });    
}

