function reset_user_comment_data() {
	$(mc+' .user_comment_id').val('');
	$(mc+' .user_comment_cur').html('');
	$(mc+' .user_comment_data').val('');
	$(mc+' .btn_saveUserComment').prop('dataset').intrac_overwrite = '';
	let quill = Quill.find($(mc+' .user_comment_data')[0]);
	if (quill) {
		quill.clipboard.dangerouslyPasteHTML('');
		quill.blur();
	} else {
		quill = quill_init(mc+' .user_comment_data', 'basic');	
	}
}

function update_user_comment(el) {
	$(mc+' .user_comment_form').removeClass('noshow_imp');
	$(mc+' .user_comment_id').val($(el).find('.comment_id').text());
	$(mc+' .user_comment_cur').html($(el).find('.comment_cur').html());
    $(mc+' .new-modal-content').animate({
        scrollTop: $(mc+' .user_comment_form').position().top + $(mc+' .new-modal-content').scrollTop() - $(mc + ' .modal-header').outerHeight()
    }, 500);
    if ($(mc+' .btn_saveUserComment').prop('dataset').intrac_overwrite) {
    	let quill = Quill.find($(mc+' .user_comment_data')[0]);
    	quill.clipboard.dangerouslyPasteHTML($(el).find('.comment_data').html().replace(/\r?\n|\r/g,"<br>"));
    	quill.blur();
    }
    $(mc+' .user_followup').val($(el).find('.followup').text());
}

function save_user_comment() {

    $('#loader-wrapper').show();

    //prepare the data

    let data ={
        comment_id: $(mc+' .user_comment_id').val(),
        comment_user_id: $(mc+' .user_edit_tab .usr_user_id').val(),
        comment_data: sanitiseQuillHTML($(mc+' .user_comment_data .ql-editor').html()),
        location_id: $('#location_id').val()
    };

    if (data.comment_data == '<p><br></p>') {
    	data.comment_data = '';
    }

    if (data.comment_id && $(mc+' .btn_saveUserComment').prop('dataset').intrac_overwrite) {
    	data.action = 'overwrite';
    }

    let followup = parse_date($(mc+' .user_followup').val() || '');
    if (isvalidDate(followup)) {
    	data.followup = followup;
    }

    let errors = [];
    //validations

    if (isEmpty(data.comment_data)) {
        errors.push('Please enter a comment and re-try');
    }

    if (!isEmpty($(mc+' .user_followup').val() || '') && !data.followup) {
    	errors.push('Please enter a valid follow up date');
    }

    if (errors.length == 0) {
        $.ajax({
            type: 'POST',
            url: '/api/saveComment',
            data: data,
            dataType: 'JSON'
        }).done(function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

                viewUser(data.comment_user_id, 'user_comments');

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });  
    }  else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();        
    }            
}

