function viewProduct(product_id, silent=false) {

    if (!silent) {
	    if (!$(mc3).hasClass('modal-open')) {
	        $('.modal_o_products:first').click();   
	    }
        reset_product_data();
        $(mc3+ ' .tl_prod_edit').click();

        $('#loader-wrapper').show();
    }

    if (product_id) {
        $.ajax({
            type: 'GET',
            url: '/api/getProducts',
            data: {product_id: product_id},
            dataType: 'JSON'
        }).done(function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

                let res = response.success;

                //data
                let data = res.data;

                if (data.length == 1) {
                    let itemobj = data[0];

                    $(mc3+' .prod_product_id').val(itemobj.product_id);
                    $(mc3+' .prod_inventory').text(itemobj.inventory);
                    
                    $('.modal_title_mc3').text((itemobj.category ? itemobj.category+': ' : '')+itemobj.product_name);

                    if (itemobj.unit_cost == undefined) {
                        $(mc3+' .prod_unitcost_tr').hide();
                    } else {
                        $(mc3+' .prod_unitcost').text(numberformatccy(itemobj.unit_cost));
                        $(mc3+' .prod_unitcost_tr').show();
                    }

                    $(mc3+' .prod_category').val(itemobj.category);
                    $(mc3+' .prod_product_name').val(itemobj.product_name);
                    $(mc3+' .prod_barcode').val(itemobj.barcode);
                    $(mc3+' .prod_restock').val(itemobj.restock);
                    $(mc3+' .prod_price').val(itemobj.price);
                    $(mc3+' .prod_member_price').val(itemobj.member_price);

                    if (itemobj.display == 1) {$(mc3+' .prod_display').prop("checked", true);}
                    if (itemobj.location_id == 0) {$(mc3+' .prod_ho').prop("checked", true);}

                    if (itemobj.product_fixed) {
                        $(mc3+' .prod_display_tr').hide();
                    } else {
                        $(mc3+' .prod_display_tr').show();
                    }

                    //get image if exists
                    if ($(mc3+' .prod_image_tr').hasClass('show_images')) {

                        $(mc3+' .prod_image_tr').show();
                        
                        $(mc3+' .prod_image_tr .display_img').hide();

                        get_prod_image(itemobj.product_id);
                    }

                }

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        }); 
    } else {
        $('#loader-wrapper').hide();
    } 

}

