function get_stock_levels() {

    $('#loader-wrapper').show();

    $(mc3+' .stock_levels_tab').html($('#master_product_view .stock_levels_tab').html());

    $.ajax({
        type: 'GET',
        url: '/api/getProducts',
        dataType: 'JSON'
    }).done(function( response ) {

        if (response.success != undefined) {

            $('#loader-wrapper').hide();

            let res = response.success;

            //data
            let data = res.data;

            let tr_html_str = '';

            let categories = [];
            let total = 0;

            for (let i = 0; i < data.length; i++) {

                if ((data[i].inventory != 0) || (data[i].restock != 0)) {
                    if (!categories.includes(data[i].category)){ //new category
                        tr_html_str += '<tr>\
                                            <td colspan="4"><b>'+data[i].category+'</b></td>\
                                        </tr>';
                        categories.push(data[i].category);
                    }                

                    tr_html_str += '<tr>\
                                        <td>'+data[i].product_name+'</td>\
                                        <td class="align-right '+(data[i].inventory<data[i].restock?'fail':'')+'">'+data[i].inventory+'</td>\
                                        <td class="align-right">'+data[i].restock+'</td>\
                                        <td class="align-right">'+(data[i].unit_cost?numberformatccy(data[i].unit_cost):'')+'</td>\
                                    </tr>';

                    if ((data[i].unit_cost) && (data[i].inventory>0)) {
                        total += data[i].inventory*data[i].unit_cost;                 
                    }
                }
            }

            //total
            tr_html_str += '<tr>\
                                <td><b>Stock on hand</b></td>\
                                <td></td>\
                                <td></td>\
                                <td class="align-right"><b>'+numberformatccy(total)+'</b></td>\
                            </tr>';

            $(mc3+' .stock_levels_list tbody').html(tr_html_str);
            
        } else if (response.redirect != undefined) {
            mini_login_wizard(response.redirect); //session timeout case
        } else {    
            set_side_error(response.error.join("<br>"));
            $('#loader-wrapper').hide();
        }

    }).fail( function(xhr, textStatus, errorThrown) {
        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
        $('#loader-wrapper').hide();
    });       
}

function get_stock_history(mode='product') {

    $('#loader-wrapper').show();
    
    let querydata = {};
    
    if (mode == 'product') {
        querydata.product_id = $(mc3+' .prod_product_id').val();
        querydata.incl_stocktakes = 'true';
    }

    if (mode == 'month') {
        querydata.month = $(mc3+' .stock_delvr_month').val();
    }

    if (mode == 'stocktake') {
        querydata.month = $(mc3+' .stock_adj_month').val();
        querydata.incl_stocktakes = 'only';
    }

    $.ajax({
        type: 'GET',
        url: '/api/getStocks',
        data: querydata,
        dataType: 'JSON'
    }).done(function( response ) {

        if (response.success != undefined) {

            $('#loader-wrapper').hide();

            let res = response.success;

            //data
            let data = res.data;

            let tr_html_str = '';


            for (let i = 0; i < data.length; i++) {

                let del_ = false;

                if ((data[i].stock_comment != 'Stocktakes') && $('#is_admin').val()) {
                    del_ = true;
                }

                if (mode == 'product') {
                    tr_html_str += '<tr class="stock_row">\
                                        <td>'+convert_date(data[i].day)+'<span class="stock_id noshow">'+data[i].stock_id+'</span></td>\
                                        <td class="align-right">'+data[i].quantity+'</td>\
                                        <td class="align-right">'+numberformatccy(data[i].cost)+'</td>\
                                        <td>'+data[i].stock_comment+'</td>\
                                        <td>'+data[i].username+'</td>\
			                            <td><ul>\
			                                    '+(del_ ? '<li><a href="#" class="btn-edit prodstock_delete">Delete</a></li>' : '')+'\
			                                </ul></td>\
                                    </tr>';
                } else {
                    tr_html_str += '<tr class="stock_row">\
                                        <td>'+convert_date(data[i].day)+'<span class="stock_id noshow">'+data[i].stock_id+'</span></td>\
                                        <td>'+data[i].product_name+'</td>\
                                        <td class="align-right">'+data[i].quantity+'</td>\
                                        <td class="align-right">'+numberformatccy(data[i].cost)+'</td>\
                                        <td>'+data[i].username+'</td>\
			                            <td><ul>\
			                                    '+(del_ ? '<li><a href="#" class="btn-edit prodstock_delete">Delete</a></li>' : '')+'\
			                                </ul></td>\
                                    </tr>';                        
                }

            }                

            if (mode == 'product') {
                $(mc3+' .stock_hist_list tbody').html(tr_html_str);    
            } else if (mode == 'month') {
                $(mc3+' .stock_delvr_list tbody').html(tr_html_str);    
            } else if (mode == 'stocktake') {
                $(mc3+' .stock_adj_list tbody').html(tr_html_str);    
            }
            
        } else if (response.redirect != undefined) {
            mini_login_wizard(response.redirect); //session timeout case
        } else {    
            set_side_error(response.error.join("<br>"));
            $('#loader-wrapper').hide();
        }

    }).fail( function(xhr, textStatus, errorThrown) {
        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
        $('#loader-wrapper').hide();
    });       
}

