function edit_passtype(passtype_id) {

    $('#loader-wrapper').show();

    if (passtype_id) {
        $.ajax({
            type: 'GET',
            url: '/api/getPasstypes',
            data: {passtype_id: passtype_id},
            dataType: 'JSON'
        }).done(function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

                let res = response.success;

                if (res.data && res.data.length) {
                    let itemobj = res.data[0];

                    //data
                    $(mc+' .ptyp_passtype_id').val(itemobj.passtype_id);
                    $(mc+' .passtype_name').val(itemobj.passtype_name);
                    $('.modal_title_mc1').text(itemobj.passtype_name);
                    $(mc+' .passtype_description').val(itemobj.passtype_description);
                    if (itemobj.features.includes('f')) {$(mc+' .features_family').prop("checked", true);}
                    $(mc+' .ptyp_level_id').val(itemobj.level_id).change();
                    $(mc+' .ptyp_user_id').val(itemobj.user_id);
                    $(mc+' .ptyp_number').val(itemobj.number);
                    $(mc+' .ptyp_share').val(itemobj.share);
                    $(mc+' .ptyp_cost').val(itemobj.cost);
                    $(mc+' .ptyp_expiry').val(itemobj.expiry);
                    if (itemobj.monthly == 1) {$(mc+' .ptyp_monthly').prop("checked", true).change();}
                    if (itemobj.display == 1) {$(mc+' .ptyp_display').prop("checked", true);}

                    $(mc+' .ptyp_features').prop('disabled',true);
                    $(mc+' .ptyp_level_id').prop('disabled',true);
                    $(mc+' .ptyp_user_id').prop('disabled',true);
                    $(mc+' .ptyp_number').prop('disabled',true);
                    $(mc+' .ptyp_share').prop('disabled',true);
                    $(mc+' .ptyp_monthly').prop('disabled',true);

	                //restrictions
	                let restr_str = '';
	                if (itemobj.restrictions) {
	                    let restrictions = itemobj.restrictions;
	                    for (let i = 0; i < restrictions.length; i++) {
	                        let restriction_name = '';

	                        if (restrictions[i].restriction_type == 1) {
	                            restriction_name = 'Gender';
	                        } else if (restrictions[i].restriction_type == 2) {
	                            restriction_name = 'Min Age';
	                        } else if (restrictions[i].restriction_type == 3) {
	                            restriction_name = 'Max Age';
	                        } else if (restrictions[i].restriction_type == 4) {
                                restriction_name = 'Level';
                            }

	                        let r = restrictions[i];

	                        restr_str += '<tr class="ptyp_restr_item">\
	                                            <td>\
	                                                <span class="restriction_id noshow">'+r.restriction_id+'</span>\
	                                                <span class="restriction_type noshow">'+r.restriction_type+'</span>\
	                                                <span class="restriction_value noshow">'+r.value+'</span>\
	                                                '+restriction_name;
	                                restr_str += '</td>';

	                                restr_str += '<td>'+(restrictions[i].restriction_type == 4 ? r.level_names : r.value)+'</td>';

	                                restr_str += '<td>\
	                                                <ul>\
	                                                    <li><a href="#" class="btn-edit ptyp_restr_update">Edit</a></li>\
	                                                    <li><a href="#" class="btn-edit ptyp_restr_delete">Delete</a></li>\
	                                                </ul>\
	                                            </td>';

	                        restr_str += '</tr>';
	                    }                                    
	                }
	                $(mc+' .ptyp_restrictions tbody').html(restr_str);
	                $(mc+' .ptyp_restrictions_div').removeClass('noshow');
                }
                
            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });
    } else {
        $('#loader-wrapper').hide();
    }
}


function savePasstype() {

    $('#loader-wrapper').show();

    //prepare the data
    let data ={
        passtype_id: $(mc+' .ptyp_passtype_id').val(),
        passtype_name: $(mc+' .passtype_name').val(),
        passtype_description: $(mc+' .passtype_description').val(),
        features: '',
        level_id: $(mc+' .ptyp_level_id').val(),
        user_id: $(mc+' .ptyp_user_id').val(),
        number: $(mc+' .ptyp_number').val(),
        share: $(mc+' .ptyp_share').val(),
        cost: $(mc+' .ptyp_cost').val(),
        expiry: $(mc+' .ptyp_expiry').val(),
        monthly: $(mc+' .ptyp_monthly').is(":checked") ? 1 : 0,
        display: $(mc+' .ptyp_display').is(":checked") ? 1 : 0,
        location_id: $('#location_id').val()
    };

    //features
    $(mc+' .ptyp_features').each(function () {
        if (this.checked) {
            data.features += $(this).val();
        }
    });

    let level_type = $(mc+' .ptyp_level_id option:selected').prop('dataset').intrac;

    let errors = [];
    //validations
    if (isEmpty(data.passtype_name)) {
        errors.push("Invalid name");
    }

	if (!validator.isFloat(data.cost,{min: 0})) {
        errors.push('Invalid cost');
    } 

    if (!validator.isInt(data.number,{min: 0, max: 127})) {
        errors.push('Invalid number. The maximum number of visits is 127. Please use zero for unlimited visits within the expiry period');
    }

    if (!validator.isInt(data.expiry,{min: 0, max: 1100})) {
        errors.push('Invalid expiry. The maximum expiry is 1100 days. Please use zero for no expiry');
    }

    if ((data.monthly == 1) && (data.features.includes('f'))) {
        errors.push('Monthly option is not allowed for family '+($('#pass_title').val() == 'pass' ? 'passes' : $('#pass_title').val()+'s'));
    }

    if ((data.level_id > 0) && (data.features.includes('f'))) {
        errors.push('Levels are not allowed for family '+($('#pass_title').val() == 'pass' ? 'passes' : $('#pass_title').val()+'s'));
    }

    if ((data.monthly == 1) && (data.level_id > 0) && (level_type != 4)) {
        errors.push('Monthly option is not allowed for this level');
    }

    if (errors.length == 0) {

        $.ajax({
            type: 'POST',
            url: '/api/savePasstype',
            data: data,
            dataType: 'JSON'
        }).done(function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

                get_api('getPasstypes');

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });
    } else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();        
    }  
          
}

