function get_passs_report(mode,rawcsv='') {

    $('#loader-wrapper').show();

    $(mc+' .passreport_list').html('');

    let querydata = {mode: mode, passtype_id: $(mc+' .prep_passtype').val(), orderby: $(mc+' .prep_orderby').val()};

    //send hold as separate parameter
    let prep_expiry = $(mc+' .prep_expiry').val()
    if (prep_expiry == 'hold') {
        querydata.hold = 'yes';
    } else if (prep_expiry) {
        querydata.expiry = prep_expiry;
    }

    let month = $(mc+' .prep_month').val();
    if ((month) && (isvalidDate(month+'-01'))) {
        querydata.month = month+'-01';
    }

    let title = (mode == 'unused') ? 'Unused Passes Report' : 'Pass Reports';

    $.ajax({
        type: 'GET',
        url: '/api/getPasss',
        data: querydata,
        dataType: 'JSON'
    }).done(function( response ) {

        if (response.success != undefined) {

            $('#loader-wrapper').hide();

            let res = response.success;

            //data
            let data = res.data;

            let html_str = '';

            let last_col_hdr = 'Cost';
            if (mode == 'unused') {
                last_col_hdr = 'Remaining';
            }
            /* else if (month) {
                last_col_hdr = 'Cost';
            }*/

            //header
            html_str += '<thead><tr>\
                            <th>Customer Name</th>\
                            <th>Bought</th>\
                            <th>Expires</th>\
                            <th>'+toTitleCase($('#pass_title').val())+'</th>\
                            <th class="align-right">'+last_col_hdr+'</th>\
                        </tr></thead><tbody>';

            //data            
            for (let i = 0; i < data.length; i++) {

                let last_col_data = numberformatccy(data[i].cost)+(data[i].monthly == 1 ? '/month' : '');
                if (mode == 'unused') {
                    last_col_data = data[i].remaining;
                } 
                /*else if (month) {
                    last_col_data = numberformatccy(data[i].amount);
                }*/

                html_str += '<tr>\
                                <td class="cursor primary view_customer"><span class="customer_id noshow">'+data[i].customer_id+'</span><span class="parent_id noshow">'+data[i].parent_id+'</span>'+data[i].first_name+' '+data[i].last_name+(data[i].monthly == 1 && data[i].direct == '' ? '*' : '')+'<span class="se_det noshow">'+(data[i].parent_id > 0 ? data[i].parent_id : data[i].customer_id)+'~'+data[i].first_name+' '+data[i].last_name+'~'+data[i].phone+'~'+data[i].email+'~'+data[i].altemail+'</span></td>\
                                <td>'+convert_date(data[i].bought)+'</td>\
                                <td>'+(data[i].expires != '2050-01-01' ? convert_date(data[i].expires) : '')+'</td>\
                                <td>'+data[i].passtype_name+(data[i].hold != '0000-00-00' ? ' On hold since '+convert_date(data[i].hold) : '')+'</td>\
                                <td class="align-right">'+last_col_data+'</td>\
                            </tr>';
            }                                                  

            //totals row
            if ((mode == 'unused') && (data.length) && (res.unused_total != undefined) && (res.unused_total_cost != undefined)) {
                html_str += '<tr>\
                                <td><b>Total</b></td>\
                                <td></td>\
                                <td></td>\
                                <td class="align-right"><b>'+numberformatccy(res.unused_total_cost)+'</b></td>\
                                <td class="align-right"><b>'+res.unused_total+'</b></td>\
                            </tr>';               
            }

            if (!data.length) {               
                html_str = '<tr>\
                                <td colspan="5" class="align-center"><div class="padding_top_sm padding_btm_sm">No data to show<div></td>\
                            </tr>';
            }

            html_str += '</tbody>';

            $(mc+' .passreport_list').html(html_str);
            
            if (rawcsv) {
                if (data.length) {
                    let dataArry = [];
                    for (let i = 0; i < data.length; i++) {
                        dataArry.push({
                            first_name: data[i].first_name,
                            last_name: data[i].last_name,
                            pass: data[i].passtype_name,
                            username: (data[i].username) ? data[i].username : '',
                            bought: data[i].bought,
                            expires: data[i].expires,
                            remaining: data[i].remaining,
                            number: data[i].number,
                            cost: numberformatccy(data[i].cost),
                            value: (data[i].number) ? numberformatccy((data[i].cost*data[i].remaining)/data[i].number) : '',
                            card: data[i].card,
                            dob: data[i].dob,
                            gender: data[i].gender,
                            direct: data[i].direct,
                            email: data[i].email,
                            phone: data[i].phone,
                            child: data[i].child || ''
                        });
                    }
                    downloadCSV(dataArry);
                }
            }

        } else if (response.redirect != undefined) {
            mini_login_wizard(response.redirect); //session timeout case
        } else {    
            set_side_error(response.error.join("<br>"));
            $('#loader-wrapper').hide();
        }

    }).fail( function(xhr, textStatus, errorThrown) {
        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
        $('#loader-wrapper').hide();
    });       
}

function savePass() {

    $('#loader-wrapper').show();

    //prepare the data
    let data ={
        customer_id: ($(mc2+' input:radio[name="cpass_customer_id"]:checked').length) ? $(mc2+' input:radio[name="cpass_customer_id"]:checked').val() : '',
        passtype_id: $(mc2+' .cpass_passtype_id').val() || '',
        cost: $(mc2+' .cpass_cost').val(),
        location_id: $('#location_id').val()
    };    

    //console.log(data);

    let errors = [];
    //validations

    if (errors.length == 0) {

        $.ajax({
            type: 'POST',
            url: '/api/savePass',
            data: data,
            dataType: 'JSON'
        }).done(async function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

                //go to account or product purchase page
                if (response.success == 'success') {
                    viewCustomer(data.customer_id, 'account'); //normal customer
                } else if (response.success.parent_id) {
                    viewCustomer(response.success.parent_id, 'account'); //child customer -> parent account
                } else {
                    await viewCustomer(response.success.customer_id, 'passes'); //refresh customer too, this is receipt customer_id. Using await as cust data required for prod purchase reset during viewCustomer
                    add_cust_prod_purchase(response.success);
                }

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });
    } else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();        
    }         
}

function updatePass(pass_id,action='') {

    $('#loader-wrapper').show();

    //prepare the data
    let data ={
        customer_id: ($(mc2+' input:radio[name="cpass_customer_id"]:checked').length) ? $(mc2+' input:radio[name="cpass_customer_id"]:checked').val() : '',
        pass_id: pass_id,
        action: action
    };    

    if (action == 'expires') {
        data.expires = parse_date($(mc2+' .cpass_alter_div .cpass_exp_expires').val());
    } else if (action == 'switch') {
        data.switch_passtype_id = $(mc2+' .cpass_alter_div .cpass_switch_passtype_id').val()
    }

    if (action == 'deduct') {
    	data.location_id = $('#location_id').val();
    }

    //console.log(data);

    let errors = [];
    //validations

    if (action == 'expires') {
        data.expires = parse_date($(mc2+' .cpass_alter_div .cpass_exp_expires').val());
		if (!isvalidDate(data.expires)) {
            errors.push("Invalid expiry date");
        }        
    } else if (action == 'switch') {
        if (!validator.isInt(data.switch_passtype_id,{min: 1})) {
            errors.push("Invalid switch option selected");
        }
    }


    if (errors.length == 0) {

        $.ajax({
            type: 'POST',
            url: '/api/updatePass',
            data: data,
            dataType: 'JSON'
        }).done(function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

                set_side_error(toTitleCase($('#pass_title').val())+' action completed successfully', 'green')

                //refresh data
                viewCustomer($(mc2+' .cust_edit_tab .cust_customer_id').val(), 'passes');               

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });
    } else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();        
    }       
}

