function get_switch_passtypes(el) {
    $('#loader-wrapper').show();

    $(mc2+' .cpass_alter_div').remove();

    let pass_details = $(el).find('.pass_details').text();

    let details = pass_details.split('~');

    let querydata = {level_id: details[1], level_type: details[2]};

    if (querydata.level_type != 1) {
        querydata.number = details[3];
        querydata.share = details[4];
    }

    $.ajax({
        type: 'GET',
        url: '/api/getPasstypes',
        data: querydata,
        dataType: 'JSON'
    }).done(function( response ) {

        if (response.success != undefined) {

            $('#loader-wrapper').hide();

            let res = response.success;

            //data
            let data = res.data;

            $(el).find('.empty_div:first').after('<div class="cpass_alter_div flex_new_row">'+$('#master_customer_view .cpass_switch_view').html()+'</div>');

            let opts_str = '';
            for (let i = 0; i < data.length; i++) {
                if (details[0] != data[i].passtype_id) {
                    opts_str += '<option value="'+data[i].passtype_id+'">'+data[i].passtype_name+'</option>';
                }
            }

            if (opts_str) {
                $(el).find('.cpass_switch_passtype_id').html(opts_str);
            } else {
                $(el).find('.cpass_switch_passtype_id').html('<option value="0"></option>');
                $(el).find('.cpass_switch_passtype_id_div').hide();
                $(el).find('.cpass_switch_noids').show();
                $(el).find('.cpassswitchbtn_save').hide();
            }

        } else if (response.redirect != undefined) {
            mini_login_wizard(response.redirect); //session timeout case
        } else {    
            set_side_error(response.error.join("<br>"));
            $('#loader-wrapper').hide();
        }

    }).fail( function(xhr, textStatus, errorThrown) {
        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
        $('#loader-wrapper').hide();
    });    
}

