function redeem_gift() {
    $('#loader-wrapper').show();

    let g_customer_id = $(mc+' .gift_customer').prop('dataset').intrac_customer_id;
    let parent_id = $(mc+' .gift_customer').prop('dataset').intrac_parent_id;

    let data = {
    	voucher_id: $(mc+' .gift_voucher_id').val().trim(),
    	code: $(mc+' .gift_code').val().trim(),
    	customer_id: parent_id > 0 ? parent_id : g_customer_id,
    	g_customer_id: g_customer_id,
    	location_id: $('#location_id').val()
    }

    let errors = [];
    //validations

    if (!data.voucher_id) {
    	errors.push('Please enter the voucher number from your gift certificate and try again');
    }

    if (!data.code) {
    	errors.push('Please enter the activation code from your gift certificate and try again');
    }

    if (errors.length == 0) {
        $.ajax({
            type: 'POST',
            url: '/api/redeemGiftAdmin',
            data: data,
            dataType: 'JSON'
        }).done(async function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();
                
                set_side_error(response.success, 'green', 'keep');

                $(mc+' .tl_gift_redeem').click();

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });  
    }  else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();
    }    
}

