function getRostersResults(res) {

    let data = res.data;

    $(mc+' .rosters_form').html($('#master_roster_view .rosters_form').html()); //reset. not resetting the entire tab to retain roster_date
    $(mc+' .rosters_form').hide();

    let html_str = '';
    for (let i = 0; i < data.length; i++) {
        let d = data[i];
        html_str += '<tr class="roster_row">\
                            <td class="na_instructor">'+d.username+'<span class="schedule_id noshow">'+d.schedule_id+'</span><span class="user_id noshow">'+d.primary_user_id+'</span></td>\
                            <td>'+d.roster_type+'</td>\
                            <td>'+convert_date_time(d.schedule_start, 'h:mma')+'</td>\
                            <td>'+convert_date_time(d.schedule_finish, 'h:mma')+'</td>\
                            <td><ul>\
                                    '+($('.roster_mgmt_items').length && ($('#is_admin').val() || ($(mc+' .roster_functions option[value="'+d.functions+'"]').length)) ? '<li><a href="#" class="btn-edit edit_form edit_roster" data-intrac="'+d.schedule_id+'">Edit</a></li>' : '')+'\
                                    '+($('.roster_mgmt_items').length && ($('#is_admin').val() || ($(mc+' .roster_functions option[value="'+d.functions+'"]').length)) ? '<li><a href="#" class="btn-edit delete_roster">Delete</a></li>' : '')+'\
                                </ul></td>\
                        </tr>';

    }

    $(mc+' .rosters_list tbody').html(html_str);

    //options
    let options = res.options;

    if (options.week_base && options.week_start) {
        $(mc+' .roster_week_base').val(options.week_base);
        $(mc+' .roster_week_base_span').text(convert_date(options.week_base,'ddd D MMM YYYY')+' - '+dayjs(options.week_base).add(6, 'day').format('ddd D MMM YYYY'));
        $(mc+' .roster_week_start').val(options.week_start);
        $(mc+' .roster_week_start_span').text(convert_date(options.week_start,'ddd D MMM YYYY'));
    }

    if ($('#add_instr_roster').is(":visible")) {
    	$(mc+' .rosters_tab .add_form').click();
    }

    if ($(mc+' .rosters_tab .add_form').hasClass('from_btn_add_shift')) {
    	$(mc+' .rosters_tab .add_form').removeClass('from_btn_add_shift').click();
    }
}

