        schedule_start: parse_time($(mc+' .roster_start').val()),
        schedule_finish: parse_time($(mc+' .roster_finish').val()),
        schedule_comment: $(mc+' .roster_comment').val(),
        repeat_until: $(mc+' .roster_repeat_until').val() ? parse_date($(mc+' .roster_repeat_until').val()) : '',
