function save_roster_week() {

    $('#loader-wrapper').show();

    let data = {
        location_id: $('#location_id').val(),
        week_base: $(mc+' .roster_week_base').val(),
        week_start: $(mc+' .roster_week_start').val(),
        week_finish: parse_date($(mc+' .roster_week_finish').val()),
        action: 'week',
        schedule_ids: []
    }

    $(mc+' .roster_week_sched').each(function () {
        if (this.checked) {
            data.schedule_ids.push($(this).val());
        }
    });    

    let errors = [];
    //validations

    if (!data.schedule_ids.length) {
    	errors.push('Please select one or more items from the roster list above and re-try')
    }

    if (!isvalidDate(data.week_finish)) {
        errors.push("Invalid finish date");
    }

    if (errors.length == 0) {
        $.ajax({
            type: 'POST',
            url: '/api/updateRoster',
            data: data,
            dataType: 'JSON'
        }).done(async function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();
                //show success message
                set_side_error('Weekly roster updated succesfully', 'green');

                //refresh data
                $(mc+' .tl_rosters').click();
                
            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });  
    }  else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();
    } 
}

