function get_loc_hours() {

    $('#loader-wrapper').show();

    $(mc+' .hours_form').html($('#master_location_view .hours_form').html()); //reset. not resetting the entire tab to retain hours_location_id

    let querydata = {location_id: $(mc+ ' .hours_location_id').val()};

    $.ajax({
        type: 'GET',
        url: '/api/getLocations',
        data: querydata,
        dataType: 'JSON'
    }).done(function( response ) {

        if (response.success != undefined) {

            $('#loader-wrapper').hide();

            let res = response.success;

            //data
            let data = res.data;

            if (data.length) {
                let d = data[0].hours;

                let hours_week = [];
                let hours_weekend = [];

                for (let i = 0; i < d.length; i++) {
                    if (d[i].hours_day == 'Mon') {
                        hours_week.push(d[i]);
                    } else if (d[i].hours_day == 'Sat') {
                        hours_weekend.push(d[i]);
                    }
                }

                let weekstart = '';
                let peakstart = '';
                let weekfinish = '';
                let weekrate = 0;
                let peakrate = 0;
                let weekendstart = '';
                let weekendfinish = '';
                let weekendrate = 0;

                if (hours_week.length) { 
                    weekstart = hours_week[0].hours_start;
                    weekfinish = hours_week[0].hours_finish;
                    weekrate = hours_week[0].rate;
                }

                if (hours_week.length > 1) { //peak rates exist
                    if (dayjs(hours_week[1].hours_start,'HH:mm:ss').isAfter(dayjs(weekstart,'HH:mm:ss'))) { //right order
                        peakstart = hours_week[1].hours_start;
                        peakrate = hours_week[1].rate;
                        weekfinish = hours_week[1].hours_finish;
                    } else { //out of order
                        peakstart = weekstart;
                        peakrate = weekrate;
                        weekstart = hours_week[1].hours_start;
                        weekrate = hours_week[1].rate;
                    }
                }

                if (hours_weekend.length) {
                    weekendstart = hours_weekend[0].hours_start;
                    weekendfinish = hours_weekend[0].hours_finish;
                    weekendrate = hours_weekend[0].rate;
                }

                $(mc+' .hours_weekstart').val(convert_time(weekstart));
                $(mc+' .hours_peakstart').val(convert_time(peakstart));
                $(mc+' .hours_weekfinish').val(convert_time(weekfinish));
                $(mc+' .hours_weekrate').val(weekrate);
                $(mc+' .hours_peakrate').val(peakrate);
                $(mc+' .hours_weekendstart').val(convert_time(weekendstart));
                $(mc+' .hours_weekendfinish').val(convert_time(weekendfinish));
                $(mc+' .hours_weekendrate').val(weekendrate);
            }
            
        } else if (response.redirect != undefined) {
            mini_login_wizard(response.redirect); //session timeout case
        } else {    
            set_side_error(response.error.join("<br>"));
            $('#loader-wrapper').hide();
        }

    }).fail( function(xhr, textStatus, errorThrown) {
        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
        $('#loader-wrapper').hide();
    });       
}

