function toggle_compressed_grid() {

    $('#loader-wrapper').show();

    let mini_grid = '';

    //current config
	if ($('#spaces').hasClass('mini_grid')) {
		mini_grid += 's';
	}
	if ($('#lessons').hasClass('mini_grid')) {
		mini_grid += 'l';
	}
	if ($('#classes').hasClass('mini_grid')) {
		mini_grid += 'c';
	}
	if ($('#rosters').hasClass('mini_grid')) {
		mini_grid += 'r';
	}

	//note changes
	let target = '';
	if ($('#spaces').is(":visible")) {
		target = '#spaces';
		if (mini_grid.includes('s')) {
			mini_grid = mini_grid.replace('s','');
		} else {
			mini_grid += 's'
		}
	} else if ($('#lessons').is(":visible")) {
		target = '#lessons';
		if (mini_grid.includes('l')) {
			mini_grid = mini_grid.replace('l','');
		} else {
			mini_grid += 'l'
		}		
	} else if ($('#classes').is(":visible")) {
		target = '#classes';
		if (mini_grid.includes('c')) {
			mini_grid = mini_grid.replace('c','');
		} else {
			mini_grid += 'c'
		}		
	} else if ($('#rosters').is(":visible")) {
		target = '#rosters';
		if (mini_grid.includes('r')) {
			mini_grid = mini_grid.replace('r','');
		} else {
			mini_grid += 'r'
		}		
	}

    let data = {mini_grid: mini_grid, action: 'mini_grid'};

    $.ajax({
        type: 'POST',
        url: '/api/updateUser',
        data: data,
        dataType: 'JSON'
    }).done(async function( response ) {

        if (response.success != undefined) {

            $('#loader-wrapper').hide();

			if (target) {
				$(target).html('');

				$(target).toggleClass('mini_grid');

				//refresh grid
				if ((target == '#spaces') || (target == '#lessons')) {		
					get_grid();
				} else if (target == '#classes') {
					get_class_grid();
				}  else if (target == '#rosters') {
					get_roster_grid();
				}
			}

        } else if (response.redirect != undefined) {
            mini_login_wizard(response.redirect); //session timeout case
        } else {    
            set_side_error(response.error.join("<br>"));
            $('#loader-wrapper').hide();
        }

    }).fail( function(xhr, textStatus, errorThrown) {
        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
        $('#loader-wrapper').hide();
    });           
}

