function calc_cash_sale_cost() {
    let total_aud = 0;
    let surcharge_aud = 0;
    $(mc3+' .cash_sale_row').each(function () {
    	if ($(mc3+' .cs_member_prices').is(":checked")) {
    		total_aud += parseFloat($(this).prop('dataset').intrac_member_price);
    	} else {
    		total_aud += parseFloat($(this).prop('dataset').intrac_price);	
    	}
    });

    //surcharge - start
    if ($(mc3+' .surcharge_rate').length) {
    	total_aud = numberformat(total_aud);

    	let s_rate = $(mc3+' .surcharge_rate').prop('dataset').intrac;

    	if (s_rate.includes('~')) {
    		surcharge_aud = (total_aud*parseFloat(s_rate.split('~')[0])/100)+(parseFloat(s_rate.split('~')[1]));
    	} else {
    		surcharge_aud = total_aud*parseFloat(s_rate)/100;
    	}

    	surcharge_aud = numberformat(surcharge_aud);
    	$(mc3+' .surcharge_aud').val(surcharge_aud);
    	$(mc3+' .surcharge_aud_display').text(numberformatccy(surcharge_aud));

    	if ($(mc3+' .surcharge_charge').is(":checked") && (total_aud > 0)) {
    		total_aud += surcharge_aud;	
    	}
    }
    //surcharge - end

    total_aud = numberformat(total_aud);
    $(mc3+' .total_aud').val(total_aud);
    $(mc3+' .total_aud_display').text(numberformatccy(total_aud));

    if ($('.stripe_items').length) {
    	StripePaymentManager.updateAmount(numberformat(total_aud*100,0));
    } 
}

async function process_cash_sale() {

    $('#loader-wrapper').show();

    //prepare the data
    let data ={
        purchases: [],
        total_aud: $(mc3+' .total_aud').val(),
        surcharge_aud: $(mc3+' .surcharge_charge').is(":visible") && $(mc3+' .surcharge_charge').is(":checked") ? $(mc3+' .surcharge_aud').val() : '0',
        mode: $(mc3+' .cash_sale_payment_options input:radio[name="mode"]:checked').filter((i, el) => $(el).closest('.custom-radio-div').is(':visible')).val() || 'none',
        location_id: $('#location_id').val(),
        card_number: ($(mc3+' .card_number').val() || '').replace(/ /g,''),
        card_holder: $(mc3+' .card_holder').val(),
        card_expiry: $(mc3+' .card_expiry').val(),
        card_cvv: $(mc3+' .card_cvv').val(),
        member_prices: ($(mc3+' .cs_member_prices').is(":checked") ? '1' : '0'),
    };    

    $(mc3+' .cash_sale_row').each(function () {
        data.purchases.push ({
            product_id: $(this).prop('dataset').intrac_product_id,
            quantity: 1,
            total_aud: ($(mc3+' .cs_member_prices').is(":checked") ? $(this).prop('dataset').intrac_member_price : $(this).prop('dataset').intrac_price)
        });
    });

    //console.log(data);

    let errors = [];
    //validations

    if (!data.purchases.length) {
    	errors.push("Please select a product and try again");
    }

    if ((data.mode != 'cash') && (data.mode != 'cc') && (data.mode != 'cc_d') && (data.mode != 'dd') && (data.mode != 'eftpos')) {
        errors.push("Please select a payment method and try again");
    }

    if (data.mode == 'cc') {

    	if ($('.stripe_items').length) {

    		// Trigger form validation and wallet collection
    		if (errors.length == 0) {
    			const {error: submitError} = await StripePaymentManager.submit();

    			if (submitError) {
    				errors.push(submitError.message);
    			}
    		}

    		//Create the ConfirmationToken
    		if (errors.length == 0) {
				const {error, confirmationToken} = await StripePaymentManager.createConfirmationToken();

				if (error) {
					errors.push(error.message)
				} else {
					if (confirmationToken.id) {
				      	data.cc_token = confirmationToken.id;

				      	delete data.card_number;
				      	delete data.card_holder;
				      	delete data.card_expiry;
				      	delete data.card_cvv;					
					} else {
						errors.push("Unable to process payment, please refresh the page and re-try");
					}
				}
    		}
    	} else {

	        if (!validator.isCreditCard(data.card_number)) {
	            errors.push("Invalid Card number");
	        }

	        if (isEmpty(data.card_holder)) {
	            errors.push("Invalid Card holder name");
	        }

	        if (!dayjs(data.card_expiry, 'MM/YY', true).isValid()) {
	            errors.push("Invalid Card expiry date");
	        } else if (dates_diff(dayjs().format('YYYY-MM-DD'),dayjs(data.card_expiry,'MM/YY').format('YYYY-MM-DD'))>0) {
	            errors.push("Card expiry date is in the past");
	        }

	        if (!validator.matches(data.card_cvv,/^[0-9]{3,4}$/)) {
	            errors.push("Invalid Card security code");
	        }

	        if (errors.length == 0) {

	        	if ($('#verifone_pub_key').text()) {
			    	const card = {
			        	cardNumber: data.card_number,
			        	expiryMonth: data.card_expiry.split('/')[0],
			        	expiryYear: data.card_expiry.split('/')[1],
			        	cvv: data.card_cvv,	        
			      	};

			      	data.cc_token = await verifone.encryptCard(card, $('#verifone_pub_key').text());

			      	delete data.card_number;
			      	delete data.card_holder;
			      	delete data.card_expiry;
			      	delete data.card_cvv;
	        	}      	
	        }
	    }
    }

    if (errors.length == 0) {

        $.ajax({
            type: 'POST',
            url: '/api/processCashSale',
            data: data,
            dataType: 'JSON'
        }).done(function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

                set_side_error('Cash sale completed successfully. Click <a class="a_direct primary" href="api/printReceipt?customer_id=1&invoice_id='+response.success+'" target="_blank">'+response.success+'</a> to view the receipt', 'green');

			    if ($('.stripe_items').length) {
			    	StripePaymentManager.unmount();
			    }

                $('.modal_o_cash_sale:first').click(); //reset

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed or timed out, please refresh the page " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });
    } else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();        
    }          
}

