function get_swap_class_schedules() {

    //resets
    $(mc+' .sched_swap_list').html('');
    $(mc+' .sched_swap_avails_list').html('');

    let querydata = {
        date: $(mc+' .sched_swap_date').val(),
        user_id: $(mc+' .sched_swap_user_id').val(),
        location_id: $('#location_id').val()
    };

    if (!isvalidDate(querydata.date)) {
        $('#loader-wrapper').hide();
        return;        
    } else {
        $('#loader-wrapper').show();
    }

    $.ajax({
        type: 'GET',
        url: '/api/getClassSchedules',
        data: querydata,
        dataType: 'JSON'
    }).done(function( response ) {

        if (response.success != undefined) {

            $('#loader-wrapper').hide();

            let res = response.success;

            //data
            let data = res.data.filter(item => item.class_id>0); //remove any term/perm bookings
            let html_str = '';
            if (data.length) {
            	html_str += '<ul class="swap-list">';
                for (let i = 0; i < data.length; i++) {
                    let d = data[i];
					
					let user_str = d.usernames.split(',')[0];
					let space_str = d.space_names.split(',')[0];
                    let sched_str_ = convert_time(dayjs(d.schedule_start).format('HH:mm:ss'),'h:mma')+' - '+convert_time(dayjs(d.schedule_finish).format('HH:mm:ss'),'h:mma')+' '+(user_str ? ' '+user_str : '')+(space_str ? ' '+space_str : '');;


					html_str += '<li class="flex w-full sm:!w-[280px] py-1 px-1.5 gap-2 bg-blue-100 rounded-[6px]">\
									<div class="relative margin_right_md">\
										<input type="checkbox" checked class="checkbox-custom sched_swap_schedule_id" value="'+d.schedule_id+'">\
									</div>\
                                    <div class="flex flex-col items-start w-full">\
                                        <h6 class="text-[.75rem]">'+(d.class_name || 'Booking')+'</h6>\
                                        <span class="text-[.75rem] text-gray">'+sched_str_+'</span>\
                                    </div>\
                                </li>'
                }
                html_str += '</ul>';
                $(mc+' .sched_swap_form').show();
            } else {
            	html_str = 'No data to show';
                $(mc+' .sched_swap_form').hide();
            }

            $(mc+' .sched_swap_list').html(html_str);          

            //avails
            let html_str_a = '';
            if (res.avails && res.avails.length) {
                html_str_a += '<h4 class="text-xl leading-[130%] margin_top_md margin_btm_md">Staff availability today</h4>'
                for (let i = 0; i < res.avails.length; i++) {
                    html_str_a += res.avails[i].username+' '+convert_date_time(res.avails[i].avail_start,'h:mma')+'-'+convert_date_time(res.avails[i].avail_finish,'h:mma')+'<br>';
                }
            }
            $(mc+' .sched_swap_avails_list').html(html_str_a);

            $(mc+' .sched_swap_new_user_id').html($(mc+' .sched_swap_user_id').html());
            $(mc+' .sched_swap_new_user_id option[value=""]').remove();
            $(mc+' .sched_swap_new_user_id option[value="'+querydata.user_id+'"]').remove();
            

        } else if (response.redirect != undefined) {
            mini_login_wizard(response.redirect); //session timeout case
        } else {    
            set_side_error(response.error.join("<br>"));
            $('#loader-wrapper').hide();
        }

    }).fail( function(xhr, textStatus, errorThrown) {
        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
        $('#loader-wrapper').hide();
    });
}

function save_swap_class_schedules() {

    $('#loader-wrapper').show();

    let location_id = $('#location_id').val();

    let schedule_ids = [];

    $(mc+' .sched_swap_schedule_id').each(function () {
        if (this.checked) {
            schedule_ids.push($(this).val());
        }
    });

    let data = {
        location_id: $('#location_id').val(),
        schedule_ids: schedule_ids,
        swap_date: parse_date($(mc+' .sched_swap_date').val()),
        cur_user_id: $(mc+' .sched_swap_user_id').val(),
        new_user_id: $(mc+' .sched_swap_new_user_id').val(),
        action: 'swap'
    }

    let errors = [];
    //validations
    if (!data.cur_user_id) {
    	errors.push('Please apply the user filter first');
    }

    if (!data.schedule_ids.length) {
    	errors.push('Please tick one of the options to swap');
    }

    if (errors.length == 0) {
        $.ajax({
            type: 'POST',
            url: '/api/updateClassSchedule',
            data: data,
            dataType: 'JSON'
        }).done(function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();
                
                close_modal();

                //refresh data
                get_class_grid();

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });  
    }  else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();
    } 
}

//grid bookings - space and lesson
function adjust_promo_comment(discountApplied, srDescription, promoApplied) {
    let el = $('.offcanvse:visible .promo_comment');

    if (discountApplied > 0) {
        let pc = 'Includes a '+(srDescription ? srDescription+' ' : '')+'discount of '+numberformatccy(discountApplied);
        if (promoApplied) {
            pc += ' (promo code '+$('.show-box .promo_code').val()+' applied)';
        }

        $(el).html(pc).removeClass('noshow');
    } else if (srDescription) {
    	$(el).html(srDescription).removeClass('noshow');
    }
}

function add_booking_space() {
    
	$('#loader-wrapper').show();

    let errors = [];

    //prepare the data - same as hold_booking logic minus the irrelevant pieces
	let space_ids = [];
	let location_ids = [];
	let user_ids = [];
	let fullfield = false;
	let capacity = 0;

	let start = $('#space_modal .starttimes_list').val();
	let finish = $('#space_modal .endtimes_list').val();

	let customer_id = $('#space_modal .customers_list').val();

	$('#space_modal .spaces_list li').each(function() {
		if ($(this).hasClass('checked')) {
			let id = $(this).find('a').prop('dataset').intrac;
			let name = $(this).find('a').text();
			if ($(this).find('a').hasClass('fullfield')) {
				space_ids = id.split(',');
				fullfield = true;
			} else {
				space_ids.push(id);
			}

			let loc_id = $(this).find('a').prop('dataset').intrac_location_id;
			if (!location_ids.includes(loc_id)) {
				location_ids.push(loc_id)
			}			
		}
	});

	$('#space_modal .buser_id').each(function() {
		let user_id = $(this).prop('dataset').intrac;
		if ((user_id > 0) && (!user_ids.includes(user_id))) {
			user_ids.push(user_id)
		}
	});

	let schedule_comment = $('#schedule_comment').text();
	$('#space_modal .booking_details_inp:visible').each(function() {
		let val = $(this).val();

		if ((val) || (!val && !$(this).prop('dataset').intrac_blank_comment)) {
			schedule_comment += (schedule_comment ? '<br>' : '')+$(this).prop('name')+': '+val;			
		}

	    if (!val && $(this).prop('dataset').intrac_mandatory) {
	    	errors.push('Please enter a value for '+$(this).prop('name'));
	    }

	    if (val && $(this).prop('max') && (Number(val) > Number($(this).prop('max')))) {
	    	errors.push('Maximum value allowed for '+$(this).prop('name')+' is '+$(this).prop('max'));
	    }

	    if ($(this).prop('dataset').intrac_capacity) {
	    	capacity = val || 0;
	    }
	});

	if (fullfield) {
		schedule_comment += (schedule_comment ? '<br>' : '')+'Full field';
	}

	if ($('#space_modal .cur_schedule_comment').is(':visible') && (!schedule_comment) && (!$('#space_modal .booking_details_inp:visible').length)) {
		schedule_comment = $('#space_modal .cur_schedule_comment textarea').val();
	}

	let addons = [];
	let purchases = [];
	let addon_guid = generateGUID();
	$('#space_modal .booking_addons').each(function() {
		if ($(this).is(":checked")) {
			addons.push($(this).prop('dataset').intrac);

			let purchobj = {
				product_id: $(this).prop('dataset').intrac_product_id,
				quantity: fullfield ? 1 : space_ids.length,
				addon_guid: addon_guid
			};

			purchases.push(purchobj);
		}
	});

    let location_id = $('#location_id').val();
    if (location_ids.length) { //virtual locations in admin
        location_id = location_ids[0];
    }

	let booking_data = {
		location_id: location_id,
		space_ids: space_ids,
		date: $('#main_date').val(),
		start: parse_time(start),
		finish: parse_time(finish),
		total_aud: (fullfield ? 1 : space_ids.length) * JSON.parse(decryptData($('#space_modal .rate_data').text())).items[0].adjustedRate,
		customer_id: customer_id,
		fullfield: fullfield ? fullfield : '',
		addons: addons,
		schedule_comment: schedule_comment,
		capacity: capacity,
		user_ids: user_ids
	};

	if (booking_data.addons.length) {
		booking_data.addon_guid = addon_guid;
	}

	//booking inputs
	let booking_details = get_booking_details_data();
	if (booking_details.length) {
		booking_data.booking_details = booking_details;
	}

    let data ={
        cur_schedule_id: $('#space_modal .schedule_id').val(),
        location_id: $('#location_id').val(),
        customer_id: $('#space_modal .customers_list option:first').val(),
        bookings: [booking_data],
        lessons: [],
        purchases: purchases,
        total_aud: $('#space_modal .total_aud').val(),
        cost: ($('#space_modal .cost_aud').val() || '').trim(),
        promo_code: $('#space_modal .promo_code:disabled').val(),
        cust_email: $('#space_modal .customer_email:visible').is(":checked") ? 'true' : ''
    };

    if (data.customer_id == 2) {
    	data.promo_code = '';
    	data.cust_email = '';
    }

    //validations
    if (!booking_data.space_ids.length) {
    	errors.push('Please select one or more '+$('#space_title').val()+'s from '+$('#space_modal .spaces_list_div .space-title').text()+' section');
    }

    if (!isvalidTime(booking_data.start)) {
    	errors.push('Please select a valid start time');
    }

    if (!isvalidTime(booking_data.finish)) {
    	errors.push('Please select a valid finish time');
    }

	if (data.total_aud < 0) {
		errors.push("Total cost cannot be negative");
	}

	let addons_amount = 0; 
	for (let i = 0; i < purchases.length; i++) {
		addons_amount += purchases[i].total_aud;
	}

    if (location_ids.length > 1) {
    	errors.push('Selecting  '+$('#space_title').val()+'s from multiple locations is not allowed');
    }

	if ((!isEmpty(data.cost)) && (!isFinite(parseFloat(data.cost)))) {
		errors.push('Invalid Cost override amount');
	}

    if (!isEmpty(data.cost)) {
		if ((parseFloat(data.cost)-addons_amount) < 0) {
        	errors.push("Cost override amount cannot be less than add-ons price, please untick add-ons and try again or adjust override amount");
        }
    }

    if (data.cur_schedule_id && data.purchases.length) {
    	errors.push('Add-ons are not allowed during booking alter process');
    }

	if (errors.length == 0) {

	    $.ajax({
	        type: 'POST',
	        url: '/api/saveBooking',
	        data: data,
	        dataType: 'JSON'
	    }).done(async function( response ) {

	        if (response.success != undefined) {

	            $('#loader-wrapper').hide();

	            let res = response.success;

	            if ($('#space_modal .repeat_booking').is(":checked")) { //repeat booking
	            	set_side_error("Booking created successfully, please continue with next booking", "green");

	            	$('#space_modal .booking_date').prop('disabled', false);
	            	$('#space_modal .calendar_booking')[0]._flatpickr.setDate(dayjs(booking_data.date).add(1, 'week').format('YYYY-MM-DD'), true); //trigger change as well
	            	$('#space_modal .booking_date:visible').addClass('show_border');

				    $('#space_modal .new-modal-content').animate({
				        scrollTop: $('#space_modal form').position().top
				    }, 500);

	            } else {
		            close_side_modal();

		            if (data.customer_id != 2) {
			            //go to customer account
			            if (res.new_receipts) {
			            	await viewCustomer(data.customer_id, 'account','',res.new_receipts);
			            } else {
			            	await viewCustomer(data.customer_id, 'cust_hist');
			            }
			        }

		            //refresh grid
		            get_grid(false);
	            }

	        } else if (response.redirect != undefined) {
	            mini_login_wizard(response.redirect); //session timeout case
	        } else {
	            set_side_error(response.error.join("<br>"));
	            $('#loader-wrapper').hide();
	           	//refresh grid without spinner...even in failure to get the up-to-date data - skip as it's overriding booking_details/addons
	        }

	    }).fail( function(xhr, textStatus, errorThrown) {
	        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
	        $('#loader-wrapper').hide();
	    });	
	} else {
		set_side_error(errors.join("<br>"));
		$('#loader-wrapper').hide();
	}
}

function add_booking_lesson() {
    
	$('#loader-wrapper').show();

    let errors = [];

    //prepare the data - same as hold_lesson logic minus the irrelevant pieces
    let user_ids = [];
    let space_ids = [];
    let location_ids = [];

	let start = $('#lesson_modal .starttimes_list').val();
	let finish = $('#lesson_modal .endtimes_list').val();

	let customer_id = $('#lesson_modal .customers_list').val();
	let parent_id = $('#lesson_modal .customers_list option:selected').prop('dataset').intrac_parent_id;

	$('#lesson_modal .users_list li').each(function() {
		if ($(this).hasClass('checked')) {
			let id = $(this).find('a').prop('dataset').intrac;
			let name = $(this).find('a').text();
			user_ids.push(id);
		}
	});

	$('#lesson_modal .bspace_id').each(function() {
		let space_id = $(this).prop('dataset').intrac;
		if ((space_id > 0) && (!space_ids.includes(space_id))) {
			space_ids.push(space_id)
		}

		let loc_id = $(this).prop('dataset').intrac_location_id;
		if ((loc_id > 0) && (!location_ids.includes(loc_id))) {
			location_ids.push(loc_id)
		}
	});

	let p_el = '#lesson_modal .passes_list option:selected';

	let pass_id = $(p_el).length ? $(p_el).prop('dataset').intrac_pass_id || 0 : '';
	let passtype_id = $(p_el).val() || '';

	let schedule_comment = $('#lesson_modal .schedule_comment').val();
	let capacity = $('#lesson_modal .capacity').val();

	//alter
	let sd = '';
	if ($('#lesson_modal .schedule_data').text()) {
		sd = JSON.parse($('#lesson_modal .schedule_data').text());
	}

	let lesson_data = {
		location_id: $('#location_id').val(),
		user_ids: user_ids,
		date: $('#main_date').val(),
		start: parse_time(start),
		finish: parse_time(finish),
		total_aud: JSON.parse(decryptData($('#lesson_modal .rate_data').text())).item.adjustedRate,
		customer_id: customer_id,
		pass_id: pass_id,
		passtype_id: passtype_id,
		schedule_comment: schedule_comment,
		capacity: capacity,
		space_ids: space_ids
	};

    let data ={
        cur_schedule_id: $('#lesson_modal .schedule_id').val(),
        location_id: $('#location_id').val(),
        customer_id: $('#lesson_modal .customers_list option:first').val(),
        bookings: [],
        lessons: [lesson_data],
        purchases: [],
        total_aud: $('#lesson_modal .total_aud').val(),
        cost: ($('#lesson_modal .cost_aud').val() || '').trim(),
        promo_code: $('#lesson_modal .promo_code:disabled').val(),
        cust_email: $('#lesson_modal .customer_email:visible').is(":checked") ? 'true' : ''
    };

    //validations
    if (lesson_data.user_ids.length != 1) {
    	errors.push('Please select an instructor from Select Instructor section');
    }

    if (!validator.isInt(lesson_data.capacity,{min: 1})) {
    	errors.push('Invalid number of participants');
    }

	if ((pass_id === '') || (passtype_id === '')) {
		errors.push('Please select a '+$('#pass_title').val());
	}

    if (!isvalidTime(lesson_data.start)) {
    	errors.push('Please select a valid start time');
    }

    if (!isvalidTime(lesson_data.finish)) {
    	errors.push('Please select a valid finish time');
    }

	if (data.total_aud < 0) {
		errors.push("Total cost cannot be negative");
	}

    if (location_ids.length > 1) {
    	errors.push('Selecting  '+$('#space_title').val()+'s from multiple locations is not allowed');
    }

	if ((!isEmpty(data.cost)) && (!isFinite(parseFloat(data.cost)))) {
		errors.push('Invalid Cost override amount');
	}

	if (errors.length == 0) {

	    $.ajax({
	        type: 'POST',
	        url: '/api/saveBooking',
	        data: data,
	        dataType: 'JSON'
	    }).done(async function( response ) {

	        if (response.success != undefined) {

	            $('#loader-wrapper').hide();

	            let res = response.success;

	            if ($('#lesson_modal .repeat_booking').is(":checked")) { //repeat booking

	            	await viewCustomer(parent_id > 0 ? parent_id : customer_id, 'silent'); //refresh data in background to update passes

	            	set_side_error("Booking created successfully, please continue with next booking", "green");

	            	$('#lesson_modal .booking_date').prop('disabled', false);
	            	$('#lesson_modal .calendar_booking')[0]._flatpickr.setDate(dayjs(lesson_data.date).add(1, 'week').format('YYYY-MM-DD'), true); //trigger change as well
	            	$('#lesson_modal .booking_date:visible').addClass('show_border');

				    $('#lesson_modal .new-modal-content').animate({
				        scrollTop: $('#lesson_modal form').position().top
				    }, 500);

	            } else {

		            close_side_modal();

		            if (sd && (sd.pass_id != lesson_data.pass_id)) {
		            	set_side_error('You have changed the '+$('#pass_title').val()+' that was used to make the current booking. If the previous '+$('#pass_title').val()+' is not required anymore, please delete it from customer\'s profile', 'amber');
		            }

		            //go to customer account
		            if (res.new_receipts) {
		            	await viewCustomer(data.customer_id, 'account','',res.new_receipts);
		            } else {
		            	await viewCustomer(data.customer_id, 'cust_hist');
		            }

		            //refresh grid
		            get_grid(false);
		        }

	        } else if (response.redirect != undefined) {
	            mini_login_wizard(response.redirect); //session timeout case
	        } else {
	            set_side_error(response.error.join("<br>"));
	            $('#loader-wrapper').hide();
	           	//refresh grid without spinner...even in failure to get the up-to-date data - skip as it's overriding booking_details/addons
	        }

	    }).fail( function(xhr, textStatus, errorThrown) {
	        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
	        $('#loader-wrapper').hide();
	    });	
	} else {
		set_side_error(errors.join("<br>"));
		$('#loader-wrapper').hide();
	}
}

function get_booking_details(id, mode, term_perm=false) {

	$(mc).scrollTop(0);

	let data = {schedule_id: id, mode: mode};

	if (term_perm) {
		data.show_term_perm_bookings = true;
	}

	$('#loader-wrapper').show();

    $.ajax({
        type: 'GET',
        url: '/api/getBooking',
        data: data,
        dataType: 'JSON'
    }).done(function( response ) {

        if (response.success != undefined) {

            $('#loader-wrapper').hide();

            let res = response.success;

            //data
            let data = res.data[0];
            let html_str = '';
            if (data) {
                html_str += '<li><span class="booking-details-list-label"><img class="size-5" src="images/icons/customer.svg" alt="">Customer</span><a href="#" class="view_customer" data-intrac_customer_id="'+data.customer_id+'" data-intrac_parent_id="'+data.parent_id+'">'+data.first_name+' '+data.last_name+'</a></li>';
                html_str += '<li><span class="booking-details-list-label"><img class="size-5" src="images/icons/date.svg" alt="">Date</span>'+convert_date_time(data.schedule_start, 'D MMM YYYY')+'</li>';
                html_str += '<li><span class="booking-details-list-label"><img class="size-5" src="images/icons/time.svg" alt="">Time</span>'+convert_date_time(data.schedule_start, 'h:mma')+' - '+convert_date_time(data.schedule_finish, 'h:mma')+'</li>';
                html_str += '<li><span class="booking-details-list-label"><img class="size-5" src="images/icons/location.svg" alt="">Location</span>'+data.location_name+'</li>';
                let space_names = data.space_names.split(',').filter(item => item != '');
                if (space_names.length) {
                    html_str += '<li><span class="booking-details-list-label"><img class="size-5" src="images/icons/spaces.svg" alt="">'+toTitleCase($('#space_title').val())+'s</span>'+(data.schedule_comment == 'Full field' ? 'Full field' : space_names.join(', '))+'</li>';    
                }
                let usernames = data.usernames.split(',').filter(item => item != '');
                if (usernames.length) {
                    html_str += '<li><span class="booking-details-list-label"><img class="size-5" src="images/icons/instructors.svg" alt="">Instructors</span>'+usernames.join(', ')+'</li>';
                }                
                if (data.booked_username) {
                    html_str += '<li><span class="booking-details-list-label"><img class="size-5" src="images/icons/customer.svg" alt="">Booked by</span>'+data.booked_username+'</li>';    
                }
                if (data.passtype_name) {
                	html_str += '<li><span class="booking-details-list-label"><img class="size-5" src="images/icons/file.svg" alt="">'+toTitleCase($('#pass_title').val())+'</span>'+data.passtype_name+'</li>';
                }                
                if ((mode == 'space') && (data.amount)) {
                	if (data.receipt_type == 1) {
                		html_str += '<li><span class="booking-details-list-label"><img class="size-5" src="images/icons/amount-gray.svg" alt="">Amount</span><a href="#" class="btn-link view_account" data-intrac_customer_id="'+data.customer_id+'" data-intrac_parent_id="'+data.parent_id+'" data-intrac_receipt_id="'+data.receipt_id+'">'+numberformatccy(data.amount)+' (Unpaid)'+'</a></li>';
                	} else {
                		html_str += '<li><span class="booking-details-list-label"><img class="size-5" src="images/icons/amount-gray.svg" alt="">Amount</span>'+numberformatccy(data.amount)+'</li>';
                	}   
                }
                if (mode == 'lesson') {
                	if (data.receipt_type == 1) {
                		html_str += '<li><span class="booking-details-list-label"><img class="size-5" src="images/icons/amount-gray.svg" alt="">Amount</span><a href="#" class="btn-link view_account" data-intrac_customer_id="'+data.customer_id+'" data-intrac_parent_id="'+data.parent_id+'" data-intrac_receipt_id="'+data.receipt_id+'">'+numberformatccy(data.amount)+' (Unpaid)'+'</a></li>';
                	}  
                }
                if (data.receipt_invoice_comment) {
                    html_str += '<li><span class="booking-details-list-label"><img class="size-5" src="images/icons/bullet-list-text.svg" alt="">Receipt Details</span>'+data.receipt_invoice_comment+'</li>';
                }
                if (data.addons && data.addons.length) {
                	let addon_strs = [];
                	data.addons_amount = 0;
                	for (let i = 0; i < data.addons.length; i++) {
                		let d = data.addons[i];
                		addon_strs.push((d.quantity > 1 ? d.quantity+' x ' : '')+d.category+' '+d.product_name);
                		data.addons_amount += d.amount;
                	}
                	data.addons_amount = numberformat(data.addons_amount);
                	html_str += '<li><span class="booking-details-list-label"><img class="size-5" src="images/icons/bullet-list-text.svg" alt="">Addons</span>'+addon_strs.join('<br>')+'</li>';
                	html_str += '<li><span class="booking-details-list-label"><img class="size-5" src="images/icons/amount-gray.svg" alt="">Addons Amount</span>'+numberformatccy(data.addons_amount)+'</li>';
                } else {
                	data.addons_amount = 0;
                }

                $(mc+' .booking_schedule_id').val(id);
                data.mode = mode;
                data.allow_update_comment = res.allow_update_comment;
                $(mc+' .booking_schedule_data').text(JSON.stringify(data));

                if (mode == 'lesson') {
                	if (!$('#lesson_modal .lesson_capacity_div').hasClass('noshow')) {
                		html_str += '<li><span class="booking-details-list-label"><img class="size-5" src="images/icons/instructors.svg" alt="">Attendees</span>'+data.capacity+'</li>';
                	}
                }

                if (data.schedule_comment) {
                    html_str += '<li><span class="booking-details-list-label"><img class="size-5" src="images/icons/bullet-list-text.svg" alt="">Details</span>'+data.schedule_comment+'</li>';
                }

                //adjust buttons
                if (dates_diff(dayjs(data.schedule_start).format('YYYY-MM-DD'), dayjs().format('YYYY-MM-DD')) < 0) {
                    if (!$('.reports_only').length) {
                        $(mc+' .btn_alterBooking').remove();
                        $(mc+' .btn_cancelBooking').remove();
                    }
                }

                //is the stid on the grid?
                if (true) {
					let space_id_ = (mode == 'lesson') ? data.user_ids.split(',')[0] : data.space_ids.split(',')[0];
					let start_ = convert_date_time(data.schedule_start, 'HH-mm');
					if (!$('#'+space_id_+'_'+start_).length) {
						$(mc+' .btn_alterBooking').remove();
					}
                }

                if (data.special_rate) {
                	$(mc+' .btn_alterBooking').remove();
                }

                if (data.addons && data.addons.length) {
                	$(mc+' .btn_alterBooking').remove();
                }

                if ((mode == 'space') && (!space_names.length)) { //single booking
                	$(mc+' .btn_alterBooking').remove();
                }

                if ((mode == 'space') && (!$('#spaces').is(":visible"))) { //called from classes grid
                	$(mc+' .btn_alterBooking').remove();
                }

                if ((mode == 'lesson') && (!$('#lessons').is(":visible"))) { //called from classes grid
                	$(mc+' .btn_alterBooking').remove();
                }

                if (term_perm) {
                    $(mc+' .btn_alterBooking').remove();
                    $(mc+' .btn_cancelBooking').prop('dataset').intrac_term_perm = true;
                }

                if (data.schedule_comment.toLowerCase().includes('party')) {
                	$(mc+' .btn_bookingEmail[data-intrac="emailconfirmbookingcombo"]').removeClass('noshow');
                } else {
                	$(mc+' .btn_bookingEmail[data-intrac="emailconfirmbookingcombo"]').remove();
                }

                //same conditions in set_alter_booking, except for btn_alterBooking check
                //must be done after adjusting buttons
                if ((!$(mc+' .btn_alterBooking').length) &&
                	(data.schedule_comment || data.allow_update_comment) &&
                	(data.schedule_comment != 'Full field') && 
                	(!$('#space_modal .booking_details_inp_rate[data-intrac_location_id="'+data.location_id+'"]').length) &&
                	(!$('#space_modal .booking_details_inp[data-intrac_capacity][data-intrac_location_id="'+data.location_id+'"]').length)) { //booking details
                	$(mc+' .booking_comment').val(data.schedule_comment);
                	$(mc+' .booking_comment_form').removeClass('noshow_imp');
                } else {
                	$(mc+' .booking_comment_form').remove();
                }

            } else {
                set_side_error('Unable to retrieve booking details');
                close_modal();
            }

            $(mc+' .booking_details').html(html_str);

        } else if (response.redirect != undefined) {
            mini_login_wizard(response.redirect); //session timeout case
        } else {    
            set_side_error(response.error.join("<br>"));
            $('#loader-wrapper').hide();
        }

    }).fail( function(xhr, textStatus, errorThrown) {
        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
        $('#loader-wrapper').hide();
    });
}

function cancel_booking(term_perm='') {
    $('#loader-wrapper').show();

    let sd = JSON.parse($(mc+' .booking_schedule_data').text());
    let location_id = sd.location_id;
    let schedule_id = $(mc+' .booking_schedule_id').val();
    let customer_id = sd.customer_id;
    let parent_id = sd.parent_id;
    let mode = sd.mode;

    let errors = [];
    //validations

    if (errors.length == 0) {
        $.ajax({
            type: 'POST',
            url: '/api/updateBooking',
            data: {schedule_id: schedule_id, customer_id: customer_id, location_id: location_id, mode: mode, term_perm_booking: term_perm, action: 'delete'},
            dataType: 'JSON'
        }).done(async function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

                close_modal();

                if (customer_id != 2) {
	                //unpaid pass feedback
	                if (response.unpaid_pass) {
	                    set_side_error('An unpaid '+$('#pass_title').val()+' was used to make this booking, please delete it from customer\'s profile if not required anymore', 'amber');
	                    viewCustomer(parent_id > 0 ? parent_id : customer_id, 'passes');
	                } else if (mode == 'lesson') {
	                	//do nothing, unpaid_pass already handled
	                } else if (sd.receipt_type == 1) {
	                	//unpaid booking, do nothing
	                } else {
	                	viewCustomer(parent_id > 0 ? parent_id : customer_id, 'account');
	                }
	            }

	            //refresh grid
	            if ($('#spaces').is(":visible") || $('#lessons').is(":visible")) {
	            	get_grid(false);
	            } else if ($('#classes').is(":visible")) { //space bookings could be visible in classes page
                	get_class_grid(false);
                } else if ($('#rosters').is(":visible")) { //space bookings could be visible in rosters page
                	get_roster_grid(false);
                }

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });  
    }  else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();
    }    
}

