function init_ps_booking_details(d) {
    //reset
    $('.ps_bd_div').html(''); //updates master too

    //booking details
    if (d.booking_details) {
        let div_str = '';
        
        for (let l = 0; l < d.booking_details.length; l++) { //locations loop
        	
        	let location_id = d.booking_details[l].location_id;
        	let booking_details = d.booking_details[l].booking_details;

	        for (let i = 0; i < (booking_details || []).length; i++) { //booking_details loop
	            let e = booking_details[i];

	            let intrac_mandatory = e.mandatory?' data-intrac_mandatory="true" ':'';
	            let intrac_capacity = e.capacity?' data-intrac_capacity="true" ':'';
	            let intrac_blank_comment = e.blank_comment?' data-intrac_blank_comment="true" ':'';
	            let intrac_rate_id = e.rate_id?' data-intrac_rate_id="'+e.rate_id+'" ':'';
	            let intrac_location_id = ' data-intrac_location_id="'+location_id+'" ';
	            let intrac_space_ids = e.space_ids?' data-intrac_space_ids="'+e.space_ids.join('-')+'" ':'';

	            if ((e.type == 'text') || (e.type == 'number')) {

	                div_str += '<div class="form-group ps_booking_details_div">\
	                                <div class="label">'+(e.display?e.display:'')+'</div>\
	                                <div class="input-group">\
	                                    <input type="'+e.type+'" class="form-control ps_booking_details_inp" name="'+e.display+'" value="'+(e.default?e.default:"")+'" '+(e.maxlength?' maxlength="'+e.maxlength+'"':'')+(e.max?' max="'+e.max+'"':'')+' data-input '+intrac_mandatory+intrac_capacity+intrac_blank_comment+intrac_location_id+intrac_space_ids+' >\
	                                </div>\
	                            </div>';
	            }

	            if (e.type == 'textarea') {
	                div_str += '<div class="form-group ps_booking_details_div">\
	                                <div class="label">'+(e.display?e.display:'')+'</div>\
	                                <div class="input-group">\
	                                    <textarea class="form-control ps_booking_details_inp" name="'+e.display+'" '+(e.maxlength?' maxlength="'+e.maxlength+'"':'')+' '+intrac_mandatory+intrac_capacity+intrac_blank_comment+intrac_location_id+intrac_space_ids+' >'+(e.default?e.default:'')+'</textarea>\
	                                </div>\
	                            </div>';
	            }

	            if (e.type == 'select') {
	                let opts_str = '';
	                for (let i = 0; i < e.values.length; i++) {
	                    opts_str += '<option value="'+e.values[i]+'" '+(e.default == e.values[i] ? 'selected' : '')+'>'+e.values[i]+'</option>';
	                }                

	                div_str += '<div class="form-group ps_booking_details_div">\
	                                <div class="label space-title">'+(e.display?e.display:'')+'</div>\
	                                <select class="form-control ps_booking_details_inp'+(intrac_rate_id ? ' ps_booking_details_inp_rate' : '')+'" name="'+e.display+'" value="" type="button" data-toggle="dropdown" '+intrac_mandatory+intrac_capacity+intrac_blank_comment+intrac_location_id+intrac_space_ids+intrac_rate_id+'>\
	                                    '+opts_str+'\
	                                </select>\
	                            </div>';
	            }
	        } //end of booking_details loop
        } //end of locations loop

        $('.ps_bd_div').html(div_str); //updates master too
    }
}

function set_ps_booking_details_inp() {
    if ($(mc+' .ps_booking_details_inp').length) {
        let space_ids = [];
        let location_ids = [];

        //spaces
        //multiple spaces visible
        if ($(mc+' .ps_space_multiple_div').is(":visible")) {

            $(mc+' .ps_su_sel').each(function () {
                if (this.checked) {
                    let s_id = 0;
                    
                    s_id = $(this).closest('tr').find('.ps_space_id_').val();

                    if (s_id > 0) {
                        let loc_id = $(this).closest('tr').find('.ps_space_id_ option:selected').prop('dataset').intrac_location_id;

                        space_ids.push(s_id);
                        location_ids.push(loc_id);               
                    }
                }
            });

        } else { //single space
            let s_id = $(mc+' .ps_space_id').val();

            if (s_id > 0) {
                let loc_id = $(mc+' .ps_space_id option:selected').prop('dataset').intrac_location_id;

                space_ids.push(s_id);
                location_ids.push(loc_id);                 
            }
        }

        $(mc+' .ps_booking_details_inp').each(function() {
            //location filter
            let bd_location_id = $(this).prop('dataset').intrac_location_id;
            if (location_ids.includes(bd_location_id)) { //any bd_location_id is in location_ids
                $(this).closest('.ps_booking_details_div').show();
            } else if (!space_ids.length && !$('.virtual_locations').length) { //no space is selected and there are no virtual locations
            	$(this).closest('.ps_booking_details_div').show();
            } else {
                $(this).closest('.ps_booking_details_div').hide();
            }

            //space filter
            if ($(this).prop('dataset').intrac_space_ids) {
                let bd_space_ids = $(this).prop('dataset').intrac_space_ids.split('-');

                if (space_ids.some(item => bd_space_ids.includes(item))) { //any items in space_ids are in bd_space_ids
                    $(this).closest('.ps_booking_details_div').show();
                } else {
                    $(this).closest('.ps_booking_details_div').hide();
                }
            }
        }); 
    }
}

function set_alter_ps_booking_details(d) {
    set_ps_booking_details_inp(); //depends on spaces selected
    let comment = d.program_comment != undefined ? d.program_comment : d.schedule_comment;
    let bds = comment.split('<br>');
    for (let i = 0; i < bds.length; i++) {
        if (bds[i].includes(':')) {
            let key = bds[i].split(':')[0].trim();
            let value = (bds[i].split(':')[1] || '').trim();

            let bd_el = $(mc+' .ps_booking_details_inp[name="'+key+'"]:visible')[0];

            if (bd_el) {
                $(bd_el).val(value);
            }
        }
    }   
}

function get_ps_booking_details_data() {
    let errors = [];	

    let capacity = 0;
    let comment = '';
    $(mc+' .ps_booking_details_inp:visible').each(function() {
        let val = $(this).val();

        if ((val) || (!val && !$(this).prop('dataset').intrac_blank_comment)) {
            comment += (comment ? '<br>' : '')+$(this).prop('name')+': '+val;         
        }

        if (!val && $(this).prop('dataset').intrac_mandatory) {
            errors.push('Please enter a value for '+$(this).prop('name'));
        }

        if (val && $(this).prop('max') && (Number(val) > Number($(this).prop('max')))) {
            errors.push('Maximum value allowed for '+$(this).prop('name')+' is '+$(this).prop('max'));
        }

        if ($(this).prop('dataset').intrac_capacity) {
            capacity = val || 0;
        }
    });

    return {
        comment: comment,
        capacity: capacity,
        errors: errors
    };
}

