function get_tb_schedules(program_id,schedule_id='') {

    $('#loader-wrapper').show();

    $(mc+' .tb_schedules_tab').html($('#master_term_booking_view .tb_schedules_tab').html()); //reset
    $(mc+' .tb_prog_form').html(''); //reset to avoid ps_user_id ps_space_id interference

    //have to do these here than in master
    //set each ps_space_id_ sel with a value per index, so that selects don't look all blanks
    set_ps_space_id_defaults(); 

    if (program_id) {
        $.ajax({
            type: 'GET',
            url: '/api/getClassSchedules',
            data: {class_id: 0, program_id: program_id, show_term_perm_bookings: true},
            dataType: 'JSON'
        }).done(function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

                let res = response.success;

                //data
                let data = res.data;

                let html_str = '';

                //program info
                $(mc+' .tb_sched_program_id').val(res.program.program_id);
                $(mc+' .tb_schedules_tab .view_account').prop('dataset').intrac_customer_id = res.program.customer_id;
                $(mc+' .tb_schedules_tab .view_account').prop('dataset').intrac_parent_id = res.program.parent_id;

                let prog_str = res.program.day.substring(1)+' '+convert_time(res.program.program_start,'h:mma')+'-'+convert_time(res.program.program_finish,'h:mma');

                $('.modal_title_mc1').text(res.program.first_name+' '+res.program.last_name+' '+prog_str+' '+res.program.term_name);

                //data            
                for (let i = 0; i < data.length; i++) {

                    let usernames = data[i].usernames.split(',');
                    let user_str = (usernames.length>1) ? (usernames[0] ? usernames[0]+'*<br>' : '')+usernames.slice(1).join('<br>') : (usernames[0] || '');

                    let space_names = data[i].space_names.split(',');
                    let space_str = (space_names.length>1) ? space_names.join('<br>') : (space_names[0] || '');

                    html_str += '<tr class="tb_sched_item">\
                                    <td><span class="program_id noshow">'+data[i].program_id+'</span><span class="schedule_id noshow">'+data[i].schedule_id+'</span>'+convert_date(data[i].schedule_start, 'ddd D MMM YYYY')+' '+dayjs(data[i].schedule_start).format('h:mma')+'-'+dayjs(data[i].schedule_finish).format('h:mma')+'</td>\
                                    <td>'+user_str+'</td>\
                                    <td>'+space_str+'</td>\
                                    <td>'+numberformatccy(data[i].amount)+(data[i].receipt_type == 1 ? ' (Unpaid)' : '')+'</td>\
                                    <td><ul>\
                                            '+($('#is_admin').val() ? '<li><a href="#" class="btn-edit edit_form edit_tb_sched" data-intrac="'+data[i].schedule_id+'">Edit</a></li>' : '')+'\
                                            '+($('#is_admin').val() ? '<li><a href="#" class="btn-edit delete_tb_sched">Delete</a></li>' : '')+'\
                                        </ul></td>\
                                </tr>';

                                //removed && !data[i].enrolments from class_tb_sched_delete
                }

                $(mc+' .tb_sched_list tbody').html(html_str);

	            //load schedule if schedule_id is passed e.g. called from grid
	            if (schedule_id) {
					$(mc+' .tb_sched_list .edit_tb_sched[data-intrac="'+schedule_id+'"]').click();
	            }

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });
    } else {
        $('#loader-wrapper').hide();
    }

}

