function refreshAllDashboardCharts() {
	if (!$('#dashboard').length || !$('#dashboard .rep_chart').length) {
		return;
	}
	destroy_charts('#dashboard');
	create_charts($('#dashboard').find('.rep_chart'));
}

function kickDashboardGridCellHeight() {
	const grid = document.getElementById('dashboard')?.gridstack;
	if (!grid || grid.opts?.cellHeight !== 'auto') {
		return;
	}
	try {
		grid.cellHeight('auto');
	} catch (e) {
	}
}

function applyDashboardGridLayout() {
	const el = document.getElementById('dashboard');
	const gs = el?.gridstack;
	if (!gs) {
		return;
	}
	const w = el.clientWidth || el.parentElement?.clientWidth || window.innerWidth;
	if (!w) {
		return;
	}
	try {
		gs.onResize(w);
	} catch (e) {
	}
	kickDashboardGridCellHeight();
}

function scheduleDashboardLayoutRefresh() {
	if (!$('#dashboard').length || !document.getElementById('dashboard')?.gridstack) {
		return;
	}
	requestAnimationFrame(function () {
		requestAnimationFrame(function () {
			applyDashboardGridLayout();
		});
	});
}

function create_charts(el) {

	const $scope = el ? $(el) : $('#report_chart').find('.rep_chart');

	const _reduceMotion = typeof window.matchMedia === 'function' && window.matchMedia('(prefers-reduced-motion: reduce)').matches;

	const lineDrawReveal = {
		id: 'lineDrawReveal',
		beforeDatasetsDraw(chart) {
			if (chart._lineDrawProgress == null || chart._lineDrawProgress >= 1) return;
			var ctx = chart.ctx;
			var ca = chart.chartArea;
			var revealW = (ca.right - ca.left) * chart._lineDrawProgress;
			ctx.save();
			ctx.beginPath();
			ctx.rect(ca.left, 0, revealW, chart.height);
			ctx.clip();
		},
		afterDatasetsDraw(chart) {
			if (chart._lineDrawProgress == null || chart._lineDrawProgress >= 1) return;
			chart.ctx.restore();
		}
	};

	$scope.each(function () {
		let raw = $(this).find('.chart_data').text().trim();
		if (!raw) {
			return;
		}

		$(this).removeClass('xl_chart');

	    let ccy_tooltip = {
        	//backgroundColor: '#645bef',
        	callbacks: {
	        	label: function(context) {
	          		let label = context.dataset.label || '';
	          		if (label) label += ': ';
	          		const value = context.parsed.y;
	          		if (parseFloat(context.parsed.y)) {
                        label += numberformatccy(context.parsed.y,0);
                    } else if (parseFloat(context.parsed)) {
                    	label += numberformatccy(context.parsed,0);
                    }
                    return label;
	        	}
	        }
      	};

		let datalabels = {
			display: 'auto',
			//anchor: 'end',
			//align: 'end',
			//clip: true,  
			formatter: (value, context) => {
		    	const { chart, datasetIndex } = context;
		    	const dataset = chart.data.datasets[datasetIndex];

		    	const hiddenIndices = chart._hiddenIndices || {};

		    	// Sum only visible items
		    	let total = 0;
		    	dataset.data.forEach((val, idx) => {
		      		if (!hiddenIndices[idx]) {
						val = typeof val === 'number' ? val : Number(val);
						if (!Number.isNaN(val)) {
						    total += val;
						}		      			
		      		}
		    	});

		    	if (total === 0) return '0%';
		    	const percentage = (value / total) * 100;
		    	return numberformat(percentage, 0) + '%';
		  	}
		  	/*
      		formatter: ((value, ctx) => {
      			const totalSum = ctx.dataset.data.reduce((accumulator, currentValue) => {
      				return accumulator + currentValue
      			}, 0);
      			const percentage = value / totalSum * 100;
      			return numberformat(percentage,0)+'%'
      		})*/		  	
		};

		const lineShadow = {
            id: 'lineShadow',
            beforeDatasetDraw(chart, args, pluginOptions) {
                if (args.index !== 0) return; // Only apply to the first dataset
                const meta = chart.getDatasetMeta(0);
                if (!meta || !meta.dataset) return;
                const ctx = chart.ctx;

                // Outer shadow
                ctx.save();
                ctx.shadowColor = 'rgba(125, 91, 255, 0.25)';
                ctx.shadowBlur = 16;
                ctx.shadowOffsetX = 0;
                ctx.shadowOffsetY = 8;
                ctx.strokeStyle = 'rgba(100, 91, 239, 1)';
                ctx.lineWidth = 3;
                meta.dataset.draw(ctx);
                ctx.restore();

                // Inset shadow (optional, subtle)
                ctx.save();
                ctx.shadowColor = 'rgba(129, 113, 223, 0.18)';
                ctx.shadowBlur = 2;
                ctx.shadowOffsetX = 0;
                ctx.shadowOffsetY = 1;
                ctx.strokeStyle = 'rgba(100, 91, 239, 0.0)';
                ctx.lineWidth = 2;
                meta.dataset.draw(ctx);
                ctx.restore();
            }
        };

		try {
			if (!isJSON(raw)) {
				return;
			}
			let data = JSON.parse(raw);

			data.options = data.options || {};
			data.options.plugins = data.options.plugins || {};

			if (data.extras && data.extras.ccy) {
				data.options.plugins.tooltip = ccy_tooltip;
			}

			if ((data.type == 'pie') || (data.type == 'doughnut')) {
				// Allow callers to explicitly disable/override datalabels.
				if (data.options.plugins.datalabels === undefined) {
					data.options.plugins.datalabels = datalabels;
				}
			} else if (data.type == 'bar') {
				data.options.plugins.datalabels = {display: false};
				data.options.plugins.legend = data.options.plugins.legend || {};
				data.options.plugins.legend.display = false;
			} else if (data.type == 'stackedbar') {
				data.type = 'bar';
				data.options.plugins.datalabels = {display: false};
				$(this).addClass('xl_chart');
			} else if (data.type == 'stackedline') {
				data.type = 'line';
				data.options.plugins.datalabels = {display: false};
				$(this).addClass('xl_chart');
			}

			//remove grid lines
			if (['bar', 'stackedbar', 'line', 'stackedline'].includes(data.type)) {
				if (data.options.scales) {
					data.options.scales.x = {...data.options.scales.x, grid: { display: false }};
					data.options.scales.y = {...data.options.scales.y, grid: { display: false }};
				} else {
					data.options.scales = {x: { grid: { display: false } }, y: { grid: { display: false } }}
				}
			}

			if (data.large_chart) {
				$(this).addClass('xl_chart');
			}

			if (data.shadow && data.type === 'line') {
				data.plugins = [...(data.plugins || []), lineShadow];
			}

			var isLineReveal = data.type === 'line' && !_reduceMotion;
			if (isLineReveal) {
				data.plugins = [...(data.plugins || []), lineDrawReveal];
				data.options.animation = { duration: 0 };
			}

			const canvas = $(this).find('.chart_canvas').get(0);
			if (!canvas) {
				return;
			}
			const existingChart = Chart.getChart(canvas);
			if (existingChart) {
				existingChart.destroy();
			}
			const ctx = canvas.getContext('2d');
			var chartInst = new Chart(ctx, data);

			if (isLineReveal) {
				chartInst._lineDrawProgress = 0;
				chartInst.draw();
				var LINE_DRAW_MS = 1400;
				var lineT0 = 0;
				(function stepDraw(now) {
					if (!chartInst.ctx) return;
					if (!lineT0) {
						var op = parseFloat(getComputedStyle(canvas).opacity);
						if (op < 0.5) {
							requestAnimationFrame(stepDraw);
							return;
						}
						lineT0 = now;
					}
					var p = Math.min((now - lineT0) / LINE_DRAW_MS, 1);
					chartInst._lineDrawProgress = 1 - Math.pow(1 - p, 3);
					chartInst.draw();
					if (p < 1) {
						requestAnimationFrame(stepDraw);
					} else {
						chartInst._lineDrawProgress = null;
						chartInst.draw();
					}
				})(performance.now());
			}
		} catch (e) {
			console.error('Chart render failed', e);
		}
	});	
}

function destroy_charts(el) {
	const $scope = el ? $(el).find('.chart_canvas') : $('#report_chart').find('.chart_canvas');
	$scope.each(function () {
		const chart = Chart.getChart(this);
		if (chart) {
			chart.destroy();
		}
	});	
}

function run_report_max_days(report) {
	$('#report_summary_title .rep_sub_name').prop('dataset').intrac_dont_run = true; //set don't run parameter
	$('.view_report[data-intrac="'+report+'"]').click(); //init the report, which will set everything except won't run the report

	//set dates
	let max_days = $('.view_report[data-intrac="'+report+'"]').prop('dataset').intrac_max_days || 90;
	let finish = dayjs().format('YYYY-MM-DD');
	let start = dayjs(finish).subtract(max_days-1, 'day').format('YYYY-MM-DD');
	$('#sh_reports .rep_start_date')[0]._flatpickr.setDate(start);
	$('#sh_reports .rep_finish_date')[0]._flatpickr.setDate(finish);
	$('#sh_reports .rep_dates_tr').removeClass('noshow');
	
	//run now with updated dates
	$('#report_summary_title .rep_sub_name').removeAttr('data-intrac_dont_run');
	run_report($('#reports .rep_report').val()); 
}

function run_lists() {
	let report_name = $(mc+' .lists_mode').val();

	let errors = [];
	let lists_data = {};

	$(mc+' .lists_filter.'+report_name).each(function () {
		let field = $(this).find('.form-control').attr('class')?.split(/\s+/).find(c => c.startsWith('lists_'))?.slice('lists_'.length);
		let value = $(this).find('.form-control').val();

		if (field.includes('dob') && value) {
			let value_ = ageToDate(value);
			if (!value_) {
				errors.push('One of the age fields is invalid, please check and re-try in the format of 5y or 18m etc.');
			} else {
				value = value_;
			}
		}

		if ($(this).find('.live_date').length) {
			if (value) {
				value = parse_date(value);
				if (!isvalidDate(value)) {
					errors.push('One of the date fields is invalid, please check and re-try');
				}
			}
		}

		//check for alt values in selects
		if ($(this).find('option').length) {
			if ($(this).find('option[value="'+value+'"]').prop('dataset')?.intrac_alt) {
				field = field+'_alt';
			}
		}

		if (field && value) {
			lists_data[field] = value;
		}
	});

	if (isEmptyJSON(lists_data)) {
		errors.push('Please enter at least one or more values in the filters and re-try');
	}

	errors = [...new Set(errors)]; //remove duplicates

	if (errors.length == 0) {
		$('<a>', {
		    class: 'view_report',
		    href: '#',
		    'data-intrac': report_name,
		    'data-intrac_fav_name': 'Queries',
		    'data-intrac_lists_data': JSON.stringify(lists_data)
		}).appendTo('body').trigger('click');

		close_modal();
	} else {
		set_side_error(errors.join("<br>"));
	}

	//convert age e.g. 5y/18m to dob
	function ageToDate(ageStr) {
	    const m = ageStr.match(/^(\d+)([ym])$/i);
	    if (!m) return null;

	    const value = parseInt(m[1], 10);
	    const unit  = m[2].toLowerCase() === 'y' ? 'year' : 'month';

	    return dayjs().subtract(value, unit).format('YYYY-MM-DD');
	}
}

function init_eftpos(code) {
    $('#loader-wrapper').show();

    let location_id = $('#location_id').val();

    let errors = [];
    //validations
    if (!code) {
    	errors.push('Invalid pairing code entered');
    }

    if (errors.length == 0) {
        $.ajax({
            type: 'POST',
            url: '/api/initEFTPOS',
            data: {code: code, location_id: location_id},
            dataType: 'JSON'
        }).done(async function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();
                set_side_error('EFTPOS paired succesfully', 'green', 'keep');

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });  
    }  else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();
    }    
}

function get_monthly_membs() {

    $(mc+' .monthly_membs_tab').html($('#master_proc_view .monthly_membs_tab').html()); //reset

    $('#loader-wrapper').show();

    $.ajax({
        type: 'GET',
        url: '/api/directProcess',
        data: {action: 'monthly_memberships'},
        dataType: 'JSON'
    }).done(function( response ) {

        if (response.success != undefined) {

            $('#loader-wrapper').hide();

            let res = response.success;

            let data = res.data;

            if (data.length) {
                $(mc+' .membership_note').html('The following membership fees will be added');

                let html_str = '';
                for (let i = 0; i < data.length; i++) {
                    let d = data[i];
                    let direct = d.direct ? '' : '*';
                    html_str += '<tr>\
                                    <td><a href="#" class="view_customer">'+d.first_name+' '+d.last_name+direct+'</a><span class="customer_id noshow">'+d.customer_id+'</span><span class="parent_id noshow">'+d.parent_id+'</span><span class="se_det noshow">'+(d.parent_id > 0 ? d.parent_id : d.customer_id)+'~'+d.first_name+' '+d.last_name+'~'+d.phone+'~'+d.email+'~'+d.altemail+'</span></td>\
                                    <td class="align-right">'+numberformatccy(d.cost)+'</td>\
                                </tr>';
                }

                $(mc+' .monthly_membs_list tbody').html(html_str); 
            } else {
                $(mc+' .membership_note').html('There are no memberships to process for this '+$('#pass_monthly_title').val());
            }

            if (res.purchases) {
            	$(mc+' .membership_note').html($(mc+' .membership_note').html()+'<br>'+res.purchases+' memberships have already been processed for this '+$('#pass_monthly_title').val());
            }

            if (res.last_run_date) {
            	$(mc+' .membership_note').html($(mc+' .membership_note').html()+'<br>'+'Memberships last created on '+convert_date(res.last_run_date));
            }

            if (res.disable_commit) {
            	$(mc+' .monthly_membsbtn_save').remove();
            }

        } else if (response.redirect != undefined) {
            mini_login_wizard(response.redirect); //session timeout case
        } else {    
            set_side_error(response.error.join("<br>"));
            $('#loader-wrapper').hide();
        }

    }).fail( function(xhr, textStatus, errorThrown) {
        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
        $('#loader-wrapper').hide();
    });       
}

function process_monthly_membs() {

    $('#loader-wrapper').show();

    $(mc+' .monthly_membsbtn_save').hide(); //hide the process button

    let data = {action: 'monthly_memberships', commit: true};

    $.ajax({
        type: 'GET',
        url: '/api/directProcess',
        data: data,
        dataType: 'JSON'
    }).done(function( response ) {

        if (response.success != undefined) {

            $('#loader-wrapper').hide();

            set_side_error('The memberships process is triggered successfully. This might take a minute or two', 'green', 'keep');

            close_modal();

        } else if (response.redirect != undefined) {
            mini_login_wizard(response.redirect); //session timeout case
        } else {    
            set_side_error(response.error.join("<br>"));
            $('#loader-wrapper').hide();
            $(mc+' .monthly_membsbtn_save').show();
            if (response.error.join(',').includes('already in progress')) {
            	close_modal();
            }            
        }

    }).fail( function(xhr, textStatus, errorThrown) {
        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
        $('#loader-wrapper').hide();
        //$(mc+' .monthly_membsbtn_save').show();

        set_side_error("This process might be still running in the background, please click on 'Membership Invoices tab' to check the current status");
        get_monthly_membs();
    });       
}

