function get_directs() {

    $(mc+' .directs_tab').html($('#master_proc_view .directs_tab').html()); //reset

    $('#loader-wrapper').show();

    $.ajax({
        type: 'GET',
        url: '/api/directProcess',
        data: {action: 'directs'},
        dataType: 'JSON'
    }).done(function( response ) {

        if (response.success != undefined) {

            $('#loader-wrapper').hide();

            let res = response.success;

            let data = res.data;

            let html_str = '';
            html_str += '<thead><tr>\
                            <th>Name</th>\
                            <th class="align-right">Amount</th>\
                            '+($('.surcharge_items').length ? '<th class="align-right">'+$('.surcharge-title:first').text()+'</th>' : '')+'\
                            <th>Comments</th>\
                        </tr></thead><tbody>';

            if (data.length) {
                $(mc+' .directs_note').html('Payments to be processed');
                let total = 0;
                let total_surcharge = 0;
                for (let i = 0; i < data.length; i++) {
                    let d = data[i];
                    html_str += '<tr>\
                                    <td><a href="#" class="view_customer">'+d.first_name+' '+d.last_name+'</a><span class="customer_id noshow">'+d.customer_id+'</span><span class="parent_id noshow">'+d.parent_id+'</span><span class="se_det noshow">'+(d.parent_id > 0 ? d.parent_id : d.customer_id)+'~'+d.first_name+' '+d.last_name+'~'+d.phone+'~'+d.email+'~'+d.altemail+'</span></td>\
                                    <td class="align-right">'+numberformatccy(d.amount)+'</td>\
                                    '+($('.surcharge_items').length ? '<td class="align-right">'+numberformatccy(d.surcharge)+'</td>' : '')+'\
                                    <td>'+(d.pending ? 'Current payment pending' : '')+'</td>\
                                </tr>';
                    total += d.amount;
                    if ($('.surcharge_items').length) {
                    	total_surcharge += d.surcharge;
                    }
                }

                if (data.length) {
                    html_str += '<tr>\
                                    <td><b>Total</b></td>\
                                    <td class="align-right">'+numberformatccy(total)+'</td>\
                                    '+($('.surcharge_items').length ? '<td class="align-right">'+numberformatccy(total_surcharge)+'</td>' : '')+'\
                                    <td></td>\
                                </tr>';
                }

            } else {
                $(mc+' .directs_note').html('There are no outstanding accounts to process');
            }

            html_str += '</tbody>';
            $(mc+' .directs_list table').html(html_str); 

            if (data.filter(item => !item.pending).length) {
            	$(mc+' .directsbtn_save').removeClass('noshow');
            }

        } else if (response.redirect != undefined) {
            mini_login_wizard(response.redirect); //session timeout case
        } else {    
            set_side_error(response.error.join("<br>"));
            $('#loader-wrapper').hide();
        }

    }).fail( function(xhr, textStatus, errorThrown) {
        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
        $('#loader-wrapper').hide();
    });       
}

