function get_direct_history(rawcsv='') {

    $(mc+' .directs_tab').html($('#master_proc_view .directs_tab').html()); //reset
    $(mc+' .directs_tab .direct_history').remove();
    $(mc+' .directs_tab .get_directs').removeClass('noshow');
    $(mc+' .directs_tab .directsbtn_save').remove();

    $('#loader-wrapper').show();

    $.ajax({
        type: 'GET',
        url: '/api/directProcess',
        data: {action: 'directs_history'},
        dataType: 'JSON'
    }).done(function( response ) {

        if (response.success != undefined) {

            $('#loader-wrapper').hide();

            let res = response.success;

            let data = res.data;

            let status = {
                "0" : "Approved",
                "1" : "Declined",
                "2" : "Pending",
                "3" : "Error" 
            };

            let html_str = '';
            html_str += '<thead><tr>\
                            <th>Date</th>\
                            <th>Name</th>\
                            <th class="align-right">Amount</th>\
                            '+($('.surcharge_items').length ? '<th class="align-right">'+$('.surcharge-title:first').text()+'</th>' : '')+'\
                            <th>Status</th>\
                            <th>Details</th>\
                        </tr></thead><tbody>';

            if (data.length) {
                $(mc+' .directs_note').html('Recent payments - since '+convert_date(res.since));
                for (let i = 0; i < data.length; i++) {
                    let d = data[i];
                    html_str += '<tr>\
                                    <td>'+convert_date_time(d.direct_time)+'</td>\
                                    <td><a href="#" class="view_customer">'+d.first_name+' '+d.last_name+'</a><span class="customer_id noshow">'+d.customer_id+'</span><span class="parent_id noshow">'+d.parent_id+'</span><span class="se_det noshow">'+(d.parent_id > 0 ? d.parent_id : d.customer_id)+'~'+d.first_name+' '+d.last_name+'~'+d.phone+'~'+d.email+'~'+d.altemail+'</span></td>\
                                    <td class="align-right">'+numberformatccy(d.amount)+'</td>\
                                    '+($('.surcharge_items').length ? '<td class="align-right">'+numberformatccy(d.surcharge)+'</td>' : '')+'\
                                    <td>'+status[d.status]+'</td>\
                                    <td>'+d.direct_comment+'</td>\
                                </tr>';
                }

            } else {
                $(mc+' .directs_note').html('No direct payment records from the past month');
            }

            html_str += '</tbody>';
            $(mc+' .directs_list table').html(html_str); 

            if (rawcsv) {
                if (data.length) {
                    let dataArry = [];
                    for (let i = 0; i < data.length; i++) {
                    	let d = data[i];
                    	let obj = {
                            date: convert_date_time(d.direct_time),
                            customer: d.first_name+' '+d.last_name,
                            customer_id: d.customer_id,
                            mobile: d.phone,
                            status: status[d.status],
                            details: d.direct_comment,
                            amount: numberformatccy(d.amount)
                        };
                        if ($('.surcharge_items').length) {
                        	obj[$('.surcharge-title:first').text().toLowerCase()] = numberformatccy(d.surcharge);
                        }
                        dataArry.push(obj);
                    }
                    downloadCSV(dataArry);
                }
            }

        } else if (response.redirect != undefined) {
            mini_login_wizard(response.redirect); //session timeout case
        } else {    
            set_side_error(response.error.join("<br>"));
            $('#loader-wrapper').hide();
        }

    }).fail( function(xhr, textStatus, errorThrown) {
        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
        $('#loader-wrapper').hide();
    });       
}

