function build_weather_html(data, from='getWeathers') {
    let html_str = '';

    for (let i = 0; i < data.length; i++) {
        let d = data[i];

        let desc = convert_date_time(d.schedule_start)+' - '+convert_date_time(d.schedule_finish, 'h:mma');
        if (d.class_name) {
        	desc += ' '+d.class_name;
        }
        if (d.username) {
        	desc += ' '+d.username;
        }
        if (d.space_name) {
        	desc += ' '+d.space_name;
        }
        d.credit = d.credit === null ? '' : d.credit;
        html_str += '<tr>\
                        '+(from == 'getWeathers' ? '<td><div class="form-label"><label class="checkbox-container">&nbsp;<input type="checkbox" class="checkbox-custom wthr_item" value="'+d.register_mode+'" data-intrac_register_id="'+(d.register_id || '')+'" data-intrac_schedule_id="'+(d.schedule_id || '')+'" data-intrac_credit="'+d.credit+'" checked></label></div></td>' : '')+'\
                        <td>'+d.type_str+'</td>\
                        <td><a href="#" class="view_customer">'+d.first_name+' '+d.last_name+'</a><span class="customer_id noshow">'+d.customer_id+'</span><span class="parent_id noshow">'+d.parent_id+'</span><span class="se_det noshow">'+(d.parent_id > 0 ? d.parent_id : d.customer_id)+'~'+d.first_name+' '+d.last_name+'~'+d.phone+'~'+d.email+'~'+d.altemail+'</span></td>\
                        <td>'+(validator.isFloat(d.credit.toString()) ? numberformatccy(d.credit) : d.credit)+'</td>\
                        <td>'+desc+'</td>\
                        '+(from == 'saveWeather' ? '<td>'+(d.processed === true ? 'Processed' : (d.processed || ''))+'</td>' : '')+'\
                    </tr>';
    }

    return html_str;
}

