function save_weather() {

    $('#loader-wrapper').show();

    let location_id = $('#location_id').val();

    let data = {
    	location_id: location_id,
    	weather_date: parse_date($(mc+' .weather_date').val()),
    	weather_start: parse_time($(mc+' .weather_start').val()),
    	weather_finish: parse_time($(mc+' .weather_finish').val()),
    	weather_comment: $(mc+' .weather_comment').val(),
    	schedule_ids: [],
    	register_ids: []
    } 

    $(mc+' .wthr_item').each(function () {
       	if (this.checked) {

       		let schedule_id = $(this).prop('dataset').intrac_schedule_id;
       		let register_id = $(this).prop('dataset').intrac_register_id;

       		if (register_id > 0) {
       			data.register_ids.push(register_id)
       		} else if (schedule_id > 0) {
       			data.schedule_ids.push(schedule_id)
       		} else {
       			if (!errors.length) {
       				errors.push('Something went wrong! Please try again')	
       			}
       		}
       	}
    });

    let errors = [];
    //validations
    if (dayjs(data.weather_date).isBefore(dayjs(dayjs().subtract(4, 'day').format('YYYY-MM-DD')))) {
    	errors.push('Date can only be upto 4 days in the past');
    }

    if (errors.length == 0) {
        $.ajax({
            type: 'POST',
            url: '/api/saveWeather',
            data: data,
            dataType: 'JSON'
        }).done(function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

				$(mc+' .weather_steps').addClass('noshow');
				$(mc+' .weather_results').removeClass('noshow');

				let res = response.success;

	            let data = res.data;

	            let html_str = build_weather_html(data, 'saveWeather');

	            $(mc+' .weather_results_list tbody').html(html_str);
	            $(mc+' .weather_bookings_list tbody').html(''); //clear to avoid duplicate SMSs

	            if (html_str) {
                	$(mc+' .weather_tab .sms_lnk').removeClass('noshow');
                	$(mc+' .weather_tab .email_lnk').removeClass('noshow');
	            }

	            //refresh grid
	            if ($('#spaces').is(":visible") || $('#lessons').is(":visible")) {
	            	get_grid(false);
	            } else if ($('#classes').is(":visible")) {
                	get_class_grid(false);
                } else if ($('#rosters').is(":visible")) {
                	get_roster_grid(false);
                }

                if (response.info.length) {
                    set_side_error(response.info.join("<br>"), 'amber');
                }

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });  
    }  else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();        
    }            
}

function get_upd_classes() {
    $('#loader-wrapper').show();

    let location_id = $('#location_id').val();

    $.ajax({
        type: 'GET',
        url: '/api/getClasss',
        data: {orderby: 'location_orders'},
        dataType: 'JSON'
    }).done(function( response ) {

        if (response.success != undefined) {

            $('#loader-wrapper').hide();

            let res = response.success;

            let data = res.data;

            let html_str = '';

	        let status_map = {
	            0: '<span class="event-status bg-gray-100 text-gray"><span class="size-1.5 bg-gray rounded-[20px]"></span> Archive</span>',
	            1: '<span class="event-status bg-yellow-100 text-black"><span class="size-1.5 bg-yellow rounded-[20px]"></span> Renewals</span>',
	            2: '<span class="event-status text-purple-dark bg-purple-pretty"><span class="size-1.5 bg-purple-dark rounded-[20px]"></span> Returning Customers</span>',
	            3: '<span class="event-status bg-blue-100 text-blue"><span class="size-1.5 bg-blue rounded-[20px]"></span> Changes</span>',
	            4: '<span class="event-status bg-green-100 text-green"><span class="size-1.5 bg-green rounded-[20px]"></span> Open</span>',
	            5: '<span class="event-status bg-coral-100 text-coral"><span class="size-1.5 bg-coral rounded-[20px]"></span> Closed</span>'
	        }

            for (let i = 0; i < data.length; i++) {
                let d = data[i];

                let loc_name = !$('#main_switch_location').closest('.locations').hasClass('noshow') ? (d.location_name+': ') : '';

                if (((d.level_type == 0) || (d.level_type == 1)) && (dates_diff(d.term_finish, dayjs().format('YYYY-MM-DD')) >= 0)) {
	                html_str += '<tr>\
	                				<td><div class="form-label"><label class="checkbox-container">&nbsp;<input type="checkbox" class="checkbox-custom updcls_item" value="'+d.class_id+'"></label></div></td>\
	                                <td>'+loc_name+d.class_name+'</td>\
	                                <td>'+status_map[d.status]+'</td>\
	                            </tr>';
                }
            }

            $(mc+' .upd_classes_list tbody').html(html_str);

        } else if (response.redirect != undefined) {
            mini_login_wizard(response.redirect); //session timeout case
        } else {    
            set_side_error(response.error.join("<br>"));
            $('#loader-wrapper').hide();
        }

    }).fail( function(xhr, textStatus, errorThrown) {
        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
        $('#loader-wrapper').hide();
    }); 	
}

