function build_multir_html(data, from='get_multir') {
    let html_str = '';

    for (let i = 0; i < data.length; i++) {
        let d = data[i];
        d.discount = d.amount-d.new_amount;

        html_str += '<tr>\
                        '+(from == 'get_multir' ? '<td><div class="form-label"><label class="checkbox-container">&nbsp;<input type="checkbox" class="checkbox-custom multir_item" value="'+d.register_id+'" data-intrac_discount="'+d.discount+'" checked></label></div></td>' : '')+'\
                        <td>'+d.class_name+'</td>\
                        <td><a href="#" class="view_customer">'+d.first_name+' '+d.last_name+'</a><span class="customer_id noshow">'+d.customer_id+'</span><span class="parent_id noshow">'+d.parent_id+'</span></td>\
                        <td>'+(d.registers ? d.registers.length : (d.pass_id > 0 ? 'N/A - '+$('#pass_title').val() : ''))+'</td>\
                        <td>'+numberformatccy(d.amount)+'</td>\
                        <td>'+numberformatccy(d.new_amount)+'</td>\
                        <td>'+numberformatccy(d.discount)+'</td>\
                        '+(from == 'save_multir' ? '<td>'+(d.processed === true ? 'Processed' : (d.processed || ''))+'</td>' : '')+'\
                    </tr>';
    }

    return html_str;
}

