function show_template_preview() {
    let subject = $(mc+' .tmp_details_subject').val();
    let data = $(mc+' .tmp_template_data').val();

    if ($(mc+' .tmp_shellemail').text()) {
        let shellemail = $(mc+' .tmp_shellemail').text();
        shellemail = shellemail.replace(/##template/,data).replace(/.email-body/g, mc+' .template_html_preview');
        data = shellemail; //override
    }

    if (subject) {
        data = 'Subject: '+subject+'<br><br>'+data;
    }

    //handle variables
    $(mc+' .leg_name').each(function () {

    	if (!$(this).closest('p').hasClass('noshow')) {
	        let name = $(this).text();

	        let ex = $(this).closest('p').find('.leg_example');
	        let example = $(ex).is("select") ? $(ex).val() : ($(ex).html().includes('br') ? $(ex).html() : $(ex).text());

	        data = data.replaceCase(name,example);
    	}
    });

    data = data.replaceCase('##no_shellemail','');

    //handle conditions
    data = evalTemplateRules(data);

    if (data.includes('<style>')) { //raw HTML template copied from another tool
        //transform body {} and html {} in css of data to .template_html_preview {}, so that global body sytles of this page is not impacted
        data = data.replace(
                    /<style[^>]*>([\s\S]*?)<\/style>/gi,
                    (m, css) => {
                        css = css.replace(
                            /(^\s*|\})\s*(html|body)\s*\{/gmi,
                            '$1'+mc+' .template_html_preview'+' {'
                        );
                        return `<style>${css}</style>`;
                    }
                );
    }

    $(mc+' .template_html_preview').html(data);
}

function get_class_notices() {

    let data = {
    	term_id: $(mc+' .notices_term_id').val(),
    	action: $(mc+' .notice_template_id option:selected').prop('dataset').intrac
    }

    if (data.action == 'emailclassupcoming') {
    	$(mc+' .leg_term_dates').removeClass('noshow');
    	$(mc+' .leg_term_holidays').removeClass('noshow');
    	$(mc+' .leg_items').removeClass('noshow');;
    } else {
    	$(mc+' .leg_term_dates').addClass('noshow');
    	$(mc+' .leg_term_holidays').addClass('noshow');
    	$(mc+' .leg_items').addClass('noshow');
    }

    if (data.term_id && data.action) {

	    $('#loader-wrapper').show();

	    $.ajax({
	        type: 'GET',
	        url: '/api/noticesProcess',
	        data: data,
	        dataType: 'JSON'
	    }).done(function( response ) {

	        if (response.success != undefined) {

	            $('#loader-wrapper').hide();

	            let res = response.success;

	            //template
                $(mc+' .tmp_template_data').val(res.template.template_data);

                if (res.shellemail) {
                    $(mc+' .tmp_shellemail').text(res.shellemail);
                }

                //template_details - optional
                let template_details = res.template.template_details;
                $(mc+' .tmp_details_subject').val(template_details ? (template_details.subject || '') : '');

                let quill = Quill.find($(mc+' .class_notice_template')[0]);
                quill.clipboard.dangerouslyPasteHTML($(mc+' .tmp_template_data').val());
                quill.blur();

                //data
	            let data = res.data;

	            let html_str = '';
	            let html_str_ = '';

	            let show_email_lnk = false;
	            let show_sms_lnk = false;

	            if (data.length) {
		            for (let i = 0; i < data.length; i++) {
		                let d = data[i];

		                if (validator.isEmail(d.email)) {
		                	show_email_lnk = true;

			                html_str += '<tr>\
			                                <td>'+d.first_name+' '+d.last_name+' &lt;'+d.email+'&gt;</td>\
			                            </tr>';

			                if (validator.isEmail(d.altemail)) {
				                html_str += '<tr>\
				                                <td>'+d.first_name+' '+d.last_name+' &lt;'+d.altemail+'&gt;</td>\
				                            </tr>';
			                }            

			                //update legend
			                if (i == 0) {
			                	$(mc+' .leg_first_name .leg_example').text(d.first_name);
			                	$(mc+' .leg_term_name .leg_example').text(d.term_name);
			                	$(mc+' .leg_term_dates .leg_example').html(d.term_start ? toTitleCase($('#term_title').val())+' dates: '+convert_date(d.term_start)+' - '+convert_date(d.term_finish)+'<br>' : '');
			                	$(mc+' .leg_term_holidays .leg_example').html(d.term_holidays || '');
			                	$(mc+' .leg_items .leg_example').html(d.items || '');
			                }

		                } else {
		                	show_sms_lnk = true;

			                html_str_ += '<tr>\
			                                <td>'+d.first_name+' '+d.last_name+'<span class="se_det noshow">'+(d.parent_id > 0 ? d.parent_id : d.customer_id)+'~'+d.first_name+' '+d.last_name+'~'+d.phone+'~'+d.email+'~'+d.altemail+'</span></td>\
			                            </tr>';

		                }
		            }

		            html_str += html_str_;
		        } else {
	            	html_str += '<tr><td>No data to show</td></tr>'
	            }

	            $(mc+' .notice_customers_list tbody').html(html_str);

	            if (show_email_lnk) {
	            	$(mc+' .class_noticebtn_send').removeClass('noshow');
	            	$(mc+' .sample_email_div').show();
	            } else {
	            	$(mc+' .class_noticebtn_send').addClass('noshow');
	            	$(mc+' .sample_email_div').hide();
	            }

	            if (show_sms_lnk) {
	            	$(mc+' .class_notices_tab .sms_lnk').removeClass('noshow');
	            } else {
	            	$(mc+' .class_notices_tab .sms_lnk').addClass('noshow');
	            }

	            //other classes
		        let status_map = {
		            0: '<span class="event-status bg-gray-100 text-gray"><span class="size-1.5 bg-gray rounded-[20px]"></span> Archive</span>',
		            1: '<span class="event-status bg-yellow-100 text-black"><span class="size-1.5 bg-yellow rounded-[20px]"></span> Renewals</span>',
		            2: '<span class="event-status text-purple-dark bg-purple-pretty"><span class="size-1.5 bg-purple-dark rounded-[20px]"></span> Returning Customers</span>',
		            3: '<span class="event-status bg-blue-100 text-blue"><span class="size-1.5 bg-blue rounded-[20px]"></span> Changes</span>',
		            4: '<span class="event-status bg-green-100 text-green"><span class="size-1.5 bg-green rounded-[20px]"></span> Open</span>',
		            5: '<span class="event-status bg-coral-100 text-coral"><span class="size-1.5 bg-coral rounded-[20px]"></span> Closed</span>'
		        }

	            let other_classes = res.otherstate_classes;

	            let html_str_c = '';

	            if (other_classes.length) {
	            	$(mc+' .class_notice_otherstate_div').show();

		            for (let i = 0; i < other_classes.length; i++) {
		                let d = other_classes[i];

		                let loc_name = !$('#main_switch_location').closest('.locations').hasClass('noshow') ? (d.location_name+': ') : '';

		                html_str_c += '<tr>\
		                                <td>'+loc_name+d.class_name+'</td>\
		                                <td>'+status_map[d.status]+'</td>\
		                            </tr>';
		            }

	            } else {
	            	$(mc+' .class_notice_otherstate_div').hide();
	            }

	            $(mc+' .notice_other_class_list tbody').html(html_str_c);

	            $(mc+' .show_template_preview').click(); //show preview mode by default

	        } else if (response.redirect != undefined) {
	            mini_login_wizard(response.redirect); //session timeout case
	        } else {
	        	set_side_error(response.error.join("<br>"));     	
	            $('#loader-wrapper').hide();
	        }

	    }).fail( function(xhr, textStatus, errorThrown) {
	        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
	        $('#loader-wrapper').hide();
	    }); 
	}    
}

function send_class_notices(sample='') {

    $('#loader-wrapper').show();

    let data = {
    	term_id: $(mc+' .notices_term_id').val(),
    	action: $(mc+' .notice_template_id option:selected').prop('dataset').intrac,
    	commit: true,
    	sample: sample
    }

    if (sample) {
    	data.sample = sample;
    }

    let errors = [];
    //validations

    if (!data.term_id || !data.action) {
        errors.push("Something went wrong! Please refresh the page and re-try");
    }

    if (errors.length == 0) {
        $.ajax({
            type: 'GET',
            url: '/api/noticesProcess',
            data: data,
            dataType: 'JSON'
        }).done(function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

                let msgs = response.success.data.filter(item => validator.isEmail(item.email)).length;

                if (sample) {
                	set_side_error('Sample notice sent succesfully', 'green');	
                } else {
                	set_side_error(msgs+' notices sent succesfully', 'green', 'keep');
                }

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });  
    }  else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();        
    }            
}

