function getAssesssResults(res) {

	let data = res.data;

    let html_str_s = '';
    let html_str_d = '';
    let opts_str = '<option value="">All Instructors</option>';

    html_str_s += '<div class="table-wrapper"><table class="table">\
                    <thead>\
                        <tr>\
                            <th>Instructor</th>\
                            <th class="align-right">Total</th>\
                            <th class="align-right">Left</th>\
                            '+(res.options.show_overdue ? '<th class="align-right">Overdue</th>' : '')+'\
                            <th>Actions</th>\
                        </tr>\
                    </thead>\
                    <tbody>';

    for (let i = 0; i < data.length; i++) {
    	let d = data[i];

    	//summary
        html_str_s += '<tr>\
                            <td>'+d.username+'<span class="user_id noshow">'+d.user_id+'</span></td>\
                            <td class="align-right">'+d.all+'</td>\
                            <td class="align-right">'+d.left+'</td>\
                            '+(res.options.show_overdue ? '<td class="align-right">'+d.overdue+'</td>' : '')+'\
                            <td><ul>\
                                    <li><a href="#" class="btn-edit view_assess_user" data-intrac="'+d.user_id+'">View Details</a></li>\
                                </ul></td>\
                        </tr>';

        //user details - dropdown
        opts_str += '<option value="'+d.user_id+'">'+(d.username || 'No Instructor')+'</option>';

        //user details
        let programs_ids = d.details.map(item => item.program_id);
        programs_ids = [...new Set(programs_ids)]; //remove duplicates

        for (let n = 0; n < programs_ids.length; n++) {

        	let p_data = d.details.filter(item => item.program_id == programs_ids[n]);

        	//program header
        	let header = '';

        	if (programs_ids[n] > 0) {
	            header = p_data[0].day.substring(1)+' '+convert_time(p_data[0].program_start,'h:mma')+'-'+convert_time(p_data[0].program_finish,'h:mma');
	            if (d.username) {
	                header += ' ('+d.username+')';
	            }
        	}

        	let sub_header = p_data[0].space_name;

        	let header_str = p_data[0].class_name+(header ? ' - '+header : '')+(sub_header ? '<br>'+sub_header : '');

            html_str_d += '<div class="table-wrapper assesssrch_table" data-intrac="'+d.user_id+'"><table class="table">\
                            <thead>\
                                <tr>\
                                    <th class="w-75p">'+header_str+'</th>\
                                    <th>Last Updated</th>\
                                    <th>Actions</th>\
                                </tr>\
                            </thead>\
                            <tbody>';

            //program data
            for (let k = 0; k < p_data.length; k++) {
            	let d_ = p_data[k];

                let age = (getAge(d_.dob)) ? ' ('+getAge(d_.dob)+')' : '';
                if (d_.details && d_.details.schoolyear) {
                    age = ' ('+d_.details.schoolyear+')';
                }

                let incomplete = d_.completed ? '' : ' #';
                if (!$(mc3+' .assess_options').prop('dataset').intrac_optional && !$(mc3+' .assess_options').prop('dataset').intrac_click_model) {
                	incomplete = '';
                }
                let last_updated = d_.assess ? convert_date(d_.assess.updated) : '';

                html_str_d += '<tr class="assess_cust_item">\
                                <td class="w-75p"><span class="register_id noshow">'+d_.register_id+'</span><span class="assess_id noshow">'+(d_.assess?.assess_id || 'new')+'</span><span class="customer_id noshow">'+d_.customer_id+'</span><span class="parent_id noshow">'+d_.parent_id+'</span>'+(k+1)+'. '+'<a href="#" class="view_customer">'+d_.first_name+' '+d_.last_name+age+incomplete+'</a></td>\
                                <td>'+last_updated+'</td>\
                                <td><ul>\
                                        <li><a href="#" class="btn-edit view_assess_customer">Assess</a></li>\
                                    </ul>\
                                </td>\
                            </tr>';

            }

            //close table
            html_str_d += '</tbody></table></div>'             	
        }

    }

	//close table
	html_str_s += '</tbody></table></div>';

    $(mc3+' .assess_summary_list').html(html_str_s);
    $(mc3+' .assess_details_list').html(html_str_d);

    if ($(mc3+' .assesssrch_user_id option').length) {
    	$(mc3+' .assesssrch_user_id').change(); //trigger change
    } else {
    	$(mc3+' .assesssrch_user_id').html(opts_str);
    }
}

function reset_cust_assess_data() {
	$(mc3+' .modal_title_mc3').text('');
	$(mc3+' .assess_cust_tab').html($('#master_assess_view .assess_cust_tab').html());
}

function get_cust_assess(customer_id, assess_id='') {

    if (!$(mc3).hasClass('modal-open')) {
        $('.modal_o_assess:first').click();   
    }

    if (!$(mc3+' .tl_assess_cust').hasClass('active')) {
    	$(mc3+' .tab-list').html($('#master_assess_view .tab-list').html());
    	$(mc3+' .tl_assess_cust').click(); 
    }
    
    reset_cust_assess_data();

    $('#loader-wrapper').show();

    if (customer_id) {

    	let querydata = {customer_id: customer_id};

        if ($('.instructor-page').length) {
            querydata.from = 'instructor';
        }

        $.ajax({
            type: 'GET',
            url: '/api/getAssesss',
            data: querydata,
            dataType: 'JSON'
        }).done(function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

                let res = response.success;

                let cust_name = res.customer.first_name+' '+res.customer.last_name;

                $(mc3+' .assess_customer_id').val(customer_id);
                $(mc3+' .assess_customer_level_id').val(res.customer.level_id);
                $('.modal_title_mc3').text(cust_name+' ('+res.customer.level_name.trim()+')');

                //data
                let data = res.data;

                let cur_assess = false;

                let html_str = '';

                for (let i = 0; i < data.length; i++) {

                    html_str += '<tr class="assess_item">\
                                    <td><span class="assess_id noshow">'+data[i].assess_id+'</span>'+data[i].level_name+'</td>\
                                    <td>'+convert_date(data[i].updated)+'</td>\
                                    <td><ul class="!items-start">\
                                            <li><a href="#" class="btn-edit view_assess" data-intrac_assess_id="'+data[i].assess_id+'">'+($(mc3+' .assessbtn_save').length ? 'Edit' : 'View')+'</a></li>\
                                            '+($(mc3+' .assessbtn_save').length ? '<li><a href="#" class="btn-edit delete_assess">Delete</a></li>' : '')+'\
                                            <li><a href="api/printAssessment?customer_id='+customer_id+'&assess_id='+data[i].assess_id+'" class="btn-edit a_direct" target="_blank">Certificate</a></li>\
                                        </ul></td>\
                                </tr>';

                    if (res.customer.level_id == data[i].level_id) {
                    	cur_assess = true;
                    }            
                }

                $(mc3+' .cust_assess_list tbody').html(html_str);

                if (!cur_assess) {
                	$(mc3+' .add_assess').removeClass('noshow');
                } else {
                	$(mc3+' .add_assess').addClass('noshow');
                }

                if (assess_id) {
                	if (assess_id == 'new') {
                		if (cur_assess) {
                			set_side_error("Customer's level is changed. Unable to add an assessment for the old level", 'amber')
                		} else {
                			$(mc3+' .add_assess').click();
                		}
                	} else {
                		$(mc3+' .view_assess[data-intrac_assess_id="'+assess_id+'"]').click();	
                	}              	
                }

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        }); 
    } else {
        $('#loader-wrapper').hide();
    }
}

function viewAsses(assess_id) {

	let customer_id = $(mc3+' .assess_customer_id').val();

    if (assess_id && customer_id) {
    	$('#loader-wrapper').show();

    	$(mc3+' .assess_form').html($('#master_assess_view .assess_form').html());

    	let querydata = {customer_id: customer_id, assess_id: assess_id};

        if ($('.instructor-page').length) {
            querydata.from = 'instructor';
        }

        $.ajax({
            type: 'GET',
            url: '/api/getAssesss',
            data: querydata,
            dataType: 'JSON'
        }).done(function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();

                let res = response.success;

                if (assess_id > 0) {
                	$(mc3+' .assess_assess_id').val(assess_id);	
                	$(mc3+' .assess_level_name').text(res.data[0]?.level_name);	
                } else {
                	$(mc3+' .assess_level_name').text(res.customer.level_name);		
                }

                //template
                let template = res.template.template_data;

                if (template.show_comments) {
                    $(mc3+' .assess_comment_div').removeClass('noshow')
                } else {
                    $(mc3+' .assess_comment_div').remove();
                }

                let assess_config = template.assess_config || [];

                let html_str = '';

                for (let i = 0; i < assess_config.length; i++) {
                    let a = assess_config[i];

                    let category_name = a.category_name;
                    
                    for (let k = 0; k < a.aconfig.length; k++) {
                        let s = a.aconfig[k];

                        let skill = s.skill;
                        let skill_values = s.skill_values.split(',');

                        let opts_str = '<option value=""></option>';
                        for (let m = 0; m < skill_values.length; m++) {
                            opts_str += '<option value="'+skill_values[m]+'">'+skill_values[m]+'</option>'
                        }

                        if (res.options.assess_click_model) {
	                        html_str += '<div class="form-group flex-div margin_bottom_md">\
	                                        <div class="label no_margin_btm mw-60p">'+skill+'</div>\
	                                        <div class="align-right flex-1">\
	                                        	<a href="#" class="btn-link label-link assess_record_date noshow">Record achievement</a>\
	                                        	<input type="text" class="form-control aconfig_item noshow" data-intrac="'+s.skill_id+'" value="">\
	                                        </div>\
	                                    </div>';
                        } else {
	                        html_str += '<div class="form-group">\
	                                        <div class="label">'+(assess_config.length > 1 ? category_name+': '+skill : skill)+'</div>\
	                                        <select class="form-control aconfig_item" data-intrac="'+s.skill_id+'">'+opts_str+'</select>\
	                                    </div>';
                        }
                    }
                }

                $(mc3+' .assess_configs').html(html_str);

                //data
                let data = res.data;

                if (data.length) {
                    let itemobj = data[0].assess_data;

                    let aconfig = itemobj.aconfig;

                    for(const key in aconfig) {
                    	$(mc3+' .aconfig_item[data-intrac="'+key+'"]').val(aconfig[key]);
                    	
                    	if (res.options.assess_click_model) {
                    		if (isvalidDate(aconfig[key])) {
                    			$(mc3+' .aconfig_item[data-intrac="'+key+'"]').closest('div').find('.assess_record_date').replaceWith('<span class="text-gray">Achieved on '+convert_date(aconfig[key])+'<a href="#" class="btn-link label-link assess_delete_date margin_left_sm noshow">Delete</a></span>');
                    		}
                    	}
                    }

                    $(mc3+' .assess_comment').val(itemobj.comment || '');

                    $(mc3+' .assess_primary_user_id').val($(mc3+' .assess_primary_user_id option[value="'+$('#user_id').val()+'"]').length ? $('#user_id').val() : data[0].primary_user_id);
                } else {
                	$(mc3+' .assess_primary_user_id').val($('#user_id').val());
                }

    			if ($(mc3+' .assessbtn_save').length) {
    				$(mc3+' .assess_record_date').removeClass('noshow');
    				$(mc3+' .assess_delete_date').removeClass('noshow');
    			}

                $(mc3+' .assess_form').removeClass('noshow');

			    $(mc3+' .new-modal-content').animate({
			        scrollTop: $(mc3+' .assess_form').position().top + $(mc3+' .new-modal-content').scrollTop() - $(mc3 + ' .modal-header').outerHeight()
			    }, 500); 

			    //promote
			    if (res.options.assess_click_model) {
			    	if (!$(mc3+' .assess_record_date').length) {
			    		$(mc3+' .assess_promote_div').show();
			    		$(mc3+' .assess_promote_div .level_id').val($(mc3+' .assess_customer_level_id').val());
			    	}
			    }

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        }); 
    }
}

function saveAssess(reopen=false) {

    $('#loader-wrapper').show();

    let errors = [];

    //prepare the data
    let data ={
        assess_id: $(mc3+' .assess_assess_id').val(),
        customer_id: $(mc3+' .assess_customer_id').val(),
        primary_user_id: $(mc3+' .assess_primary_user_id').val() || '0'
    };

    if (!data.assess_id) {
    	data.level_id = $(mc3+' .assess_customer_level_id').val()
    }

    let assess_data = {aconfig: {}};

    $(mc3+' .aconfig_item').each(function () {
        let key = $(this).prop('dataset').intrac;
        let value = $(this).val();
        assess_data.aconfig[key] = value;

        if (!value && !$(mc3+' .assess_options').prop('dataset').intrac_optional && !$(mc3+' .assess_options').prop('dataset').intrac_click_model) {
        	if (!errors.length) {
        		errors.push('Please select an option for all assessment criteria');	
        	}
        }
    });

    if ($(mc3+' .assess_comment').is(":visible")) {
        assess_data.comment = $(mc3+' .assess_comment').val().trim();       
    }

    data.assess_data = JSON.stringify(assess_data);

    let qry_from = '';
    if ($('.instructor-page').length) {
        qry_from = '?from=instructor';
    }

    //console.log(data);

    //validations

    if (errors.length == 0) {

        $.ajax({
            type: 'POST',
            url: '/api/saveAssess'+qry_from,
            data: data,
            dataType: 'JSON'
        }).done(function( response ) {

            if (response.success != undefined) {

                $('#loader-wrapper').hide();
                set_side_error('Assessment saved succesfully', 'green');
                
                if ($('.instructor-page').length) {
                	if (reopen) {
                		//refresh data
                		get_cust_assess(data.customer_id,(reopen ? (data.assess_id || response.success) : ''));
                	} else {
                		close_modal3();
                	}

	                //refresh class attendance
	                if (($(mc).hasClass('modal-open')) && $(mc+' .tl_attendance').hasClass('active')) {
	                	get_class_attendance();
	                }
                } else {
                	//refresh data
                	get_cust_assess(data.customer_id,(reopen ? (data.assess_id || response.success) : ''));
                	get_api('getAssesss', true);
                }

            } else if (response.redirect != undefined) {
                mini_login_wizard(response.redirect); //session timeout case
            } else {    
                set_side_error(response.error.join("<br>"));
                $('#loader-wrapper').hide();
            }

        }).fail( function(xhr, textStatus, errorThrown) {
            set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
            $('#loader-wrapper').hide();
        });
    } else {
        set_side_error(errors.join("<br>"));
        $('#loader-wrapper').hide();        
    }  
          
}

