function get_gcards() {

    //can't reset gcards_tab because of date
    $(mc+' .gcards_list').html($('#master_gcard_view .gcards_list').html());
    $(mc+' .gsusp_list').html($('#master_gcard_view .gsusp_list').html());
    $(mc+' .gsusp_form').html($('#master_gcard_view .gsusp_form').html());
    $(mc+' .gsusp_form').hide();

    $('#loader-wrapper').show();

    let location_id = $('#location_id').val();

    $.ajax({
        type: 'GET',
        url: '/api/getCards',
        data: {date: $(mc+' .gcard_date').val(), location_id: location_id},
        dataType: 'JSON'
    }).done(function( response ) {

        if (response.success != undefined) {

            $('#loader-wrapper').hide();

            let res = response.success;

            let html_str = '';
            for (let i = 0; i < res.data.length; i++) {
                let d = res.data[i];
                
                let team1 = (d.team1_name || '');
                let team2 = (d.team2_name || '');

                if (d.orders == 1) {
                    team1 = '<b>'+team1+'</b>';
                } else {
                    team2 = '<b>'+team2+'</b>';
                }

                html_str += '<tr class="gcard_item">\
                                <td>'+convert_date_time(d.card_time, 'h:mma')+'<span class="noshow card_id">'+d.card_id+'</span><span class="customer_id noshow">'+d.customer_id+'</span><span class="parent_id noshow">'+d.parent_id+'</span></td>\
                                <td>'+(d.card_type == 1 ? 'Red' : 'Yellow')+'</td>\
                                <td><a href="#" class="view_customer">'+d.first_name+' '+d.last_name+'</a></td>\
                                <td>'+(team1+' v '+team2+'<br>'+d.class_name)+'</td>\
                                <td>'+d.username+'</td>\
                                <td>'+d.card_comment+'</td>\
                                <td><ul>\
                                    '+($('#is_admin').val() ? '<li><a href="#" class="btn-edit delete_gcard">Delete</a></li>' : '')+'\
                                    '+($('#is_admin').val() ? '<li><a href="#" class="btn-edit suspend_gcard">Suspend</a></li>' : '')+'\
                                </ul></td>\
                            </tr>';
            }
            $(mc+' .gcards_list tbody').html(html_str);

            let html_str_s = '';
            for (let i = 0; i < res.suspensions.length; i++) {
                let d = res.suspensions[i];

                html_str_s +='<tr class="gcard_item">\
                                <td>'+convert_date_time(d.card_time, 'D MMM YYYY')+'<span class="noshow card_id">'+d.card_id+'</span><span class="customer_id noshow">'+d.customer_id+'</span><span class="parent_id noshow">'+d.parent_id+'</span></td>\
                                <td><a href="#" class="view_customer">'+d.first_name+' '+d.last_name+'</a></td>\
                                <td>'+d.username+(d.location_id != location_id ? '<br>'+d.location_name : '')+'</td>\
                                <td>'+d.orders+'</td>\
                                <td>'+d.card_comment+'</td>\
                                <td><ul>\
                                    '+($('#is_admin').val() ? '<li><a href="#" class="btn-edit delete_gcard">Delete</a></li>' : '')+'\
                                </ul></td>\
                            </tr>';

            }
            $(mc+' .gsusp_list tbody').html(html_str_s);

        } else if (response.redirect != undefined) {
            mini_login_wizard(response.redirect); //session timeout case
        } else {    
            set_side_error(response.error.join("<br>"));
            $('#loader-wrapper').hide();
        }

    }).fail( function(xhr, textStatus, errorThrown) {
        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
        $('#loader-wrapper').hide();
    });       
}

