function admin_add_game_card(customer_id,card_type,comment,fixture_id,orders) {
    let data ={
    	card_id: '',
        customer_id: customer_id || '',
        orders: orders || '',
        card_comment: comment || '',
        fixture_id: fixture_id || '',
        card_type: card_type || ''
    };

    save_game_card_ry(data);
}

function set_score_font_sizes() {
    let height = window.screen.height;
    $(mc+' .score_team1_name').css('font-size', Math.floor(height/20)+'px');
    $(mc+' .score_team2_name').css('font-size', Math.floor(height/20)+'px');
    $(mc+' .score_score1').css('font-size', Math.floor(height/5)+'px');
    $(mc+' .score_score2').css('font-size', Math.floor(height/5)+'px');
    $(mc+' .score_timer').css('font-size', Math.floor(height/20)+'px');
    $(mc+' .score_space_name').css('font-size', Math.floor(height/35)+'px');
    $(mc+' .score_fixture_time').css('font-size', Math.floor(height/35)+'px');	
}

function get_scoreboard_fixtures() {

    $('#loader-wrapper').show();

    let location_id = $('#location_id').val();

    $.ajax({
        type: 'GET',
        url: '/api/getScoreboards',
        data: {location_id: location_id},
        dataType: 'JSON'
    }).done(function( response ) {

        if (response.success != undefined) {

            $('#loader-wrapper').hide();

            let res = response.success;

            let data = res.data;

            let opts_str = data.length ? '' : '<option value="">No fixtures scheduled today</option>';
            for (let i = 0; i < data.length; i++) {
            	if ((data[i].team1 != 'Bye') && (data[i].team2 != 'Bye')) {
                	let game_title = (data[i].tag ? data[i].tag+': ' : '')+(data[i].team1_name || '') +' v '+ (data[i].team2_name || '')+' @ '+convert_date_time(data[i].schedule_start, 'h:mma')+' '+(data[i].space_names ? data[i].space_names.split(',').filter(item => item).join(', ') : '');
                	opts_str += '<option value="'+data[i].fixture_id+'">'+game_title+'</option>';            		
            	}
            }

            if (data.length) {
            	$(mc+' .score_div').removeClass('noshow');
            }

            $(mc+' .score_fixture_id').html(opts_str).change(); //trigger change

            set_score_font_sizes(); //font sizes

        } else if (response.redirect != undefined) {
            mini_login_wizard(response.redirect); //session timeout case
        } else {    
            set_side_error(response.error.join("<br>"));
            $('#loader-wrapper').hide();
        }

    }).fail( function(xhr, textStatus, errorThrown) {
        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
        $('#loader-wrapper').hide();
    });       
}

function get_scoreboard_data(reset=true) {

	clear_score_loop(); //clear always

	if ($(mc+' .score_fixture_id').length) {
		if (reset) {
			$(mc+' .score_div').html($('#master_scoreboard_view .score_div').html());
			set_score_font_sizes(); //font sizes

			clear_game_clock();
		}

	    let location_id = $('#location_id').val();
	    let fixture_id = $(mc+' .score_fixture_id').val();

	    if (fixture_id > 0) {
	    	if (reset) {$('#loader-wrapper').show();}

		    $.ajax({
		        type: 'GET',
		        url: '/api/getScoreboards',
		        data: {location_id: location_id, fixture_id: fixture_id},
		        dataType: 'JSON'
		    }).done(function( response ) {

		        if (response.success != undefined) {

		            if (reset) {$('#loader-wrapper').hide();}

		            let res = response.success;

		            //fixture
		            $(mc+' .score_team1_name').text(res.fixture.team1_name || '');
		            $(mc+' .score_team2_name').text(res.fixture.team2_name || '');

		            $(mc+' .score_fixture_time').text(convert_date_time(res.fixture.schedule_start, 'h:mma')+' - '+convert_date_time(res.fixture.schedule_finish, 'h:mma'));
		            $(mc+' .score_space_name').text(res.fixture.space_names ? res.fixture.space_names.split(',').filter(item => item).join(', ') : '');

		            //scorecard
		            if (res.scoreboard) {
		                set_score_scoreboard(res.scoreboard);
		            }

		            //call the function again in 5 seconds during live period
					if (dayjs().isAfter(dayjs(res.fixture.schedule_start).subtract(10, 'minute')) && 
	                    dayjs().isBefore(dayjs(res.fixture.schedule_finish).add(30, 'minute'))) {
	                    //valid live period        	            
					  	let scoreLoopID = setTimeout(() => {
					    	 get_scoreboard_data(false);
					  	}, 5000);

					  	$('#score_loop_id').text(scoreLoopID);
		            }

		        } else if (response.redirect != undefined) {
		            mini_login_wizard(response.redirect); //session timeout case
		        } else {    
		            set_side_error(response.error.join("<br>"));
		            $('#loader-wrapper').hide();
		        }

		    }).fail( function(xhr, textStatus, errorThrown) {
		        set_side_error("Operation failed " + (xhr.responseText?xhr.responseText:''));
		        $('#loader-wrapper').hide();
		    });
	    }
	}
}

function add_dashboard_widget(type, html_str = '', x = 0, y = 0, w = 1, h = 1) {
	x = Number(x);
	y = Number(y);
	w = Number(w);
	h = Number(h);
	if (Number.isNaN(x)) x = 0;
	if (Number.isNaN(y)) y = 0;
	if (Number.isNaN(w) || w < 1) w = 1;
	if (Number.isNaN(h) || h < 1) h = 1;
    const contentHtml = '<div class="widget_item" data-type="'+type+'">\
                            '+html_str+'\
                            <a href="#" class="remove_widget"><img src="images/icons/x.svg" alt=""></a>\
                         </div>';
    const widget = $('#dashboard')[0].gridstack.addWidget({x: x, y: y, w: w, h: h});
    $(widget).find('.grid-stack-item-content').html(contentHtml);

    if (contentHtml.includes('rep_chart')) {
    	destroy_charts($(widget).find('.grid-stack-item-content .rep_chart'));
    	create_charts($(widget).find('.grid-stack-item-content .rep_chart'));
    }
}

function refresh_dashboard_widget(type, html_str = '') {
    const contentHtml = '<div class="widget_item" data-type="'+type+'">\
                            '+html_str+'\
                            <a href="#" class="remove_widget"><img src="images/icons/x.svg" alt=""></a>\
                         </div>';
    let widget = $('.widget_item[data-type='+type+']');
    widget.closest('.grid-stack-item-content').html(contentHtml);

    widget = $('.widget_item[data-type='+type+']'); //assign again as HTML replaced

    if (contentHtml.includes('rep_chart')) {
    	destroy_charts(widget.find('.rep_chart'));
    	create_charts(widget.find('.rep_chart'));
    }
}

let _dashboardInitRunning = false;
async function init_dashboard_widgets() {

	const $dash = $('#dashboard');
	const dashEl = $dash[0];
	if (!dashEl || _dashboardInitRunning) {
		return;
	}
	_dashboardInitRunning = true;

	let all_modes = JSON.parse($('#add_widget').prop('dataset').intrac).map(item => item.value);

	let layout = isJSON($('#dashboard_layout').text()) ? JSON.parse($('#dashboard_layout').text()) : '';

	let grid = null;

	const totalRows = 2, totalCols = 4;

	if (!layout || !layout.length) {
	    layout = [
			      ...(all_modes.includes('class_schedules') ? [{'x': '0', 'y': '0', 'type': 'class_schedules'}] : []),
			      ...(all_modes.includes('new_customers') ? [{'x': '1', 'y': '0', 'type': 'new_customers'}] : []),
			      ...(all_modes.includes('staff') ? [{'x': '2', 'y': '0', 'type': 'staff'}] : []),
			      ...(all_modes.includes('outstanding_accts') ? [{'x': '3', 'y': '0', 'type': 'outstanding_accts'}] : []), 
			      ...(all_modes.includes('revenue') ? [{'x': '0', 'y': '1', 'w': '2', 'type': 'revenue'}] : [])
			      ];
	}

	let modes = layout.map(item => item.type);

	let mode_opts = layout.map(item => item.options || {});
	mode_opts = Object.assign({}, ...mode_opts);

	let resp;
	try {
		resp = await get_widget_data(modes, mode_opts);
	} catch (err) {
		_dashboardInitRunning = false;
		return;
	}

	$dash.removeAttr('style');
	$dash.removeAttr('gs-current-row');
	dashEl.className = dashEl.className.replace(/\bgs-\d+\b/g, '');

	const dashboardColumnOpts = {
		columnMax: 4,
		breakpointForWindow: true,
		breakpoints: [
			{ w: 700, c: 1 },
			{ w: 850, c: 2 }
		]
	};

	destroy_charts('#dashboard');
	if (dashEl.gridstack) {
		try {
			dashEl.gridstack.destroy(false);
		} catch (e) {
		}
	}
	$dash.empty();

	grid = GridStack.init({
		column: totalCols,
		cellHeight: 'auto',
		margin: 5,
		columnOpts: dashboardColumnOpts
	}, '#dashboard');

	if (!window._dashboardMoveLayoutDone) {
		window._dashboardMoveLayoutDone = true;
		if (isTouchDevice()) {
			grid.enableMove(false);
			$('#move_layout').closest('li').removeClass('noshow');
		} else if ($('#move_layout').length) {
			$('#move_layout').closest('li').remove();
		}
	}

	grid.batchUpdate();
	grid.column(totalCols);
	layout.forEach(w => add_dashboard_widget(w.type, resp[w.type], w.x, w.y, w.w, w.h));
	grid.commit();

	const wPx = dashEl.clientWidth || dashEl.parentElement?.clientWidth || window.innerWidth;
	try {
		grid.onResize(wPx);
	} catch (e) {
	}

	requestAnimationFrame(function () {
		applyDashboardGridLayout();
		scheduleDashboardLayoutRefresh();
		setTimeout(function () {
			applyDashboardGridLayout();
		}, 50);
		setTimeout(function () {
			applyDashboardGridLayout();
		}, 200);
		_dashboardInitRunning = false;
		requestAnimationFrame(function () {
			run_dashboard_intro_animation(true);
		});
	});
}

