let navPillInstantOnce = true;
let navPillBootstrapping = false;

function updateNavPill() {
	var $list = $('#nav_list');
	var $wrap = $('#nav_list_wrap');
	if (!$list.length || !$wrap.length) {
		return;
	}
	var $pill = $wrap.find('.nav-pill-bg');
	if (!$pill.length) {
		return;
	}
	if (window.matchMedia('(max-width: 1023px)').matches) {
		$pill.removeClass('is-visible nav-pill-instant');
		navPillBootstrapping = false;
		return;
	}
	var $active = $list.children('li.nav-link-row.active').filter(function () {
		return !$(this).hasClass('noshow') && $(this).css('display') !== 'none';
	}).first();
	if (!$active.length) {
		$pill.removeClass('is-visible');
		return;
	}
	var $btn = $active.find('.nav-btn').first();
	if (!$btn.length) {
		return;
	}
	var wrapEl = $wrap[0];
	var btnEl = $btn[0];
	function placeNavPill() {
		var wRect = wrapEl.getBoundingClientRect();
		var bRect = btnEl.getBoundingClientRect();
		$pill.css({
			left: bRect.left - wRect.left,
			top: bRect.top - wRect.top,
			width: $btn.outerWidth(),
			height: $btn.outerHeight()
		}).addClass('is-visible');
	}
	var instantLayout = navPillInstantOnce || navPillBootstrapping;
	if (instantLayout) {
		$pill.addClass('nav-pill-instant');
	}
	placeNavPill();
	if (navPillInstantOnce) {
		navPillInstantOnce = false;
		navPillBootstrapping = true;
		function finishNavPillBootstrap() {
			placeNavPill();
			requestAnimationFrame(function () {
				placeNavPill();
				$pill.removeClass('nav-pill-instant');
				navPillBootstrapping = false;
			});
		}
		var stepsRemaining = 6;
		function stepBootstrap() {
			placeNavPill();
			stepsRemaining--;
			if (stepsRemaining > 0) {
				requestAnimationFrame(stepBootstrap);
			} else if (document.fonts && document.fonts.ready) {
				document.fonts.ready.then(function () {
					requestAnimationFrame(finishNavPillBootstrap);
				});
			} else {
				requestAnimationFrame(finishNavPillBootstrap);
			}
		}
		requestAnimationFrame(stepBootstrap);
	}
}

function updateGviewPill($ul) {
	if (!$ul || !$ul.length) return;
	var $pill = $ul.children('.gview-pill-bg');
	if (!$pill.length) {
		$pill = $('<span class="gview-pill-bg" aria-hidden="true"></span>');
		$ul.css('position', 'relative').prepend($pill);
	}
	if (!$ul.is(':visible') || window.matchMedia('(max-width: 1023px)').matches) {
		$pill.removeClass('is-visible');
		return;
	}
	var $active = $ul.find('> li > a.active, > li > a.header-btn.active').first();
	if (!$active.length) {
		$pill.removeClass('is-visible');
		return;
	}
	var ulRect = $ul[0].getBoundingClientRect();
	var btnRect = $active[0].getBoundingClientRect();
	$pill.css({
		left: btnRect.left - ulRect.left,
		top: btnRect.top - ulRect.top,
		width: $active.outerWidth(),
		height: $active.outerHeight()
	}).addClass('is-visible');
}

function updateAllGviewPills() {
	$('#sh_grid ul.rounded-panel:visible').each(function () {
		updateGviewPill($(this));
	});
}

