let dashboard_intro_timer = null;

const INTRAC_HEADER_INTRO_SS_KEY = 'intrac_has_animated_header';

function resetHeaderIntroFlagIfPageReload() {
	try {
		var nav = performance.getEntriesByType && performance.getEntriesByType('navigation')[0];
		if (nav && nav.type === 'reload') {
			sessionStorage.removeItem(INTRAC_HEADER_INTRO_SS_KEY);
		}
	} catch (e) {}
}

function shouldRunDashboardHeaderIntro() {
	try {
		return !sessionStorage.getItem(INTRAC_HEADER_INTRO_SS_KEY);
	} catch (e) {
		return true;
	}
}

function markDashboardHeaderIntroComplete() {
	try {
		sessionStorage.setItem(INTRAC_HEADER_INTRO_SS_KEY, '1');
	} catch (e) {}
}

function dashboardGridItemsInLayoutOrder() {
	const nodes = $('#dashboard .grid-stack-item').get();
	nodes.sort(function (a, b) {
		const na = a.gridstackNode;
		const nb = b.gridstackNode;
		if (na && nb) {
			if (na.y !== nb.y) {
				return na.y - nb.y;
			}
			return na.x - nb.x;
		}
		const ya = parseInt(a.getAttribute('gs-y'), 10);
		const yb = parseInt(b.getAttribute('gs-y'), 10);
		const yai = Number.isNaN(ya) ? 0 : ya;
		const ybi = Number.isNaN(yb) ? 0 : yb;
		if (yai !== ybi) {
			return yai - ybi;
		}
		const xa = parseInt(a.getAttribute('gs-x'), 10);
		const xb = parseInt(b.getAttribute('gs-x'), 10);
		const xai = Number.isNaN(xa) ? 0 : xa;
		const xbi = Number.isNaN(xb) ? 0 : xb;
		return xai - xbi;
	});
	return $(nodes);
}

function run_table_diag_intro_animation($table, onDone) {
	if (!$table || !$table.length) {
		if (typeof onDone === 'function') {
			onDone();
		}
		return;
	}
	if (typeof window.matchMedia === 'function' && window.matchMedia('(prefers-reduced-motion: reduce)').matches) {
		if (typeof onDone === 'function') {
			onDone();
		}
		return;
	}

	const DIAG_STEP = 42;
	const FADE_MS = 340;
	const items = [];
	const $firstHeadRow = $table.find('thead tr').first();
	const ncol = $firstHeadRow.children('th').length;
	const headerMaxSum = Math.max(0, ncol - 1);

	function diagIntroTarget(el) {
		if (!el || el.nodeType !== 1) {
			return el;
		}
		if (el.tagName === 'TD' && el.classList.contains('cell-many') && el.firstElementChild) {
			return el.firstElementChild;
		}
		if (el.tagName === 'TH' && el.classList.contains('courts-many') && el.firstElementChild) {
			return el.firstElementChild;
		}
		return el;
	}

	$firstHeadRow.children('th').each(function (colIdx) {
		items.push({ el: diagIntroTarget(this), delay: colIdx * DIAG_STEP });
	});

	$table.find('tbody tr').each(function (rowIdx) {
		$(this).children('td').each(function (colIdx) {
			const sum = rowIdx + colIdx;
			items.push({ el: diagIntroTarget(this), delay: (headerMaxSum + 1 + sum) * DIAG_STEP });
		});
	});

	if (!items.length) {
		if (typeof onDone === 'function') {
			onDone();
		}
		return;
	}

	items.forEach(function (item) {
		item.el.style.opacity = '0';
		item.el.style.transform = 'translateY(10px)';
		item.el.style.transition = 'none';
	});

	void document.body.offsetWidth;

	items.forEach(function (item) {
		item.el.style.transition = 'opacity ' + FADE_MS + 'ms cubic-bezier(0.4, 0, 0.2, 1) ' + item.delay + 'ms, transform ' + FADE_MS + 'ms cubic-bezier(0.4, 0, 0.2, 1) ' + item.delay + 'ms';
		item.el.style.opacity = '1';
		item.el.style.transform = 'translateY(0)';
	});

	var maxDelay = 0;
	items.forEach(function (item) {
		if (item.delay > maxDelay) {
			maxDelay = item.delay;
		}
	});

	setTimeout(function () {
		items.forEach(function (item) {
			item.el.style.transition = '';
			item.el.style.opacity = '';
			item.el.style.transform = '';
		});
		if (typeof onDone === 'function') {
			onDone();
		}
	}, maxDelay + FADE_MS + 60);
}

function run_class_grid_intro_animation() {
	run_table_diag_intro_animation($('#classes table:first'));
}

function run_roster_grid_intro_animation() {
	run_table_diag_intro_animation($('#rosters table:first'));
}

function run_events_intro_animation() {
	var $container = $('#classes_list');
	if (!$container.length || !$container.children().length) return;

	var SECTION_STAGGER = 40;
	var HEADER_COL_STAGGER = 60;
	var ROW_STAGGER = 55;
	var CELL_STAGGER = 40;
	var SECTION_GAP = 60;
	var FADE_DUR = 300;

	var items = [];
	var globalDelay = 0;

	$container.children().each(function () {
		if ($(this).hasClass('section_title')) {
			items.push({ el: this, delay: globalDelay });
			globalDelay += SECTION_STAGGER;
		} else if ($(this).hasClass('classes-table')) {
			var $tbl = $(this);
			$tbl.find('thead th').each(function (colIdx) {
				items.push({ el: this, delay: globalDelay + colIdx * HEADER_COL_STAGGER });
			});
			var thCount = $tbl.find('thead th').length;
			globalDelay += Math.min(thCount, 3) * HEADER_COL_STAGGER;

			$tbl.find('tbody tr').each(function (rowIdx) {
				var rowBase = globalDelay + rowIdx * ROW_STAGGER;
				$(this).children('td').each(function (colIdx) {
					items.push({ el: this, delay: rowBase + colIdx * CELL_STAGGER });
				});
			});
			var rowCount = $tbl.find('tbody tr').length;
			globalDelay += rowCount * ROW_STAGGER + SECTION_GAP;
		}
	});

	if (!items.length) return;

	items.forEach(function (item) {
		item.el.style.opacity = '0';
		item.el.style.transition = 'none';
	});

	void document.body.offsetWidth;

	items.forEach(function (item) {
		item.el.style.transition = 'opacity ' + FADE_DUR + 'ms ease-out ' + item.delay + 'ms';
		item.el.style.opacity = '1';
	});

	var maxDelay = 0;
	items.forEach(function (item) {
		if (item.delay > maxDelay) maxDelay = item.delay;
	});

	setTimeout(function () {
		items.forEach(function (item) {
			item.el.style.transition = '';
			item.el.style.opacity = '';
		});
	}, maxDelay + FADE_DUR + 100);
}

/** Direct children of .content, expanding tables into tbody rows (same stagger idea as SSR dashboard). */
function collectDashboardContentAnimRows($gridItem) {
	const $content = $gridItem.find('.widget_item > .content').first();
	if (!$content.length) {
		return $();
	}
	let $rows = $();
	$content.children(':not(.noshow)').each(function () {
		if (this.classList && this.classList.contains('chart_canvas')) {
			return;
		}
		const tag = this.tagName && this.tagName.toLowerCase();
		if (tag === 'table') {
			$rows = $rows.add($(this).find('tbody tr'));
		} else {
			$rows = $rows.add(this);
		}
	});
	if (!$rows.length) {
		return $content;
	}
	return $rows;
}

function run_dashboard_intro_animation(force = false) {
	const $dashboard_main = $('#dashboard_main');
	if (!$dashboard_main.length || $dashboard_main.hasClass('noshow')) {
		return;
	}

	const $body = $('body');
	if ($body.hasClass('dashboard-intro-running') && !force) {
		return;
	}

	const includeHeaderIntro = shouldRunDashboardHeaderIntro();
	if (includeHeaderIntro) {
		markDashboardHeaderIntroComplete();
	}

	const CARD_STAGGER = 130;
	const ROW_STAGGER  = 80;
	const BASE_DELAY   = 280;
	const ANIM_DUR     = 520;
	const CHART_STAGGER = 100;

	let maxDelay = 0;
	const $items = dashboardGridItemsInLayoutOrder();

	$items.each(function(cardIdx) {
		const cardBase = BASE_DELAY + Math.min(cardIdx, 12) * CARD_STAGGER;
		const $rows = collectDashboardContentAnimRows($(this));
		$rows.each(function(rowIdx) {
			const delay = cardBase + rowIdx * ROW_STAGGER;
			if (delay > maxDelay) {
				maxDelay = delay;
			}
			this.classList.add('dash-anim-row');
			this.style.setProperty('--dash-row-delay', delay);
		});
	});

	const HEADER_STAGGER = 45;
	let headerIdx = 0;

	if (includeHeaderIntro) {
		const $logoA = $('#top_container header.page_header nav > div > a.a_direct').first();
		const $logoImg = $logoA.find('img.logo').first();
		if ($logoA.length && $logoImg.length) {
			$logoA.addClass('dash-anim-parent');
			$logoImg[0].classList.add('dash-anim-row');
			$logoImg[0].style.setProperty('--dash-row-delay', headerIdx * HEADER_STAGGER);
			headerIdx++;
		}

		const $navList = $('#nav_list');
		if ($navList.length && $navList.is(':visible')) {
			$navList.addClass('dash-anim-parent');
			$navList.find('> li.nav-link-row').each(function () {
				const $li = $(this);
				if ($li.hasClass('noshow') || $li.css('display') === 'none') {
					return;
				}
				this.classList.add('dash-anim-row');
				this.style.setProperty('--dash-row-delay', headerIdx * HEADER_STAGGER);
				headerIdx++;
			});
		}

		const $userBar = $('.user_dropdown_div');
		if ($userBar.length && $userBar.is(':visible')) {
			$userBar.addClass('dash-anim-parent');
			$userBar.children().each(function () {
				if ($(this).css('display') === 'none') {
					return;
				}
				this.classList.add('dash-anim-row');
				this.style.setProperty('--dash-row-delay', headerIdx * HEADER_STAGGER);
				headerIdx++;
			});
		}

		const $toolbarUl = $('#sub_header_top ul.rounded-panel');
		if ($toolbarUl.length) {
			$toolbarUl.addClass('dash-anim-parent');
			$toolbarUl.find('> li').each(function () {
				const $li = $(this);
				if ($li.hasClass('noshow') || $li.css('display') === 'none') {
					return;
				}
				this.classList.add('dash-anim-row');
				this.style.setProperty('--dash-row-delay', headerIdx * HEADER_STAGGER);
				headerIdx++;
			});
		}
		const $shDashRow = $('#sh_dashboard > div').first();
		if ($shDashRow.length) {
			$shDashRow.addClass('dash-anim-parent');
			$shDashRow.children().each(function () {
				this.classList.add('dash-anim-row');
				this.style.setProperty('--dash-row-delay', headerIdx * HEADER_STAGGER);
				headerIdx++;
			});
		}
	}

	clearTimeout(dashboard_intro_timer);
	$body.removeClass('dashboard-intro-running');
	void document.body.offsetWidth;
	$body.addClass('dashboard-intro-running');

	const totalMs = maxDelay + ANIM_DUR + 100;
	dashboard_intro_timer = setTimeout(function () {
		$('#dashboard .dash-anim-row').add('#top_container .dash-anim-row').add('#sub_header_top .dash-anim-row').add('#sh_dashboard .dash-anim-row').removeClass('dash-anim-row').css({
			'--dash-row-delay': '',
			'opacity': '',
			'transform': ''
		});
		$('#top_container .dash-anim-parent, #sub_header_top ul.rounded-panel.dash-anim-parent, #sh_dashboard .dash-anim-parent').removeClass('dash-anim-parent').css('overflow', '');
		scheduleDashboardLayoutRefresh();
		requestAnimationFrame(function () {
			refreshAllDashboardCharts();

			var $charts = $('#dashboard .chart_canvas');
			$charts.each(function(i) {
				this.classList.add('dash-anim-row');
				this.style.setProperty('--dash-row-delay', i * CHART_STAGGER);
			});
			void document.body.offsetWidth;
			setTimeout(function () {
				$body.removeClass('dashboard-intro-running');
				$charts.removeClass('dash-anim-row').css({
					'--dash-row-delay': '',
					'opacity': '',
					'transform': ''
				});
			}, ($charts.length * CHART_STAGGER) + ANIM_DUR + 50);
		});
		updateNavPill();
	}, totalMs);
}

