    $(document).on("change",".cregister_class_id", function(e){
    	//resets
	    $(mc2+' .cregister_program_list').html('');
	    $(mc2+' .cregister_schedule_list').html('');
	    $(mc2+' .cregister_team_list').html('');
	    $(mc2+' .cregister_fixture_list').html('');

        let class_data = JSON.parse($(mc2+' .cregister_class_id').find(':selected').prop('dataset').intrac);

        if (class_data.level_type == 4) {
            $(mc2+' .cregister_ps_trs').addClass('noshow');
            $(mc2+' .cregister_comp_trs').removeClass('noshow');
            get_cust_class_teams();
        } else if ((class_data.level_type == 0) || (class_data.level_type == 1) || (class_data.level_type == 6)) {
            $(mc2+' .cregister_ps_trs').removeClass('noshow');
            $(mc2+' .cregister_comp_trs').addClass('noshow');
            get_cust_class_programs();
            //get_cust_class_schedules(); called from inside get_cust_class_programs();
            //calcRegisterCost(); called from inside get_cust_class_schedules();
        }

        //reset buttons
        if ($(mc2+' .cregister_team_manager').is(":checked")) {
            $(mc2+' .custregisterbtn_save').hide();
            $(mc2+' .cregister_email_tr').addClass('noshow_imp'); //dont show at all
            $(mc2+' .custteammanagerbtn_save').show();
        } else {
            $(mc2+' .custregisterbtn_save').show();
            $(mc2+' .cregister_email_tr').removeClass('noshow_imp');
            $(mc2+' .custteammanagerbtn_save').hide();
        }

        if (class_data.features.includes('r')) {
        	$(mc2+' .cregister_email').prop('checked', true);
        	$(mc2+' .cregister_email_tr').removeClass('noshow');
        } else {
        	$(mc2+' .cregister_email').prop('checked', false);
        	$(mc2+' .cregister_email_tr').addClass('noshow');
        }

        if ((class_data.level_type == 4) || (dates_diff(class_data.term_finish, dayjs().format('YYYY-MM-DD')) < 0)) {
        	$(mc2+' .custwaitbtn_save').hide();
        } else {
        	$(mc2+' .custwaitbtn_save').show();
        }
        
        get_cust_class_passs();
        get_cust_class_addons();
    });

