    $(document).on("change",".rep_orderby", async function(e){
    	if ($(this).val().includes('~alt')) {
    		let key = $(this).val().replace('~alt','');
    		$(this).val(key);

	        let res = await loadItems_iDB();
	        if (res) {
	        	for (let a = 0; a < res.items.length; a++) {
	        		let data = res.items[a].data;

					data.forEach(obj => {
					    if (obj[key]) {
					    	if ((key == 'Customer') && (obj.first_name != undefined) && (obj.last_name != undefined)) {
					    		obj[key] = res.options.altSort == 'customer_last_name' ? (obj.first_name+' '+obj.last_name) : (obj.last_name+' '+obj.first_name);
					    	} else {
					    		obj[key] = flipName(obj[key]);
					    	}
					    }
					});
	        	}
	        	res.options.altSort = key.toLowerCase()+'_'+($(this).text().includes('First') ? 'first_name' : 'last_name');
	        	await clearItems_iDB();
	        	await saveItem_iDB(res);
	        }

	        //helper function. flip based on last space in str
			function flipName (str) {
			    const parts = String(str).trim().split(/\s+/);
			    if (parts.length < 2) return str;
			    const last = parts.pop();
			    return `${last} ${parts.join(' ')}`;
			};	        
    	}

        run_report($('#reports .rep_report').val(), true); //run from local
    });

