    $(document).on('click','.multirbtn_save', function(e){
        let discounts = 0;

        $(mc+' .multir_item').each(function () {
            if (this.checked) {
                let cr = $(this).prop('dataset').intrac_discount;
                if (validator.isFloat(cr)) {
                    discounts += parseFloat(cr);
                }
            }
        });

        if (discounts != 0) {
            discounts = ' You are processing total discounts of '+numberformatccy(discounts);
        } else {
            discounts = '';
        }

        open_confirm_popup({fn: 'save_multir', fn_data: '', msg: 'Are you sure?'+discounts});
    });

